def get_demand_coefficient(category: str, month: int) -> float:
    """Получить коэффициент спроса для категории и месяца (1-12)"""
    if not category:
        return SEASONALITY_DEMAND_2026["default"][month - 1]
    cat_key = category.lower().strip()
    if cat_key in SEASONALITY_DEMAND_2026:
        return SEASONALITY_DEMAND_2026[cat_key][month - 1]
    # Поиск по подстроке
    for key, values in SEASONALITY_DEMAND_2026.items():
        if key in cat_key:
            return values[month - 1]
    return SEASONALITY_DEMAND_2026["default"][month - 1]

