# ============================================================================
# 🆕 v101.0: УТИЛИТЫ ДЛЯ ТОЧНЫХ РАСЧЁТОВ (Decimal)
# ============================================================================
def money_round(value: float, decimals: int = 2) -> float:
    """Корректное округление денег (банковское) через Decimal"""
    if value is None or (isinstance(value, float) and (math.isnan(value) or math.isinf(value))):
        return 0.0
    return float(Decimal(str(value)).quantize(
        Decimal(f"0.{'0' * decimals}"),
        rounding=ROUND_HALF_UP
    ))

def safe_decimal(value: Any) -> Decimal:
    """Безопасное преобразование в Decimal"""
    if value is None:
        return Decimal('0')
    try:
        if isinstance(value, Decimal):
            return value
        return Decimal(str(value))
    except Exception:
        return Decimal('0')

def calculate_tax(price: float, cost: float, tax_system: str = "УСН_6") -> float:
    """Расчёт налога с учётом режима"""
    cfg = TAX_SYSTEMS.get(tax_system, TAX_SYSTEMS["УСН_6"])
    if cfg["base"] == "revenue":
        return money_round(price * cfg["rate"])
    elif cfg["base"] == "profit":
        profit = price - cost
        if profit <= 0:
            # 🆕 v101.0: При убытке на УСН 15% — минимальный налог 1% от дохода
            if tax_system == "УСН_15":
                return money_round(price * cfg.get("min_rate", 0.01))
            return 0.0
        tax = profit * cfg["rate"]
        if tax_system == "УСН_15":
            min_tax = price * cfg.get("min_rate", 0.01)
            tax = max(tax, min_tax)
        return money_round(max(0, tax))
    elif cfg["base"] == "fixed":
        return 0.0
    return 0.0

# ============================================================================
# 🆕 v101.0: РАСЧЁТ ОБЪЁМНОГО ВЕСА (с учётом МП)
# ============================================================================
def calculate_billable_weight(weight_kg: float,
                              length_cm: float, width_cm: float,
                              height_cm: float,
                              marketplace: str = "Яндекс Маркет",
                              volumetric_coeff: float = 5000.0) -> float:
    """
    Расчёт оплачиваемого веса (больший из реального и объёмного).
    🆕 v101.0: Учитывает специфику округления по МП.
    """
    if length_cm <= 0 or width_cm <= 0 or height_cm <= 0:
        return weight_kg

    volumetric_weight = (length_cm * width_cm * height_cm) / volumetric_coeff
    billable = max(weight_kg, volumetric_weight)

    # 🆕 v101.0: Разное округление по МП
    if marketplace == "Wildberries":
        # WB округляет до 0.5 кг
        billable = math.ceil(billable * 2) / 2
    elif marketplace in ["Ozon", "Яндекс Маркет"]:
        # Ozon и ЯМ округляют до 0.1 кг (100 г)
        billable = math.ceil(billable * 10) / 10
    elif marketplace == "AliExpress":
        # AliExpress округляет до 0.5 кг
        billable = math.ceil(billable * 2) / 2
    else:
        # По умолчанию — до 0.1 кг
        billable = math.ceil(billable * 10) / 10

    return billable

# ============================================================================
# 🆕 v101.0: ПРОГРЕССИВНОЕ ХРАНЕНИЕ (с учётом МП)
# ============================================================================
def calculate_storage_cost_progressive(volume_l: float, days: int,
                                       base_rate: float, marketplace: str) -> float:
    """Прогрессивная стоимость хранения"""
    if marketplace in ["Ozon", "Wildberries", "Яндекс Маркет"]:
        if days <= 60:
            multiplier = 1.0
        elif days <= 90:
            multiplier = 2.0
        elif days <= 180:
            multiplier = 4.0
        elif days <= 365:
            multiplier = 8.0
        else:
            multiplier = 16.0
        weighted_rate = base_rate * multiplier
        return money_round(volume_l * weighted_rate * days)
    else:
        return money_round(volume_l * base_rate * days)

# ============================================================================
# 🆕 v101.0: РЕАЛЬНЫЕ ВОЗВРАТЫ (с учётом типа товара)
# ============================================================================
def calculate_returns_cost(price: float, return_rate: float,
                           reverse_logistics: float = 150.0,
                           inspection_cost: float = 50.0,
                           product_origin: ProductOrigin = ProductOrigin.ANALOG_STANDARD) -> float:
    """
    Полная стоимость возвратов.
    🆕 v101.0: Учитывает тип товара (оригинал/аналог/Китай).
    """
    # Корректируем коэффициент возврата по типу товара
    origin_cfg = PRODUCT_ORIGIN_DEFAULTS.get(product_origin, PRODUCT_ORIGIN_DEFAULTS[ProductOrigin.ANALOG_STANDARD])
    adjusted_return_rate = return_rate * origin_cfg["return_rate_multiplier"]

    # Стоимость возврата = обратная логистика + проверка + потеря товарного вида
    reverse_logistics_cost = reverse_logistics * adjusted_return_rate
    inspection = inspection_cost * adjusted_return_rate
    # 🆕 v101.0: Потеря товарного вида зависит от типа товара
    loss_percent = {
        ProductOrigin.ORIGINAL: 0.15,       # Оригинал теряет меньше
        ProductOrigin.ANALOG_PREMIUM: 0.20,
        ProductOrigin.ANALOG_STANDARD: 0.30,
        ProductOrigin.ANALOG_BUDGET: 0.40,
        ProductOrigin.CHINA: 0.60,          # Китай часто нельзя продать повторно
        ProductOrigin.REMANUFACTURED: 0.50,
        ProductOrigin.USED: 0.70,
    }.get(product_origin, 0.30)

    loss_from_defects = price * adjusted_return_rate * loss_percent

    return money_round(reverse_logistics_cost + inspection + loss_from_defects)

# ============================================================================
# 🆕 v101.0: СПЕЦИФИЧЕСКИЕ РАСХОДЫ АВТОЗАПЧАСТЕЙ
# ============================================================================
@dataclass
class AutoPartsSpecificCosts:
    """Специфические расходы для автозапчастей"""
    chestny_znak: float = 1.5
    certification_amortization: float = 0.0
    warranty_reserve: float = 0.02
    packaging_fbs: float = 45.0
    labeling: float = 3.0
    util_tax: float = 0.0
    customs_duty: float = 0.0
    currency_risk: float = 0.03

    def calculate(self, price: float, is_import: bool = False,
                  requires_marking: bool = True,
                  product_origin: ProductOrigin = ProductOrigin.ANALOG_STANDARD) -> float:
        """
        🆕 v101.0: Учитывает тип товара.
        """
        origin_cfg = PRODUCT_ORIGIN_DEFAULTS.get(product_origin, PRODUCT_ORIGIN_DEFAULTS[ProductOrigin.ANALOG_STANDARD])

        total = 0.0
        if requires_marking:
            total += self.chestny_znak
            total += self.certification_amortization
            total += origin_cfg.get("certification_cost", 0.0)  # Доп. сертификация для Китая
            total += price * self.warranty_reserve
            total += self.packaging_fbs
            total += self.labeling

        if is_import:
            # 🆕 v101.0: Валютный риск зависит от типа товара
            total += price * origin_cfg.get("currency_risk", self.currency_risk)
            total += self.customs_duty
            total += price * self.util_tax

        return money_round(total)

# ============================================================================
# 🆕 v101.0: РЕКЛАМНЫЕ РАСХОДЫ (ДРР) С УЧЁТОМ СЕЗОНА
# ============================================================================
def calculate_advertising_cost(price: float,
                               category: str,
                               ad_intensity: str = "medium",
                               month: Optional[int] = None) -> float:
    """
    Рекламные расходы (ДРР — доля рекламных расходов).
    🆕 v101.0: Учитывает сезон — в сезон конкуренция выше, ДРР растёт.
    """
    drr_rates = {
        "low": 0.05,
        "medium": 0.15,
        "high": 0.25,
        "aggressive": 0.35
    }
    competitive_categories = ["масла", "фильтры", "колодки", "аккумуляторы", "шины"]
    if category in competitive_categories:
        intensity = "high" if ad_intensity == "medium" else ad_intensity
    else:
        intensity = ad_intensity

    base_rate = drr_rates.get(intensity, 0.15)

    # 🆕 v101.0: Сезонная корректировка ДРР
    if month:
        demand_coeff = get_demand_coefficient(category, month)
        # В высокий сезон ДРР выше (конкуренция), в низкий — ниже
        seasonal_adj = 1.0 + (demand_coeff - 1.0) * 0.3
        base_rate *= seasonal_adj

    return money_round(price * base_rate)

# ============================================================================
# 🆕 v101.0: ВАЛИДАЦИЯ ВХОДНЫХ ДАННЫХ (расширенная)
# ============================================================================
def validate_input_data(df: pd.DataFrame) -> Tuple[bool, List[str]]:
    """Проверка качества данных перед расчётом"""
    errors = []
    warnings = []

    if 'Цена' in df.columns:
        negative_prices = (df['Цена'] <= 0).sum()
        if negative_prices > 0:
            errors.append(f" ⚠️ {negative_prices} товаров с ценой ≤ 0")
        suspicious = (df['Цена'] < 50).sum()
        if suspicious > 0:
            warnings.append(f" ⚠️ {suspicious} товаров дешевле 50₽ — проверьте")

    if 'Длина' in df.columns:
        missing_dims = df['Длина'].isna().sum()
        if missing_dims > len(df) * 0.3:
            warnings.append(f" ⚠️ У {missing_dims} товаров нет габаритов — логистика будет неточной")

    # 🆕 v101.0: Проверка типа товара
    if 'Тип товара' in df.columns:
        unknown_types = df['Тип товара'].isin([o.value for o in ProductOrigin]).sum()
        if unknown_types < len(df) * 0.5:
            warnings.append(f" ⚠️ У {(len(df) - unknown_types)} товаров не указан тип — будет использован 'Стандартный аналог'")

    # 🆕 v101.0: Проверка 300K+ SKU
    if len(df) > 100000:
        warnings.append(f" ⚠️ Большой каталог ({len(df):,} SKU). Рекомендуется параллельный расчёт.")

    return len(errors) == 0, errors + warnings

# ============================================================================
# 🆕 v101.0: ПАРСИНГ РАЗМЕРОВ (векторизованный)
# ============================================================================
def parse_dimensions_string(dim_str: str) -> Tuple[float, float, float]:
    """Парсит 'человеческий' ввод размеров в формат (длина, ширина, высота)."""
    if not dim_str or not isinstance(dim_str, str):
        return 0.0, 0.0, 0.0
    dim_str = dim_str.lower().strip()
    separators = ['x', '*', 'х', '×', ' ', ',']
    for sep in separators:
        if sep in dim_str:
            parts = [p.strip() for p in dim_str.split(sep) if p.strip()]
            if len(parts) >= 3:
                try:
                    dimensions = []
                    for p in parts[:3]:
                        cleaned = re.sub(r'[^\d.,\-]', '', p)
                        cleaned = cleaned.replace(',', '.')
                        if cleaned and cleaned.replace('.', '').replace('-', '').isdigit():
                            dimensions.append(float(cleaned))
                        else:
                            nums = re.findall(r'(\d+\.?\d*)', p)
                            if nums:
                                dimensions.append(float(nums[0]))
                    if len(dimensions) == 3:
                        dimensions.sort(reverse=True)
                        return tuple(dimensions)
                except (ValueError, TypeError):
                    pass
    return 0.0, 0.0, 0.0

def parse_dimensions_vectorized(dims_series) -> "pl.DataFrame":
    """Векторизованный парсинг размеров для Polars DataFrame."""
    if not POLARS_AVAILABLE:
        return pl.DataFrame()
    dims = dims_series.str.extract_all(r"(\d+\.?\d*)")

    def sort_dimensions(nums):
        if nums and len(nums) >= 3:
            try:
                return sorted([float(n) for n in nums[:3]], reverse=True)
            except (ValueError, TypeError):
                pass
        elif nums and len(nums) == 2:
            try:
                return [float(nums[0]), float(nums[1]), 1.0]
            except (ValueError, TypeError):
                pass
        return [0.0, 0.0, 0.0]

    result = dims.map_elements(sort_dimensions, return_dtype=pl.List(pl.Float64))
    return pl.DataFrame({
        "length": result.list.get(0),
        "width": result.list.get(1),
        "height": result.list.get(2)
    })

