# УТИЛИТЫ ДЛЯ БЕЗОПАСНОСТИ И КЭШИРОВАНИЯ
# ============================================================================
def get_api_key_safe(service_name: str) -> Optional[str]:
    """Безопасное получение API ключа через st.secrets"""
    try:
        if hasattr(st, 'secrets') and service_name in st.secrets:
            return st.secrets[service_name]
    except Exception:
        pass
    env_key = f"{service_name.upper()}_API_KEY"
    return os.environ.get(env_key)

def escape_sql_string(value: str) -> str:
    """Экранирование строк для SQL-запросов"""
    if not value:
        return ""
    return re.sub(r"['\";\\]", "", str(value))

# ============================================================================
# 🆕 v101.0: ЛОГГЕР (без st.cache_resource для простоты)
# ============================================================================
def get_logger():
    """Логгер приложения"""
    logger = logging.getLogger('UnitEconomyPro')
    logger.setLevel(getattr(logging, LOG_LEVEL))
    formatter = logging.Formatter(LOG_FORMAT, datefmt=LOG_DATE_FORMAT)
    if not logger.handlers:
        try:
            fh = logging.FileHandler(LOG_FILE, encoding='utf-8')
            fh.setLevel(logging.DEBUG)
            fh.setFormatter(formatter)
            logger.addHandler(fh)
        except OSError as e:
            print(f"Ошибка создания файлового логгера: {e}")
        ch = logging.StreamHandler()
        ch.setLevel(logging.INFO)
        ch.setFormatter(formatter)
        logger.addHandler(ch)
    return logger

logger = get_logger()

# ============================================================================
# 🆕 v101.0: SAFE-УТИЛИТЫ (безопасные преобразования)
# ============================================================================
def safe_float(val: Any, default: float = 0.0) -> float:
    if val is None:
        return default
    if isinstance(val, bool):
        return float(val)
    if isinstance(val, (int, float)):
        if math.isnan(val) or math.isinf(val):
            return default
        return float(val)
    if isinstance(val, (Decimal, np.floating, np.integer)):
        try:
            return float(val)
        except (ValueError, TypeError):
            return default
    if isinstance(val, str):
        cleaned = val.strip()
        if not cleaned:
            return default
        cleaned = re.sub(r'[^\d.,\-+\s]', '', cleaned)
        cleaned = cleaned.replace(' ', '').replace(',', '.')
        if cleaned.count('-') > 1:
            return default
        parts = cleaned.split('.')
        if len(parts) > 2:
            return default
        try:
            return float(cleaned)
        except ValueError:
            return default
    return default

def safe_int(val: Any, default: int = 0) -> int:
    try:
        float_val = safe_float(val, default)
        if float_val == default and val != 0:
            return default
        return int(float_val)
    except (ValueError, TypeError):
        return default

def safe_str(val: Any, default: str = "") -> str:
    if val is None:
        return default
    if isinstance(val, bool):
        return str(val)
    if isinstance(val, (int, float)):
        if math.isnan(val) or math.isinf(val):
            return default
        return str(val)
    try:
        result = str(val).strip()
        return result if result else default
    except Exception:
        return default

def safe_bool(val: Any, default: bool = False) -> bool:
    if val is None:
        return default
    if isinstance(val, bool):
        return val
    if isinstance(val, (int, float)):
        return bool(val)
    if isinstance(val, str):
        val_lower = val.lower().strip()
        true_values = {'true', 'yes', '1', 'y', 'да', 'on'}
        false_values = {'false', 'no', '0', 'n', 'нет', 'off'}
        if val_lower in true_values:
            return True
        if val_lower in false_values:
            return False
        return default
    return default

def normalize_key_for_match(value: str) -> str:
    if not value:
        return ""
    return re.sub(r'[^0-9A-Za-zА-Яа-яЁё]', '', str(value).lower().strip())

