# 🆕 v101.0: ПРОВЕРКА ДОСТУПНОСТИ GOOGLE SHEETS
# ============================================================================
def check_google_sheets_available() -> Tuple[bool, str]:
    """Проверяет доступность Google Sheets API"""
    if not GSPREAD_AVAILABLE:
        return False, "❌ gspread не установлен. Установите: pip install gspread google-auth"
    return True, "✅ Google Sheets API доступен"

