from enum import Enum, auto, IntEnum


# ============================================================================
# 🆕 v101.0: БАЗОВЫЙ КЛАСС ДЛЯ ВСЕХ ENUM С ДОПОЛНИТЕЛЬНЫМИ МЕТОДАМИ
# ============================================================================
class BaseEnum(Enum):
    """Базовый класс для всех enum с общими методами"""

    @classmethod
    def from_string(cls, value: str, default: Optional['BaseEnum'] = None) -> Optional['BaseEnum']:
        """Безопасное получение enum по строке (регистронезависимо)"""
        if not value:
            return default
        value_lower = str(value).strip().lower()
        # Поиск по имени
        for member in cls:
            if member.name.lower() == value_lower:
                return member
        # Поиск по значению
        for member in cls:
            if isinstance(member.value, str) and member.value.lower() == value_lower:
                return member
        # Поиск по value если это dict
        for member in cls:
            if isinstance(member.value, dict):
                if value_lower in [str(v).lower() for v in member.value.values()]:
                    return member
        return default

    @classmethod
    def values(cls) -> List[str]:
        """Получить список всех значений"""
        return [m.value for m in cls]

    @classmethod
    def names(cls) -> List[str]:
        """Получить список всех имён"""
        return [m.name for m in cls]

    @classmethod
    def choices(cls) -> List[Tuple[str, str]]:
        """Получить список пар (value, name) для UI"""
        return [(m.value, m.name) for m in cls]


