        """Получить enum по русскому названию"""
        russian_name = russian_name.strip().lower()
        for member in cls:
            if member.value.lower() == russian_name:
                return member
        # Поиск по подстроке
        for member in cls:
            if russian_name in member.value.lower() or member.value.lower() in russian_name:
                return member
        return cls.OTHER


