# 🆕 v101.0: УРОВНИ РЕНТАБЕЛЬНОСТИ
# ============================================================================
class ProfitabilityLevel(BaseEnum):
    """Уровни рентабельности"""
    LOSS = "Убыток"
    BREAK_EVEN = "Точка безубыточности"
    LOW = "Низкая"
    MEDIUM = "Средняя"
    HIGH = "Высокая"
    VERY_HIGH = "Очень высокая"
    SUPER_PROFIT = "Сверхприбыль"     # 🆕 v101.0

    def get_thresholds(self) -> Tuple[float, float]:
        """Диапазон маржи для уровня (в %)"""
        thresholds = {
            "LOSS": (-float('inf'), 0),
            "BREAK_EVEN": (0, 0.01),
            "LOW": (0.01, 5),
            "MEDIUM": (5, 15),
            "HIGH": (15, 30),
            "VERY_HIGH": (30, 50),
            "SUPER_PROFIT": (50, float('inf')),
        }
        return thresholds.get(self.name, (0, 100))

    def get_color(self) -> str:
        colors = {
            "LOSS": "#ef553b",
            "BREAK_EVEN": "#ffa600",
            "LOW": "#ffa600",
            "MEDIUM": "#636efa",
            "HIGH": "#00cc96",
            "VERY_HIGH": "#00cc96",
            "SUPER_PROFIT": "#26a69a",
        }
        return colors.get(self.name, "#636efa")

    @classmethod
    def from_margin(cls, margin_percent: float) -> 'ProfitabilityLevel':
        """Получить уровень по марже"""
        for member in cls:
            low, high = member.get_thresholds()
            if low <= margin_percent < high:
                return member
        return cls.MEDIUM


