# ============================================================================
class XYZClass(BaseEnum):
    """Классы XYZ-анализа по стабильности спроса"""
    X = "X"   # Низкая вариация (стабильный спрос, CV < 0.2)
    Y = "Y"   # Средняя вариация (CV 0.2-0.5)
    Z = "Z"   # Высокая вариация (нестабильный, CV > 0.5)

    def get_cv_threshold(self) -> Tuple[float, float]:
        """Диапазон коэффициента вариации"""
        thresholds = {
            "X": (0.0, 0.20),
            "Y": (0.20, 0.50),
            "Z": (0.50, float('inf')),
        }
        return thresholds.get(self.name, (0.0, 1.0))

    def get_display_name(self) -> str:
        names = {
            "X": "✅ Класс X (стабильный)",
            "Y": "🟡 Класс Y (умеренный)",
            "Z": "⚠️ Класс Z (нестабильный)",
        }
        return names.get(self.name, self.name)

    @classmethod
    def from_cv(cls, cv: float) -> 'XYZClass':
        """Получить класс по коэффициенту вариации"""
        for member in cls:
            low, high = member.get_cv_threshold()
            if low <= cv < high:
                return member
        return cls.Z


