# 🆕 v101.0: КОНФИГУРАЦИЯ МАРКЕТПЛЕЙСА (РАСШИРЕННАЯ)
# ============================================================================
@dataclass
class MarketplaceConfig:
    """
    🆕 v101.0: Расширенная конфигурация маркетплейса.
    Приоритет: Яндекс Маркет (с расширением на другие).
    Поддерживает динамические тарифы, AI-прогноз, сезонность.
    """
    # === Базовые параметры ===
    name: str
    commission_rate: float
    min_commission: float = 0.0
    max_commission: float = float('inf')

    # === Логистика ===
    logistics_base: float = 0.0
    logistics_per_kg: float = 0.0
    logistics_per_liter: float = 0.0
    storage_per_day: float = 0.0
    return_fee: float = 0.0
    acquiring_fee: float = 0.0
    last_mile_fee: float = 0.0
    delivery_fee_percent: float = 0.0

    # === Дополнительные комиссии ===
    premium_fee: float = 0.0
    rko_fee: float = 0.0
    subscription_fee: float = 0.0
    insurance_fee: float = 0.0
    packing_fee: float = 0.0
    marketing_fee: float = 0.0
    hazardous_surcharge: float = 0.0
    fragile_surcharge: float = 0.0
    oversized_surcharge: float = 0.0

    # === Категории и режимы ===
    category_rates: Dict[str, float] = field(default_factory=dict)
    mode_multipliers: Dict[str, float] = field(default_factory=dict)
    weight_tiers: List[Tuple[float, float, float]] = field(default_factory=list)
    volume_tiers: List[Tuple[float, float, float]] = field(default_factory=list)

    # === Метаданные ===
    available: bool = True
    description: str = ""
    version: str = "2026.1"
    last_updated: datetime = field(default_factory=datetime.now)
    tariff_source: 'TariffSource' = field(default_factory=lambda: TariffSource.HARDCODED)

    # === Сезонность и промо ===
    seasonal_multipliers: Dict[str, float] = field(default_factory=dict)
    promo_discount: float = 0.0
    promo_start: Optional[datetime] = None
    promo_end: Optional[datetime] = None
    dynamic_adjustment: float = 0.0

    # === AI-прогноз ===
    last_forecast: Optional[Dict[str, Any]] = None
    forecast_timestamp: Optional[datetime] = None

    # 🆕 v101.0: Приоритет МП (Яндекс Маркет = 1, другие = 2-8)
    priority: int = 5

    # 🆕 v101.0: Специфика МП (округление веса, лимиты)
    weight_rounding_step: float = 0.1      # 0.1 кг для ЯМ/Ozon, 0.5 для WB
    max_dimension_sum: float = 200.0       # Макс. сумма трёх измерений (см)
    max_weight: float = 25.0               # Макс. вес (кг)
    volumetric_coefficient: float = 5000.0 # Коэффициент объёмного веса

    # 🆕 v101.0: Динамические тарифы
    tariff_update_mode: 'TariffUpdateMode' = field(default_factory=lambda: TariffUpdateMode.MANUAL)
    last_tariff_sync: Optional[datetime] = None
    tariff_confidence: float = 1.0         # Доверие к тарифам (0-1)

    # 🆕 v101.0: Google Sheets интеграция
    google_sheets_tariff_id: Optional[str] = None
    google_sheets_tariff_url: Optional[str] = None

    def get_commission_rate(self, category: Optional[str] = None) -> float:
        """Получить комиссию с учётом категории"""
        if category and category in self.category_rates:
            return self.category_rates[category]
        return self.commission_rate

    def get_mode_multiplier(self, mode: str) -> float:
        """Получить множитель режима"""
        return self.mode_multipliers.get(mode, 1.0)

    def apply_seasonal_multiplier(self, base_rate: float, current_month: Optional[int] = None) -> float:
        """Применить сезонный коэффициент"""
        if current_month is None:
            current_month = datetime.now().month
        if current_month in [12, 1, 2]:
            season = "winter"
        elif current_month in [3, 4, 5]:
            season = "spring"
        elif current_month in [6, 7, 8]:
            season = "summer"
        else:
            season = "autumn"
        multiplier = self.seasonal_multipliers.get(season, 1.0)
        return base_rate * multiplier

    def apply_promo_discount(self, amount: float) -> float:
        """Применить промо-скидку"""
        if self.promo_discount <= 0:
            return amount
        now = datetime.now()
        if self.promo_start and self.promo_end:
            if self.promo_start <= now <= self.promo_end:
                return amount * (1 - self.promo_discount)
        else:
            return amount * (1 - self.promo_discount)
        return amount

    def calculate_commission_with_dynamics(self, price: float,
                                           discount_percent: float = 0.0,
                                           promo_participation: float = 0.0,
                                           category: Optional[str] = None,
                                           current_month: Optional[int] = None) -> float:
        """🆕 v101.0: Комиссия с учётом скидок, участия в акциях и динамики"""
        actual_price = price * (1 - discount_percent)
        promo_surcharge = actual_price * promo_participation
        base_rate = self.get_commission_rate(category)
        rate = self.apply_seasonal_multiplier(base_rate, current_month)
        rate += self.dynamic_adjustment
        commission = max(actual_price * rate, self.min_commission)
        commission += promo_surcharge
        commission = self.apply_promo_discount(commission)
        if self.max_commission < float('inf'):
            commission = min(commission, self.max_commission)
        return commission

    # 🆕 v101.0: Методы для Яндекс Маркет (приоритет)
    def is_yandex_market(self) -> bool:
        """Проверка — это Яндекс Маркет?"""
        return "яндекс" in self.name.lower() or "yandex" in self.name.lower()

    def get_priority_icon(self) -> str:
        """Иконка приоритета"""
        if self.priority == 1:
            return "⭐"
        elif self.priority <= 3:
            return "🔵"
        return "⚪"

    def to_dict(self) -> Dict[str, Any]:
        """Сериализация в словарь"""
        result = {
            "name": self.name,
            "commission_rate": self.commission_rate,
            "min_commission": self.min_commission,
            "logistics_base": self.logistics_base,
            "logistics_per_kg": self.logistics_per_kg,
            "storage_per_day": self.storage_per_day,
            "priority": self.priority,
            "tariff_source": self.tariff_source.value if hasattr(self.tariff_source, 'value') else str(self.tariff_source),
            "last_updated": self.last_updated.isoformat() if self.last_updated else None,
        }
        return result


# ============================================================================
# 🆕 v101.0: ГАБАРИТЫ ТОВАРА (С ВАЛИДАЦИЕЙ)
# ============================================================================
@dataclass
class ProductDimensions:
    """🆕 v101.0: Габариты товара с валидацией и экспортом"""
    length: float = 0.0
    width: float = 0.0
    height: float = 0.0
    weight: float = 0.0
    unit: str = "см"
    weight_unit: str = "кг"
    dimension_string: str = ""

    @property
    def volume(self) -> float:
        """Объём в литрах"""
        return calculate_volume(self.length, self.width, self.height)

    @property
    def is_valid(self) -> bool:
        """Проверка валидности"""
        return all([self.length > 0, self.width > 0, self.height > 0, self.weight > 0])

    @property
    def display_dimensions(self) -> str:
        """Отображение размеров"""
        if self.length > 0 and self.width > 0 and self.height > 0:
            return f"{self.length:.1f}x{self.width:.1f}x{self.height:.1f} см"
        return "Размеры не указаны"

    # 🆕 v101.0: Валидация габаритов
    def validate(self, marketplace: str = "Яндекс Маркет") -> Tuple[bool, List[str]]:
        """
        Валидация габаритов под требования МП.
        Возвращает (is_valid, list_of_errors).
        """
        errors = []
        if self.length <= 0 or self.width <= 0 or self.height <= 0:
            errors.append("Все размеры должны быть > 0")
        if self.weight <= 0:
            errors.append("Вес должен быть > 0")

        # Проверка под МП
        if marketplace == "Яндекс Маркет":
            if max(self.length, self.width, self.height) > 120:
                errors.append("Яндекс Маркет: макс. сторона 120 см")
            if self.weight > 25:
                errors.append("Яндекс Маркет: макс. вес 25 кг")
            if self.length + self.width + self.height > 200:
                errors.append("Яндекс Маркет: сумма сторон ≤ 200 см")
        elif marketplace == "Ozon":
            if max(self.length, self.width, self.height) > 120:
                errors.append("Ozon: макс. сторона 120 см")
            if self.weight > 25:
                errors.append("Ozon: макс. вес 25 кг")
        elif marketplace == "Wildberries":
            if max(self.length, self.width, self.height) > 100:
                errors.append("WB: макс. сторона 100 см")
            if self.weight > 25:
                errors.append("WB: макс. вес 25 кг")

        return len(errors) == 0, errors

    # 🆕 v101.0: Экспорт в Excel
    def to_excel_dict(self) -> Dict[str, float]:
        """Словарь для Excel-экспорта"""
        return {
            "Длина, см": round(self.length, 2),
            "Ширина, см": round(self.width, 2),
            "Высота, см": round(self.height, 2),
            "Вес, кг": round(self.weight, 2),
            "Объём, л": round(self.volume, 3),
        }

    def to_dict(self) -> Dict[str, float]:
        return {
            "length": self.length, "width": self.width,
            "height": self.height, "weight": self.weight,
            "volume": self.volume
        }

    @classmethod
    def from_string(cls, dim_str: str, weight: float = 0.0) -> 'ProductDimensions':
        length, width, height = parse_dimensions_string(dim_str)
        return cls(
            length=length,
            width=width,
            height=height,
            weight=weight,
            dimension_string=dim_str
        )


