# 🆕 v101.0: КАТЕГОРИЯ ТОВАРА (С ТИПОМ ПРОИСХОЖДЕНИЯ)
# ============================================================================
@dataclass
class ProductCategory:
    """🆕 v101.0: Категория товара с типом происхождения и сезонностью"""
    name: str
    description: str = ""
    parent_category: Optional[str] = None
    dimensions: Optional[ProductDimensions] = None
    typical_volume: float = 0.0
    typical_weight: float = 0.0
    oem_codes: List[str] = field(default_factory=list)
    cross_references: List[str] = field(default_factory=list)
    alternatives: List[str] = field(default_factory=list)
    compatibility: List[str] = field(default_factory=list)
    hazardous: bool = False
    fragile: bool = False
    requires_special_packaging: bool = False
    seasonality: 'Seasonality' = field(default_factory=lambda: Seasonality.ALL_YEAR)
    risk_level: 'RiskLevel' = field(default_factory=lambda: RiskLevel.LOW)
    price_range_min: float = 0.0
    price_range_max: float = 0.0
    margin_avg: float = 0.0
    demand_score: float = 0.0
    min_length: float = 0.0
    max_length: float = 0.0
    min_width: float = 0.0
    max_width: float = 0.0
    min_height: float = 0.0
    max_height: float = 0.0
    min_weight: float = 0.0
    max_weight: float = 0.0

    # 🆕 v101.0: Тип происхождения по умолчанию для категории
    product_origin_default: 'ProductOrigin' = field(default_factory=lambda: ProductOrigin.ANALOG_STANDARD)

    # 🆕 v101.0: Сезонность спроса (12 коэффициентов по месяцам)
    seasonality_demand: List[float] = field(default_factory=lambda: [1.0] * 12)

    # 🆕 v101.0: Возвраты по умолчанию для категории
    return_rate_base: float = 0.05

    # 🆕 v101.0: Средний ДРР для категории
    drr_base: float = 0.15

    def get_dimensions(self) -> ProductDimensions:
        return self.dimensions or ProductDimensions()

    # 🆕 v101.0: Получить коэффициент спроса для месяца
    def get_demand_coefficient(self, month: int) -> float:
        """Получить коэффициент спроса для месяца (1-12)"""
        if 1 <= month <= 12 and len(self.seasonality_demand) >= month:
            return self.seasonality_demand[month - 1]
        return 1.0

    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name, "description": self.description,
            "parent_category": self.parent_category,
            "typical_volume": self.typical_volume,
            "typical_weight": self.typical_weight,
            "oem_codes": self.oem_codes,
            "cross_references": self.cross_references,
            "hazardous": self.hazardous, "fragile": self.fragile,
            "seasonality": self.seasonality.value if hasattr(self.seasonality, 'value') else str(self.seasonality),
            "risk_level": self.risk_level.value if hasattr(self.risk_level, 'value') else str(self.risk_level),
            "product_origin_default": self.product_origin_default.value if hasattr(self.product_origin_default, 'value') else str(self.product_origin_default),
            "return_rate_base": self.return_rate_base,
        }


# ============================================================================
# 🆕 v101.0: РЕЗУЛЬТАТ РАСЧЁТА ЮНИТ-ЭКОНОМИКИ (ГЛАВНОЕ РАСШИРЕНИЕ)
# ============================================================================
@dataclass
class UnitEconomicsResult:
    """
    🆕 v101.0: Результат расчёта с расширенными полями:
    ✅ Тип товара (оригинал/аналог/Китай)
    ✅ ABC/XYZ-анализ
    ✅ Сезонность спроса
    ✅ Безубыточность в штуках
    ✅ Google Sheets интеграция
    ✅ Методы to_google_sheets_row() и to_excel_formula_row()
    """
    # === Базовые параметры ===
    marketplace: str
    operation_mode: str
    category: str
    price: float
    cost: float

    # === Габариты ===
    length: float
    width: float
    height: float
    weight: float
    volume: float

    # === Комиссии и сборы ===
    commission: float
    commission_percent: float
    logistics: float
    storage_cost: float
    acquiring: float
    delivery: float
    last_mile: float
    returns: float
    rko_fee: float
    premium_fee: float
    insurance_fee: float
    packing_fee: float
    marketing_fee: float
    subscription_cost: float
    hazardous_surcharge: float = 0.0
    fragile_surcharge: float = 0.0
    oversized_surcharge: float = 0.0

    # === Налоги ===
    tax_amount: float = 0.0
    tax_system: str = "УСН_6"

    # === Итоги ===
    total_expenses: float = 0.0
    profit: float = 0.0
    margin_percent: float = 0.0
    roi: float = 0.0
    breakeven_price: float = 0.0
    recommended_min_price: float = 0.0
    profit_per_ruble: float = 0.0
    contribution_margin: float = 0.0
    contribution_margin_ratio: float = 0.0

    # === Метаданные ===
    timestamp: datetime = field(default_factory=datetime.now)
    calculation_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    status: 'CalculationStatus' = field(default_factory=lambda: CalculationStatus.COMPLETED)
    tariff_source: 'TariffSource' = field(default_factory=lambda: TariffSource.HARDCODED)
    metadata: Dict[str, Any] = field(default_factory=dict)

    # === Сезонность и промо ===
    applied_seasonal_multiplier: float = 1.0
    applied_promo_discount: float = 0.0
    dynamic_adjustment: float = 0.0

    # === Дополнительные расходы ===
    billable_weight: float = 0.0
    advertising_cost: float = 0.0
    auto_parts_specific: float = 0.0

    # 🆕 v101.0: Тип товара (оригинал/аналог/Китай)
    product_origin: str = "analog_standard"
    product_origin_name: str = "Стандартный аналог"
    product_origin_icon: str = "🥈"

    # 🆕 v101.0: ABC/XYZ-анализ
    abc_class: Optional[str] = None          # "A", "B", "C"
    xyz_class: Optional[str] = None          # "X", "Y", "Z"
    abc_matrix_cell: Optional[str] = None    # "AX", "AY", ..., "CZ"
    abc_recommendation: str = ""
    profit_share_percent: float = 0.0        # Доля в общей прибыли
    demand_cv: float = 0.0                   # Коэффициент вариации спроса

    # 🆕 v101.0: Сезонность спроса
    demand_coefficient: float = 1.0          # Коэффициент спроса на текущий месяц
    seasonal_month: Optional[int] = None     # Месяц расчёта (1-12)
    seasonal_forecast_3m: List[float] = field(default_factory=list)  # Прогноз на 3 мес.

    # 🆕 v101.0: Безубыточность в штуках
    break_even_units: int = 0                # Сколько штук продать, чтобы выйти в ноль
    break_even_revenue: float = 0.0          # Выручка для безубыточности

    # 🆕 v101.0: Финансовые метрики
    cash_conversion_cycle_days: float = 0.0  # Цикл конверсии денег (дни)
    gross_margin_percent: float = 0.0        # Валовая маржа %
    net_margin_percent: float = 0.0          # Чистая маржа %
    markup_percent: float = 0.0              # Наценка %

    # 🆕 v101.0: Google Sheets
    google_sheets_id: Optional[str] = None
    google_sheets_url: Optional[str] = None
    google_sheets_row: Optional[int] = None

    # 🆕 v101.0: Рекомендации
    recommendations: List[str] = field(default_factory=list)
    risk_level: str = "LOW"

    def to_dict(self) -> Dict[str, Any]:
        """Сериализация в словарь"""
        result = asdict(self)
        result['timestamp'] = self.timestamp.isoformat()
        result['status'] = self.status.name if hasattr(self.status, 'name') else str(self.status)
        result['tariff_source'] = self.tariff_source.value if hasattr(self.tariff_source, 'value') else str(self.tariff_source)
        return result

    def to_dataframe(self) -> pd.DataFrame:
        """Преобразование в DataFrame"""
        return pd.DataFrame([self.to_dict()])

    def get_summary(self) -> Dict[str, Any]:
        """Краткая сводка"""
        return {
            "marketplace": self.marketplace,
            "profit": self.profit,
            "margin": self.margin_percent,
            "roi": self.roi,
            "breakeven": self.breakeven_price,
            "recommended_min_price": self.recommended_min_price,
            "total_expenses": self.total_expenses,
            "abc_class": self.abc_class,
            "product_origin": self.product_origin_name,
        }

    def get_profitability_level(self) -> 'ProfitabilityLevel':
        """Уровень рентабельности"""
        if self.profit < 0:
            return ProfitabilityLevel.LOSS
        elif self.profit == 0:
            return ProfitabilityLevel.BREAK_EVEN
        elif self.margin_percent < 5:
            return ProfitabilityLevel.LOW
        elif self.margin_percent < 15:
            return ProfitabilityLevel.MEDIUM
        elif self.margin_percent < 30:
            return ProfitabilityLevel.HIGH
        else:
            return ProfitabilityLevel.VERY_HIGH

    # 🆕 v101.0: Строка для Google Sheets
    def to_google_sheets_row(self, columns: Optional[List[str]] = None) -> List[Any]:
        """
        Преобразование в строку для прямой записи в Google Sheets.
        Возвращает список значений в порядке колонок.
        """
        default_columns = [
            'Артикул', 'marketplace', 'operation_mode', 'category',
            'product_origin_name', 'price', 'cost', 'profit',
            'margin_percent', 'roi', 'abc_class', 'xyz_class',
            'abc_matrix_cell', 'demand_coefficient', 'breakeven_price',
            'recommended_min_price', 'break_even_units',
        ]
        cols = columns or default_columns
        row = []
        data = self.to_dict()
        for col in cols:
            value = data.get(col, "")
            # Преобразуем сложные типы
            if isinstance(value, (list, dict)):
                value = str(value)
            elif isinstance(value, datetime):
                value = value.isoformat()
            elif isinstance(value, Enum):
                value = value.value
            row.append(value)
        return row

    # 🆕 v101.0: Строка с формулами для Excel
    def to_excel_formula_row(self, tariff_sheet: str = "📋 Тарифы",
                             input_row: int = 1) -> Dict[str, Any]:
        """
        Генерация строки с живыми формулами для Excel.
        Формулы ссылаются на лист "Тарифы" для динамического пересчёта.
        """
        row_data = {
            'Артикул': self.metadata.get('article', ''),
            'Бренд': self.metadata.get('brand', ''),
            'МП': self.marketplace,
            'Режим': self.operation_mode,
            'Категория': self.category,
            'Тип товара': self.product_origin_name,
            'Цена': self.price,
            'Себестоимость': self.cost,
            # Формулы для динамического пересчёта
            'Комиссия': f"={self.price}*VLOOKUP(B{input_row}&\"|\"&C{input_row},'{tariff_sheet}'!$A:$P,4,FALSE)",
            'Логистика': f"=VLOOKUP(B{input_row}&\"|\"&C{input_row},'{tariff_sheet}'!$A:$P,5,FALSE)+G{input_row}*VLOOKUP(B{input_row}&\"|\"&C{input_row},'{tariff_sheet}'!$A:$P,6,FALSE)",
            'Прибыль': f"=G{input_row}-H{input_row}-I{input_row}-J{input_row}",
            'Маржа %': f"=IF(G{input_row}>0,M{input_row}/G{input_row},0)",
        }
        return row_data

    # 🆕 v101.0: Рекомендация по ABC-анализу
    def get_abc_recommendation(self) -> str:
        """Получить рекомендацию на основе ABC/XYZ-анализа"""
        if self.abc_matrix_cell:
            try:
                cell = ABCMatrixCell.from_string(self.abc_matrix_cell)
                if cell:
                    return cell.get_recommendation()
            except Exception:
                pass
        return self.abc_recommendation

    # 🆕 v101.0: Проверка, товар прибыльный
    def is_profitable(self) -> bool:
        return self.profit > 0

    # 🆕 v101.0: Получить уровень риска
    def get_risk_level(self) -> str:
        """Определить уровень риска на основе метрик"""
        if self.profit < 0:
            return "CRITICAL"
        elif self.margin_percent < 5:
            return "HIGH"
        elif self.margin_percent < 15:
            return "MEDIUM"
        return "LOW"


