# 🆕 v101.0: РЕЗУЛЬТАТ ABC/XYZ-АНАЛИЗА
# ============================================================================
@dataclass
class ABCAnalysisResult:
    """
    🆕 v101.0: Результат ABC/XYZ-анализа каталога.
    Включает распределение по классам и матрицу рекомендаций.
    """
    total_items: int = 0
    class_a_count: int = 0
    class_b_count: int = 0
    class_c_count: int = 0
    class_a_profit_share: float = 0.0
    class_b_profit_share: float = 0.0
    class_c_profit_share: float = 0.0

    # XYZ-анализ
    class_x_count: int = 0
    class_y_count: int = 0
    class_z_count: int = 0

    # Матрица 3x3
    matrix: Dict[str, int] = field(default_factory=dict)  # {"AX": 10, "AY": 5, ...}
    matrix_recommendations: Dict[str, str] = field(default_factory=dict)

    # Топ товары
    top_a_items: List[Dict[str, Any]] = field(default_factory=list)
    bottom_c_items: List[Dict[str, Any]] = field(default_factory=list)

    # Метаданные
    analysis_date: datetime = field(default_factory=datetime.now)
    category: Optional[str] = None
    marketplace: Optional[str] = None

    def to_dict(self) -> Dict[str, Any]:
        return {
            "total_items": self.total_items,
            "class_a": {"count": self.class_a_count, "profit_share": self.class_a_profit_share},
            "class_b": {"count": self.class_b_count, "profit_share": self.class_b_profit_share},
            "class_c": {"count": self.class_c_count, "profit_share": self.class_c_profit_share},
            "class_x": self.class_x_count,
            "class_y": self.class_y_count,
            "class_z": self.class_z_count,
            "matrix": self.matrix,
            "analysis_date": self.analysis_date.isoformat(),
        }

    def to_dataframe(self) -> pd.DataFrame:
        """Преобразование в DataFrame для визуализации"""
        data = []
        for abc in ["A", "B", "C"]:
            for xyz in ["X", "Y", "Z"]:
                cell = f"{abc}{xyz}"
                count = self.matrix.get(cell, 0)
                try:
                    rec = ABCMatrixCell.from_string(cell).get_recommendation()
                except Exception:
                    rec = ""
                data.append({
                    "Класс": cell,
                    "ABC": abc,
                    "XYZ": xyz,
                    "Количество SKU": count,
                    "Рекомендация": rec,
                })
        return pd.DataFrame(data)


# ============================================================================
# 🆕 v101.0: РЕЗУЛЬТАТ АНАЛИЗА ЧУВСТВИТЕЛЬНОСТИ
# ============================================================================
@dataclass
class SensitivityResult:
    """
    🆕 v101.0: Результат анализа чувствительности.
    Показывает, как изменится прибыль при изменении параметров.
    """
    base_profit: float = 0.0
    base_price: float = 0.0
    base_cost: float = 0.0
    scenarios: List[Dict[str, Any]] = field(default_factory=list)
    # scenarios = [{"name": "Цена +5%", "profit": 1000, "delta": 50, "delta_percent": 5.0}, ...]

    most_sensitive_parameter: str = ""
    least_sensitive_parameter: str = ""
    sensitivity_coefficient: float = 0.0  # Коэффициент чувствительности

    def to_dict(self) -> Dict[str, Any]:
        return {
            "base_profit": self.base_profit,
            "base_price": self.base_price,
            "base_cost": self.base_cost,
            "scenarios": self.scenarios,
            "most_sensitive": self.most_sensitive_parameter,
            "least_sensitive": self.least_sensitive_parameter,
            "sensitivity_coefficient": self.sensitivity_coefficient,
        }

    def to_dataframe(self) -> pd.DataFrame:
        return pd.DataFrame(self.scenarios)

    def get_top_3_sensitive(self) -> List[Dict[str, Any]]:
        """Топ-3 самых чувствительных параметра"""
        sorted_scenarios = sorted(
            self.scenarios,
            key=lambda x: abs(x.get('delta_percent', 0)),
            reverse=True
        )
        return sorted_scenarios[:3]


