# 🆕 v101.0: РЕЗУЛЬТАТ ПРОГНОЗА (РАСШИРЕННЫЙ)
# ============================================================================
@dataclass
class ForecastResult:
    """🆕 v101.0: Результат прогноза с сезонностью спроса"""
    periods: List[datetime] = field(default_factory=list)
    values: List[float] = field(default_factory=list)
    seasonality: List[float] = field(default_factory=list)
    trend: List[float] = field(default_factory=list)
    confidence_intervals: Tuple[List[float], List[float]] = ([], [])
    metadata: Dict[str, Any] = field(default_factory=dict)
    forecasted_rates: Optional[Dict[str, List[float]]] = None
    monthly_forecast: Optional[Dict[str, Dict[str, float]]] = None

    # 🆕 v101.0: Сезонность спроса по категориям
    demand_seasonality: List[float] = field(default_factory=list)
    category: Optional[str] = None
    demand_coefficients: List[float] = field(default_factory=list)

    # 🆕 v101.0: Прогноз по типам товаров
    forecast_by_origin: Optional[Dict[str, List[float]]] = None

    def to_dataframe(self) -> pd.DataFrame:
        df = pd.DataFrame({
            "period": self.periods, "value": self.values,
            "seasonality": self.seasonality, "trend": self.trend,
            "lower_bound": self.confidence_intervals[0] if self.confidence_intervals else [],
            "upper_bound": self.confidence_intervals[1] if self.confidence_intervals else []
        })
        if self.forecasted_rates:
            for rate_name, values in self.forecasted_rates.items():
                df[f"forecast_{rate_name}"] = values[:len(df)]
        # 🆕 v101.0: Добавляем сезонность спроса
        if self.demand_coefficients:
            df["demand_coefficient"] = self.demand_coefficients[:len(df)]
        return df


