# 🆕 v101.0: ЗАПИСЬ КЭША ТАРИФОВ (С GOOGLE SHEETS)
# ============================================================================
@dataclass
class TariffCacheEntry:
    """🆕 v101.0: Запись кэша тарифов с Google Sheets интеграцией"""
    marketplace: str
    category: Optional[str]
    data: Dict[str, Any]
    source: 'TariffSource'
    timestamp: float
    ttl_seconds: int = 86400
    version: str = "2026.1"
    notes: str = ""
    forecast_data: Optional[Dict[str, Any]] = None
    historical_data: Optional[List[Dict[str, Any]]] = None

    # 🆕 v101.0: Google Sheets интеграция
    google_sheets_id: Optional[str] = None
    google_sheets_url: Optional[str] = None
    last_sync_from_sheets: Optional[float] = None

    # 🆕 v101.0: Доверие к данным
    confidence: float = 1.0
    update_mode: str = "manual"  # manual / ai / api / hybrid

    def is_expired(self) -> bool:
        return time.time() - self.timestamp > self.ttl_seconds

    def to_dict(self) -> Dict[str, Any]:
        return {
            "marketplace": self.marketplace, "category": self.category,
            "data": self.data,
            "source": self.source.value if hasattr(self.source, 'value') else str(self.source),
            "timestamp": self.timestamp, "ttl_seconds": self.ttl_seconds,
            "version": self.version, "notes": self.notes,
            "forecast_data": self.forecast_data,
            "historical_data": self.historical_data,
            "google_sheets_id": self.google_sheets_id,
            "google_sheets_url": self.google_sheets_url,
            "confidence": self.confidence,
            "update_mode": self.update_mode,
        }

    @staticmethod
    def from_dict(d: Dict[str, Any]) -> 'TariffCacheEntry':
        source_value = d.get("source", "HARDCODED")
        try:
            source = TariffSource(source_value)
        except ValueError:
            source = TariffSource.HARDCODED
        return TariffCacheEntry(
            marketplace=d.get("marketplace", ""),
            category=d.get("category"),
            data=d.get("data", {}),
            source=source,
            timestamp=d.get("timestamp", 0),
            ttl_seconds=d.get("ttl_seconds", 86400),
            version=d.get("version", "2026.1"),
            notes=d.get("notes", ""),
            forecast_data=d.get("forecast_data"),
            historical_data=d.get("historical_data"),
            google_sheets_id=d.get("google_sheets_id"),
            google_sheets_url=d.get("google_sheets_url"),
            confidence=d.get("confidence", 1.0),
            update_mode=d.get("update_mode", "manual"),
        )
