# 🆕 v101.0: УТИЛИТА ДЛЯ ПОЛУЧЕНИЯ КОЛОНКИ ПО ИНДЕКСУ
# ============================================================================
def get_column_letter(col_idx: int) -> str:
    """Преобразование индекса колонки в букву (1=A, 26=Z, 27=AA)"""
    result = ""
    while col_idx > 0:
        col_idx, remainder = divmod(col_idx - 1, 26)
        result = chr(65 + remainder) + result
    return result
