# 🆕 v101.0: УТИЛИТЫ ДЛЯ РАБОТЫ С КАТЕГОРИЯМИ
# ============================================================================
def get_category_defaults(category_name: str) -> Dict[str, Any]:
    """
    🆕 v101.0: Получить все дефолтные параметры для категории.

    Returns:
        Dict с product_origin, seasonality, return_rate, drr
    """
    categories = get_auto_parts_categories_full()
    cat = categories.get(category_name.lower().strip())
    if not cat:
        return {
            "product_origin": ProductOrigin.ANALOG_STANDARD,
            "return_rate": 0.05,
            "drr": 0.15,
            "seasonality_demand": [1.0] * 12,
        }
    return {
        "product_origin": cat.product_origin_default,
        "return_rate": cat.return_rate_base,
        "drr": cat.drr_base,
        "seasonality_demand": cat.seasonality_demand,
    }


def get_category_demand_coefficient(category_name: str, month: int) -> float:
    """
    🆕 v101.0: Получить коэффициент спроса для категории и месяца.

    Args:
        category_name: Название категории
        month: Месяц (1-12)

    Returns:
        Коэффициент спроса (1.0 = среднемесячный)
    """
    if not (1 <= month <= 12):
        return 1.0
    categories = get_auto_parts_categories_full()
    cat = categories.get(category_name.lower().strip())
    if not cat:
        return 1.0
    return cat.seasonality_demand[month - 1]


def get_categories_by_origin(origin: ProductOrigin) -> List[str]:
    """
    🆕 v101.0: Получить список категорий для заданного типа товара.
    """
    categories = get_auto_parts_categories_full()
    return [
        name for name, cat in categories.items()
        if cat.product_origin_default == origin
    ]


def get_high_return_categories(threshold: float = 0.08) -> List[Tuple[str, float]]:
    """
    🆕 v101.0: Получить категории с высоким уровнем возвратов.
    """
    categories = get_auto_parts_categories_full()
    return [
        (name, cat.return_rate_base)
        for name, cat in categories.items()
        if cat.return_rate_base >= threshold
    ]


def get_seasonal_categories(month: int, threshold: float = 1.3) -> List[Tuple[str, float]]:
    """
    🆕 v101.0: Получить категории с высоким спросом в заданный месяц.

    Args:
        month: Месяц (1-12)
        threshold: Порог коэффициента спроса (1.3 = на 30% выше среднего)

    Returns:
        Список (категория, коэффициент)
    """
    if not (1 <= month <= 12):
        return []
    categories = get_auto_parts_categories_full()
    result = []
    for name, cat in categories.items():
        coeff = cat.seasonality_demand[month - 1]
        if coeff >= threshold:
            result.append((name, coeff))
    return sorted(result, key=lambda x: x[1], reverse=True)
