# 🆕 v101.0: РАСШИРЕННЫЙ ПОИСК КРОСС-ССЫЛОК
# ============================================================================
class OEMCrossReferenceFinder:
    """
    🆕 v101.0: Расширенный поиск кросс-ссылок между OE-номерами.

    Поддерживает:
    ✅ Многоуровневый поиск (прямые + косвенные связи)
    ✅ Фильтрация по брендам
    ✅ Приоритизация по качеству аналогов
    """

    def __init__(self):
        self.cross_graph = defaultdict(set)  # OE → множество связанных OE
        self.oe_to_parts = defaultdict(list)  # OE → список (artikul, brand)
        self.brand_quality = {}  # brand → качество (0-1)

        # Качество брендов (по умолчанию)
        self._init_brand_quality()

    def _init_brand_quality(self):
        """Инициализация качества брендов"""
        # Премиум бренды
        premium = [
            "bosch", "trw", "lemforder", "sachs", "bilstein",
            "mann", "knecht", "mahle", "ngk", "denso",
            "valeo", " Continental", "siemens", "hella",
            "skf", "fag", "ntn", "koyo", "nsk"
        ]
        for brand in premium:
            self.brand_quality[brand.lower()] = 0.95

        # Стандартные бренды
        standard = [
            "patron", "stellox", "fenox", "fortech", "hola",
            "lynx", "masuma", "sat", "tsn", "pilenga"
        ]
        for brand in standard:
            self.brand_quality[brand.lower()] = 0.70

        # Китайские бренды
        china = [
            "cn", "tco", "yes", "webasto_cn", "generic_cn"
        ]
        for brand in china:
            self.brand_quality[brand.lower()] = 0.40

    def load_cross_data(self, df: pd.DataFrame):
        """
        Загрузка кросс-ссылок.

        Ожидаемые колонки:
        - oe_number
        - artikul
        - brand
        """
        if df.empty:
            return

        # Строим граф связей между OE
        oe_to_parts_local = defaultdict(list)
        for _, row in df.iterrows():
            oe = str(row.get('oe_number', '')).strip()
            artikul = str(row.get('artikul', '')).strip()
            brand = str(row.get('brand', '')).strip()

            if oe and artikul:
                oe_to_parts_local[oe].append((artikul, brand))

        # Для каждого OE находим все связанные OE через общие товары
        for oe, parts in oe_to_parts_local.items():
            self.oe_to_parts[oe] = parts
            for artikul, brand in parts:
                # Находим все OE этого товара
                for other_oe, other_parts in oe_to_parts_local.items():
                    if other_oe != oe:
                        for other_art, other_brand in other_parts:
                            if (other_art, other_brand) in parts:
                                self.cross_graph[oe].add(other_oe)
                                self.cross_graph[other_oe].add(oe)

    def find_related_oes(self, oe_number: str,
                         max_depth: int = 2,
                         max_results: int = 50) -> List[Dict[str, Any]]:
        """
        🆕 v101.0: Поиск связанных OE-номеров (многоуровневый).

        Args:
            oe_number: Исходный OE-номер
            max_depth: Макс. глубина поиска (1 = прямые связи, 2 = косвенные)
            max_results: Макс. количество результатов

        Returns:
            List of Dict с информацией о связанных OE
        """
        if not oe_number:
            return []

        visited = {oe_number}
        queue = [(oe_number, 0)]  # (OE, глубина)
        results = []

        while queue and len(results) < max_results:
            current_oe, depth = queue.pop(0)

            if depth >= max_depth:
                continue

            for related_oe in self.cross_graph.get(current_oe, set()):
                if related_oe in visited:
                    continue

                visited.add(related_oe)
                queue.append((related_oe, depth + 1))

                # Получаем информацию о связанных товарах
                for artikul, brand in self.oe_to_parts.get(related_oe, []):
                    quality = self.brand_quality.get(brand.lower(), 0.5)
                    results.append({
                        "oe_number": related_oe,
                        "artikul": artikul,
                        "brand": brand,
                        "depth": depth + 1,
                        "quality": quality,
                        "relation": "direct" if depth == 0 else "indirect",
                    })

        # Сортируем по качеству и глубине
        results.sort(
            key=lambda x: (-x["quality"], x["depth"])
        )

        return results[:max_results]

    def find_analogs_prioritized(self, artikul: str, brand: str,
                                  max_results: int = 30) -> List[Dict[str, Any]]:
        """
        🆕 v101.0: Поиск аналогов с приоритизацией по качеству.

        Returns:
            List of Dict, отсортированный по качеству бренда
        """
        # Находим OE-номера товара
        oe_numbers = []
        for oe, parts in self.oe_to_parts.items():
            if (artikul, brand) in parts:
                oe_numbers.append(oe)

        if not oe_numbers:
            return []

        # Собираем все аналоги
        all_analogs = []
        seen = set()
        seen.add((artikul, brand))

        for oe in oe_numbers:
            for related_oe in self.cross_graph.get(oe, {oe}):
                for related_art, related_brand in self.oe_to_parts.get(related_oe, []):
                    key = (related_art, related_brand)
                    if key in seen:
                        continue
                    seen.add(key)

                    quality = self.brand_quality.get(related_brand.lower(), 0.5)
                    all_analogs.append({
                        "oe_number": related_oe,
                        "artikul": related_art,
                        "brand": related_brand,
                        "quality": quality,
                        "quality_label": self._get_quality_label(quality),
                    })

        # Сортируем по качеству
        all_analogs.sort(key=lambda x: -x["quality"])
        return all_analogs[:max_results]

    def _get_quality_label(self, quality: float) -> str:
        """Получение текстовой метки качества"""
        if quality >= 0.9:
            return "🏆 Премиум"
        elif quality >= 0.7:
            return "🥈 Стандарт"
        elif quality >= 0.5:
            return "🥉 Бюджет"
        else:
            return "⚠️ Китай"

    def get_brand_quality(self, brand: str) -> float:
        """Получение качества бренда"""
        return self.brand_quality.get(brand.lower(), 0.5)

    def set_brand_quality(self, brand: str, quality: float):
        """Установка качества бренда"""
        self.brand_quality[brand.lower()] = max(0.0, min(1.0, quality))
