# 🆕 v101.0: ДЕКОРАТОР ПРОФИЛИРОВАНИЯ
# ============================================================================
def profile_execution(operation_name: Optional[str] = None,
                      log_slow: bool = True,
                      track_memory: bool = False) -> Callable:
    """
    🆕 v101.0: Декоратор для профилирования выполнения функций.

    Args:
        operation_name: Название операции (по умолчанию — имя функции)
        log_slow: Логировать медленные операции
        track_memory: Отслеживать использование памяти

    Usage:
        @profile_execution("calculate_unit_economics")
        def calculate(...):
            ...
    """
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Получаем profiler из глобального менеджера
            profiler = get_performance_manager().profiler
            if not profiler or not profiler.enabled:
                return func(*args, **kwargs)

            op_name = operation_name or func.__name__
            start_time = time.perf_counter()
            start_memory = None

            if track_memory and PSUTIL_AVAILABLE:
                try:
                    process = psutil.Process(os.getpid())
                    start_memory = process.memory_info().rss / (1024 * 1024)
                except Exception:
                    pass

            try:
                result = func(*args, **kwargs)
                elapsed_ms = (time.perf_counter() - start_time) * 1000
                success = True
                error = None
            except Exception as e:
                elapsed_ms = (time.perf_counter() - start_time) * 1000
                success = False
                error = str(e)
                result = None
                raise
            finally:
                memory_delta = None
                if track_memory and start_memory is not None and PSUTIL_AVAILABLE:
                    try:
                        process = psutil.Process(os.getpid())
                        current_memory = process.memory_info().rss / (1024 * 1024)
                        memory_delta = current_memory - start_memory
                    except Exception:
                        pass

                profiler.record_operation(
                    operation=op_name,
                    duration_ms=elapsed_ms,
                    success=success,
                    error=error,
                    memory_delta_mb=memory_delta,
                )

                # Логируем медленные операции
                if log_slow and elapsed_ms > profiler.slow_threshold_ms:
                    logger.warning(
                        f"⏱️ Медленная операция: {op_name} "
                        f"({elapsed_ms:.0f} мс)"
                    )

            return result
        return wrapper
    return decorator


