# 🆕 v101.0: RATE LIMITER ДЛЯ GOOGLE SHEETS API
# ============================================================================
class GoogleSheetsRateLimiter:
    """
    🆕 v101.0: Rate limiter для Google Sheets API.

    Google API лимиты:
    - 100 запросов на пользователя за 100 секунд
    - 60 запросов в минуту
    - 30 операций записи в минуту

    Использует алгоритм Token Bucket + sliding window.
    """

    def __init__(self,
                 max_per_100_sec: int = 100,
                 max_per_minute: int = 60,
                 max_writes_per_minute: int = 30,
                 backoff_factor: float = 2.0,
                 max_backoff_seconds: float = 60.0):
        self.max_per_100_sec = max_per_100_sec
        self.max_per_minute = max_per_minute
        self.max_writes_per_minute = max_writes_per_minute
        self.backoff_factor = backoff_factor
        self.max_backoff_seconds = max_backoff_seconds

        # История запросов (timestamp)
        self._requests_100s = deque(maxlen=max_per_100_sec * 2)
        self._requests_1m = deque(maxlen=max_per_minute * 2)
        self._writes_1m = deque(maxlen=max_writes_per_minute * 2)

        # Статистика
        self.stats = {
            "total_requests": 0,
            "total_writes": 0,
            "throttled_requests": 0,
            "total_wait_time_seconds": 0.0,
            "errors": 0,
        }

        self._lock = threading.Lock()

    def _clean_old_requests(self):
        """Удаление старых запросов из истории"""
        now = time.time()
        while self._requests_100s and now - self._requests_100s[0] > 100:
            self._requests_100s.popleft()
        while self._requests_1m and now - self._requests_1m[0] > 60:
            self._requests_1m.popleft()
        while self._writes_1m and now - self._writes_1m[0] > 60:
            self._writes_1m.popleft()

    def _calculate_wait_time(self, is_write: bool = False) -> float:
        """Расчёт времени ожидания перед следующим запросом"""
        now = time.time()
        wait_time = 0.0

        # Проверка лимита 100 сек
        if len(self._requests_100s) >= self.max_per_100_sec:
            oldest = self._requests_100s[0]
            wait_100s = max(0.0, 100 - (now - oldest))
            wait_time = max(wait_time, wait_100s)

        # Проверка лимита 1 мин
        if len(self._requests_1m) >= self.max_per_minute:
            oldest = self._requests_1m[0]
            wait_1m = max(0.0, 60 - (now - oldest))
            wait_time = max(wait_time, wait_1m)

        # Проверка лимита записей
        if is_write and len(self._writes_1m) >= self.max_writes_per_minute:
            oldest = self._writes_1m[0]
            wait_writes = max(0.0, 60 - (now - oldest))
            wait_time = max(wait_time, wait_writes)

        return min(wait_time, self.max_backoff_seconds)

    def acquire(self, is_write: bool = False) -> bool:
        """
        Получение разрешения на запрос.

        Args:
            is_write: Это операция записи?

        Returns:
            True если запрос разрешён, False если превышен лимит
        """
        with self._lock:
            self._clean_old_requests()

            wait_time = self._calculate_wait_time(is_write)

            if wait_time > 0:
                # Ждём
                logger.info(
                    f"⏳ Google Sheets rate limit: ожидание {wait_time:.1f} сек"
                )
                time.sleep(wait_time)
                self.stats["throttled_requests"] += 1
                self.stats["total_wait_time_seconds"] += wait_time

            now = time.time()
            self._requests_100s.append(now)
            self._requests_1m.append(now)
            self.stats["total_requests"] += 1

            if is_write:
                self._writes_1m.append(now)
                self.stats["total_writes"] += 1

            return True

    @contextmanager
    def rate_limit(self, is_write: bool = False):
        """
        Контекстный менеджер для rate limiting.

        Usage:
            with rate_limiter.rate_limit(is_write=True):
                sheets_api.write(...)
        """
        self.acquire(is_write=is_write)
        try:
            yield
        except Exception as e:
            self.stats["errors"] += 1
            raise

    def get_stats(self) -> Dict[str, Any]:
        """Получение статистики"""
        with self._lock:
            return {
                **self.stats,
                "current_100s_requests": len(self._requests_100s),
                "current_1m_requests": len(self._requests_1m),
                "current_1m_writes": len(self._writes_1m),
                "available_100s": max(0, self.max_per_100_sec - len(self._requests_100s)),
                "available_1m": max(0, self.max_per_minute - len(self._requests_1m)),
            }

    def reset(self):
        """Сброс статистики"""
        with self._lock:
            self._requests_100s.clear()
            self._requests_1m.clear()
            self._writes_1m.clear()
            for key in self.stats:
                self.stats[key] = 0


# ============================================================================
# 🆕 v101.0: ПРОФИЛИРОВЩИК ВЫПОЛНЕНИЯ
# ============================================================================
class ExecutionProfiler:
    """
    🆕 v101.0: Профилировщик выполнения операций.

    Отслеживает:
    - Время выполнения операций
    - Успешность операций
    - Использование памяти
    - Узкие места (bottlenecks)
    """

    def __init__(self,
                 enabled: bool = True,
                 slow_threshold_ms: float = 1000.0,
                 keep_last_n: int = 1000):
        self.enabled = enabled
        self.slow_threshold_ms = slow_threshold_ms
        self.keep_last_n = keep_last_n

        # История операций
        self._operations = deque(maxlen=keep_last_n)

        # Агрегированная статистика по операциям
        self._operation_stats = defaultdict(lambda: {
            "count": 0,
            "total_ms": 0.0,
            "min_ms": float('inf'),
            "max_ms": 0.0,
            "success_count": 0,
            "error_count": 0,
            "total_memory_mb": 0.0,
        })

        self._lock = threading.Lock()

    def record_operation(self,
                         operation: str,
                         duration_ms: float,
                         success: bool = True,
                         error: Optional[str] = None,
                         memory_delta_mb: Optional[float] = None):
        """Запись операции"""
        if not self.enabled:
            return

        with self._lock:
            # Добавляем в историю
            self._operations.append({
                "operation": operation,
                "duration_ms": duration_ms,
                "success": success,
                "error": error,
                "memory_delta_mb": memory_delta_mb,
                "timestamp": datetime.now().isoformat(),
            })

            # Обновляем агрегированную статистику
            stats = self._operation_stats[operation]
            stats["count"] += 1
            stats["total_ms"] += duration_ms
            stats["min_ms"] = min(stats["min_ms"], duration_ms)
            stats["max_ms"] = max(stats["max_ms"], duration_ms)
            if success:
                stats["success_count"] += 1
            else:
                stats["error_count"] += 1
            if memory_delta_mb is not None:
                stats["total_memory_mb"] += memory_delta_mb

    def get_stats(self) -> Dict[str, Any]:
        """Получение статистики по операциям"""
        with self._lock:
            result = {}
            for op, stats in self._operation_stats.items():
                count = stats["count"]
                if count > 0:
                    result[op] = {
                        "count": count,
                        "avg_ms": stats["total_ms"] / count,
                        "min_ms": stats["min_ms"] if stats["min_ms"] != float('inf') else 0,
                        "max_ms": stats["max_ms"],
                        "total_ms": stats["total_ms"],
                        "success_rate": stats["success_count"] / count,
                        "error_count": stats["error_count"],
                        "avg_memory_mb": stats["total_memory_mb"] / count if count > 0 else 0,
                    }
            return result

    def get_slow_operations(self, threshold_ms: Optional[float] = None) -> List[Dict]:
        """Получение списка медленных операций"""
        threshold = threshold_ms or self.slow_threshold_ms
        with self._lock:
            return [
                op for op in self._operations
                if op["duration_ms"] > threshold
            ]

    def get_bottlenecks(self, top_n: int = 5) -> List[Dict[str, Any]]:
        """
        🆕 v101.0: Поиск узких мест (bottlenecks).

        Возвращает top_n операций с наибольшим суммарным временем.
        """
        stats = self.get_stats()
        bottlenecks = []
        for op, data in stats.items():
            bottlenecks.append({
                "operation": op,
                "total_time_ms": data["total_ms"],
                "avg_time_ms": data["avg_ms"],
                "count": data["count"],
                "error_rate": 1 - data["success_rate"],
            })

        # Сортируем по суммарному времени
        bottlenecks.sort(key=lambda x: x["total_time_ms"], reverse=True)
        return bottlenecks[:top_n]

    def get_recent_operations(self, limit: int = 50) -> List[Dict]:
        """Получение последних операций"""
        with self._lock:
            return list(self._operations)[-limit:]

    def export_to_json(self, file_path: str) -> bool:
        """Экспорт статистики в JSON"""
        try:
            data = {
                "stats": self.get_stats(),
                "bottlenecks": self.get_bottlenecks(top_n=10),
                "slow_operations": [
                    {
                        "operation": op["operation"],
                        "duration_ms": op["duration_ms"],
                        "timestamp": op["timestamp"],
                    }
                    for op in self.get_slow_operations()[:100]
                ],
                "exported_at": datetime.now().isoformat(),
            }
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            return True
        except Exception as e:
            logger.error(f"Ошибка экспорта профилировщика: {e}")
            return False

    def reset(self):
        """Сброс статистики"""
        with self._lock:
            self._operations.clear()
            self._operation_stats.clear()


# ============================================================================
# 🆕 v101.0: ОПТИМИЗАТОР ПАМЯТИ
# ============================================================================
class MemoryOptimizer:
    """
    🆕 v101.0: Автоматический оптимизатор памяти.

    Функции:
    - Автоматический GC при превышении порога
    - Оптимизация DataFrame (downcast типов)
    - Очистка кэшей
    - Отслеживание роста памяти
    """

    def __init__(self,
                 warning_threshold_mb: float = 2048,
                 critical_threshold_mb: float = 4096,
                 emergency_threshold_mb: float = 6144):
        self.warning_threshold_mb = warning_threshold_mb
        self.critical_threshold_mb = critical_threshold_mb
        self.emergency_threshold_mb = emergency_threshold_mb

        self.last_memory_mb = 0.0
        self.gc_count = 0
        self.optimization_count = 0

        self.stats = {
            "gc_runs": 0,
            "memory_freed_mb": 0.0,
            "dataframes_optimized": 0,
            "caches_cleared": 0,
        }

    def check_and_optimize(self, force: bool = False) -> Dict[str, Any]:
        """
        Проверка памяти и автоматическая оптимизация.

        Returns:
            Dict с результатами
        """
        result = {
            "action_taken": None,
            "memory_before_mb": 0.0,
            "memory_after_mb": 0.0,
            "freed_mb": 0.0,
        }

        if not PSUTIL_AVAILABLE:
            return result

        try:
            process = psutil.Process(os.getpid())
            memory_mb = process.memory_info().rss / (1024 * 1024)
            result["memory_before_mb"] = memory_mb

            # Определяем необходимое действие
            action = None
            if memory_mb > self.emergency_threshold_mb or force:
                action = "emergency"
            elif memory_mb > self.critical_threshold_mb:
                action = "critical"
            elif memory_mb > self.warning_threshold_mb:
                action = "warning"

            if action:
                result["action_taken"] = action

                # Запускаем GC
                gc.collect()

                # Очищаем кэши Polars
                if POLARS_AVAILABLE and hasattr(pl, 'free_memory'):
                    try:
                        pl.free_memory()
                    except Exception:
                        pass

                memory_after = process.memory_info().rss / (1024 * 1024)
                result["memory_after_mb"] = memory_after
                result["freed_mb"] = memory_mb - memory_after

                self.stats["gc_runs"] += 1
                self.stats["memory_freed_mb"] += result["freed_mb"]

                logger.info(
                    f"🧹 Memory optimization ({action}): "
                    f"{memory_mb:.0f} MB → {memory_after:.0f} MB "
                    f"(освобождено {result['freed_mb']:.0f} MB)"
                )

            self.last_memory_mb = memory_mb

        except Exception as e:
            logger.error(f"Ошибка проверки памяти: {e}")

        return result

    def optimize_dataframe(self, df: pd.DataFrame) -> pd.DataFrame:
        """
        🆕 v101.0: Оптимизация DataFrame (downcast типов).

        Уменьшает использование памяти за счёт:
        - Преобразования float64 → float32 где возможно
        - Преобразования int64 → int32/int16 где возможно
        - Категоризации строковых колонок
        """
        if df.empty:
            return df

        try:
            df = df.copy()
            start_memory = df.memory_usage(deep=True).sum() / (1024 * 1024)

            # Числовые колонки
            for col in df.select_dtypes(include=['float64']).columns:
                # Проверяем, можно ли downcast до float32
                col_min = df[col].min()
                col_max = df[col].max()
                if (pd.notna(col_min) and pd.notna(col_max) and
                        col_min >= np.finfo(np.float32).min and
                        col_max <= np.finfo(np.float32).max):
                    df[col] = pd.to_numeric(df[col], downcast='float')

            for col in df.select_dtypes(include=['int64']).columns:
                col_min = df[col].min()
                col_max = df[col].max()
                if pd.notna(col_min) and pd.notna(col_max):
                    if col_min >= np.iinfo(np.int16).min and col_max <= np.iinfo(np.int16).max:
                        df[col] = pd.to_numeric(df[col], downcast='integer')
                    elif col_min >= np.iinfo(np.int32).min and col_max <= np.iinfo(np.int32).max:
                        df[col] = pd.to_numeric(df[col], downcast='integer')

            # Строковые колонки с малым количеством уникальных значений → category
            for col in df.select_dtypes(include=['object']).columns:
                nunique = df[col].nunique()
                if nunique > 0 and nunique < len(df) * 0.5 and nunique < 100:
                    try:
                        df[col] = df[col].astype('category')
                    except Exception:
                        pass

            end_memory = df.memory_usage(deep=True).sum() / (1024 * 1024)
            saved_mb = start_memory - end_memory

            if saved_mb > 0.1:
                self.stats["dataframes_optimized"] += 1
                logger.debug(
                    f"📊 DataFrame оптимизирован: "
                    f"{start_memory:.2f} MB → {end_memory:.2f} MB "
                    f"(сохранено {saved_mb:.2f} MB)"
                )

        except Exception as e:
            logger.warning(f"Ошибка оптимизации DataFrame: {e}")

        return df

    def get_stats(self) -> Dict[str, Any]:
        """Получение статистики"""
        result = self.stats.copy()
        if PSUTIL_AVAILABLE:
            try:
                process = psutil.Process(os.getpid())
                result["current_memory_mb"] = process.memory_info().rss / (1024 * 1024)
                result["system_memory_percent"] = psutil.virtual_memory().percent
            except Exception:
                pass
        return result


# ============================================================================
# 🆕 v101.0: ДЕТЕКТОР УЗКИХ МЕСТ
# ============================================================================
class BottleneckDetector:
    """
    🆕 v101.0: Автоматический поиск узких мест в расчётах.

    Анализирует:
    - Самые медленные операции
    - Операции с высоким потреблением памяти
    - Операции с высоким процентом ошибок
    - Рекомендации по оптимизации
    """

    def __init__(self, profiler: ExecutionProfiler):
        self.profiler = profiler

    def analyze(self) -> Dict[str, Any]:
        """Полный анализ узких мест"""
        stats = self.profiler.get_stats()
        bottlenecks = self.profiler.get_bottlenecks(top_n=10)

        analysis = {
            "total_operations": sum(s["count"] for s in stats.values()),
            "total_time_ms": sum(s["total_ms"] for s in stats.values()),
            "bottlenecks": bottlenecks,
            "recommendations": [],
            "critical_issues": [],
        }

        # Анализ медленных операций
        for bn in bottlenecks:
            if bn["avg_time_ms"] > 5000:  # > 5 сек
                analysis["critical_issues"].append({
                    "type": "slow_operation",
                    "operation": bn["operation"],
                    "avg_ms": bn["avg_time_ms"],
                    "recommendation": (
                        f"Операция '{bn['operation']}' очень медленная "
                        f"({bn['avg_ms']:.0f} мс). "
                        "Рассмотрите оптимизацию или кэширование."
                    ),
                })

        # Анализ ошибок
        for op, data in stats.items():
            error_rate = 1 - data["success_rate"]
            if error_rate > 0.1 and data["count"] > 10:  # > 10% ошибок
                analysis["critical_issues"].append({
                    "type": "high_error_rate",
                    "operation": op,
                    "error_rate": error_rate,
                    "recommendation": (
                        f"Операция '{op}' имеет высокий процент ошибок "
                        f"({error_rate:.1%}). Проверьте входные данные."
                    ),
                })

        # Анализ памяти
        for op, data in stats.items():
            if data["avg_memory_mb"] > 100:  # > 100 МБ на операцию
                analysis["recommendations"].append({
                    "type": "high_memory",
                    "operation": op,
                    "avg_memory_mb": data["avg_memory_mb"],
                    "recommendation": (
                        f"Операция '{op}' потребляет много памяти "
                        f"({data['avg_memory_mb']:.1f} МБ). "
                        "Рассмотрите батчевую обработку."
                    ),
                })

        # Общие рекомендации
        if analysis["total_time_ms"] > 60000:  # > 1 мин суммарно
            analysis["recommendations"].append({
                "type": "general",
                "recommendation": (
                    "Общее время выполнения операций превышает 1 минуту. "
                    "Рекомендуется включить параллельную обработку."
                ),
            })

        return analysis

    def get_report(self) -> str:
        """Получение текстового отчёта"""
        analysis = self.analyze()

        lines = [
            "=" * 60,
            "📊 ОТЧЁТ О ПРОИЗВОДИТЕЛЬНОСТИ",
            "=" * 60,
            f"Всего операций: {analysis['total_operations']:,}",
            f"Общее время: {analysis['total_time_ms'] / 1000:.2f} сек",
            "",
            "🔴 КРИТИЧЕСКИЕ ПРОБЛЕМЫ:",
        ]

        if analysis["critical_issues"]:
            for issue in analysis["critical_issues"]:
                lines.append(f"  - [{issue['type']}] {issue['recommendation']}")
        else:
            lines.append("  ✅ Критических проблем не обнаружено")

        lines.append("")
        lines.append("🟡 РЕКОМЕНДАЦИИ:")

        if analysis["recommendations"]:
            for rec in analysis["recommendations"]:
                lines.append(f"  - {rec['recommendation']}")
        else:
            lines.append("  ✅ Рекомендаций нет")

        lines.append("")
        lines.append("🏆 ТОП-5 УЗКИХ МЕСТ:")
        for i, bn in enumerate(analysis["bottlenecks"][:5], 1):
            lines.append(
                f"  {i}. {bn['operation']}: "
                f"всего {bn['total_time_ms'] / 1000:.2f} сек, "
                f"среднее {bn['avg_time_ms']:.0f} мс"
            )

        return "\n".join(lines)


# ============================================================================
# 🆕 v101.0: ГЛАВНЫЙ МЕНЕДЖЕР ПРОИЗВОДИТЕЛЬНОСТИ
# ============================================================================
class PerformanceManager:
    """
    🆕 v101.0: Центральный менеджер производительности.

    Объединяет:
    - Мониторинг памяти
    - Профилировщик
    - Rate limiter для Google Sheets
    - Оптимизатор памяти
    - Детектор узких мест
    - Автоматическую настройку под объёмы SKU
    """

    def __init__(self):
        self.start_time = time.time()
        self.operation_count = 0

        # Компоненты
        self.profiler = ExecutionProfiler(
            enabled=PERFORMANCE_CONFIG["profiler"]["enabled"],
            slow_threshold_ms=PERFORMANCE_CONFIG["profiler"]["slow_operation_threshold_ms"],
            keep_last_n=PERFORMANCE_CONFIG["profiler"]["keep_last_n_operations"],
        )

        self.memory_optimizer = MemoryOptimizer(
            warning_threshold_mb=PERFORMANCE_CONFIG["memory_thresholds_mb"]["warning"],
            critical_threshold_mb=PERFORMANCE_CONFIG["memory_thresholds_mb"]["critical"],
            emergency_threshold_mb=PERFORMANCE_CONFIG["memory_thresholds_mb"]["emergency"],
        )

        self.google_sheets_limiter = GoogleSheetsRateLimiter(
            max_per_100_sec=PERFORMANCE_CONFIG["google_sheets_rate_limit"]["max_requests_per_100_seconds"],
            max_per_minute=PERFORMANCE_CONFIG["google_sheets_rate_limit"]["max_requests_per_minute"],
            max_writes_per_minute=PERFORMANCE_CONFIG["google_sheets_rate_limit"]["max_write_operations_per_minute"],
        )

        self.bottleneck_detector = BottleneckDetector(self.profiler)

        # Текущий профиль
        self._current_profile = "medium"
        self._last_gc_time = time.time()
        self._last_memory_check = time.time()

        # Автооптимизация
        self._auto_optimize_enabled = True

        logger.info("🚀 PerformanceManager v101.0 инициализирован")

    # ========================================================================
    # АВТОМАТИЧЕСКАЯ ОПТИМИЗАЦИЯ ПОД ОБЪЁМЫ SKU
    # ========================================================================
    def get_profile_for_sku_count(self, sku_count: int) -> Dict[str, Any]:
        """
        🆕 v101.0: Получение оптимального профиля под количество SKU.
        """
        if sku_count < 1000:
            profile_name = "small"
        elif sku_count < 10000:
            profile_name = "medium"
        elif sku_count < 100000:
            profile_name = "large"
        else:
            profile_name = "xlarge"

        profile = PERFORMANCE_CONFIG["sku_profiles"][profile_name].copy()
        profile["profile_name"] = profile_name
        profile["sku_count"] = sku_count

        # Адаптация под доступную память
        if PSUTIL_AVAILABLE:
            try:
                available_mb = psutil.virtual_memory().available / (1024 * 1024)
                if available_mb < 2048:
                    # Мало памяти — уменьшаем параллелизм
                    profile["max_workers"] = max(1, profile["max_workers"] // 2)
                    profile["polars_threads"] = max(1, profile["polars_threads"] // 2)
                    profile["duckdb_threads"] = max(1, profile["duckdb_threads"] // 2)
                    profile["warning"] = "Мало памяти — параллелизм снижен"
            except Exception:
                pass

        self._current_profile = profile_name
        return profile

    def apply_profile(self, profile: Dict[str, Any]):
        """Применение профиля к системам"""
        # Polars threads
        if POLARS_AVAILABLE:
            os.environ['POLARS_MAX_THREADS'] = str(profile.get("polars_threads", 4))
            os.environ['POLARS_VERBOSE'] = '0'

        # DuckDB threads
        if DUCKDB_AVAILABLE:
            os.environ['DUCKDB_THREADS'] = str(profile.get("duckdb_threads", 4))

        logger.info(
            f"🎯 Применён профиль '{profile.get('profile_name', 'unknown')}' "
            f"для {profile.get('sku_count', 0)} SKU"
        )

    # ========================================================================
    # ПРОВЕРКА ПАМЯТИ
    # ========================================================================
    def check_memory_usage(self) -> Dict[str, Any]:
        """Проверка использования памяти"""
        self.operation_count += 1

        result = {
            "memory_mb": 0.0,
            "system_percent": 0.0,
            "action": None,
        }

        if not PSUTIL_AVAILABLE:
            return result

        try:
            process = psutil.Process(os.getpid())
            mem_info = process.memory_info()
            mem_mb = mem_info.rss / (1024 * 1024)
            result["memory_mb"] = mem_mb
            result["system_percent"] = psutil.virtual_memory().percent

            # Автоматическая оптимизация
            if self._auto_optimize_enabled:
                now = time.time()

                # Проверка по счётчику операций
                if self.operation_count % PERFORMANCE_CONFIG["gc_thresholds"]["operation_count"] == 0:
                    opt_result = self.memory_optimizer.check_and_optimize()
                    result["action"] = opt_result.get("action_taken")

                # Проверка по времени
                elif now - self._last_gc_time > PERFORMANCE_CONFIG["gc_thresholds"]["time_interval_seconds"]:
                    opt_result = self.memory_optimizer.check_and_optimize()
                    result["action"] = opt_result.get("action_taken")
                    self._last_gc_time = now

            self._last_memory_check = time.time()

        except (psutil.Error, OSError) as e:
            logger.error(f"Ошибка проверки памяти: {e}")

        return result

    # ========================================================================
    # СИСТЕМНАЯ СТАТИСТИКА
    # ========================================================================
    def get_system_stats(self) -> Dict[str, Any]:
        """Полная системная статистика"""
        stats = {
            "uptime_seconds": time.time() - self.start_time,
            "operation_count": self.operation_count,
            "current_profile": self._current_profile,
            "profiler": {
                "enabled": self.profiler.enabled,
                "operations_tracked": len(self.profiler._operations),
            },
            "google_sheets_limiter": self.google_sheets_limiter.get_stats(),
            "memory_optimizer": self.memory_optimizer.get_stats(),
        }

        if PSUTIL_AVAILABLE:
            try:
                stats.update({
                    "cpu_percent": psutil.cpu_percent(interval=0.1),
                    "memory_percent": psutil.virtual_memory().percent,
                    "memory_available_mb": psutil.virtual_memory().available / (1024 * 1024),
                    "disk_usage_percent": psutil.disk_usage('/').percent,
                })
                process = psutil.Process(os.getpid())
                mem_info = process.memory_info()
                stats["process_memory_mb"] = mem_info.rss / (1024 * 1024)
                stats["process_cpu_percent"] = process.cpu_percent()
            except (psutil.Error, OSError):
                pass

        return stats

    # ========================================================================
    # ЭКСПОРТ ОТЧЁТОВ
    # ========================================================================
    def export_performance_report(self, output_path: str) -> bool:
        """Экспорт полного отчёта о производительности"""
        try:
            report = {
                "generated_at": datetime.now().isoformat(),
                "system_stats": self.get_system_stats(),
                "operation_stats": self.profiler.get_stats(),
                "bottlenecks": self.bottleneck_detector.analyze(),
                "memory_stats": self.memory_optimizer.get_stats(),
                "google_sheets_stats": self.google_sheets_limiter.get_stats(),
            }

            with open(output_path, 'w', encoding='utf-8') as f:
                json.dump(report, f, ensure_ascii=False, indent=2)

            logger.info(f"📊 Отчёт о производительности сохранён: {output_path}")
            return True

        except Exception as e:
            logger.error(f"Ошибка экспорта отчёта: {e}")
            return False

    def print_performance_summary(self):
        """Вывод краткой сводки в лог"""
        stats = self.get_system_stats()
        bottlenecks = self.profiler.get_bottlenecks(top_n=3)

        logger.info("=" * 60)
        logger.info("📊 СВОДКА ПРОИЗВОДИТЕЛЬНОСТИ")
        logger.info("=" * 60)
        logger.info(f"⏱️ Uptime: {stats['uptime_seconds']:.0f} сек")
        logger.info(f"🔢 Операций: {stats['operation_count']:,}")
        logger.info(f"🎯 Профиль: {stats['current_profile']}")

        if 'process_memory_mb' in stats:
            logger.info(f"💾 Память: {stats['process_memory_mb']:.0f} MB")

        if bottlenecks:
            logger.info("🏆 Топ-3 узких места:")
            for i, bn in enumerate(bottlenecks, 1):
                logger.info(
                    f"  {i}. {bn['operation']}: "
                    f"{bn['total_time_ms'] / 1000:.2f} сек всего"
                )

        logger.info("=" * 60)

    # ========================================================================
    # УПРАВЛЕНИЕ
    # ========================================================================
    def enable_auto_optimize(self, enabled: bool = True):
        """Включение/выключение автоматической оптимизации"""
        self._auto_optimize_enabled = enabled
        logger.info(f"{'✅' if enabled else '❌'} Автооптимизация: {'включена' if enabled else 'выключена'}")

    def force_gc(self):
        """Принудительный запуск GC"""
        return self.memory_optimizer.check_and_optimize(force=True)

    def reset_all_stats(self):
        """Сброс всей статистики"""
        self.profiler.reset()
        self.google_sheets_limiter.reset()
        self.operation_count = 0
        self.start_time = time.time()
        logger.info("🔄 Вся статистика сброшена")

    def close(self):
        """Закрытие менеджера"""
        self.print_performance_summary()


