# 🆕 v101.0: ГЛОБАЛЬНЫЙ МЕНЕДЖЕР (singleton)
# ============================================================================
_performance_manager_instance = None
_perf_manager_lock = threading.Lock()


def get_performance_manager() -> PerformanceManager:
    """
    🆕 v101.0: Получение глобального экземпляра PerformanceManager.
    Thread-safe singleton.
    """
    global _performance_manager_instance
    if _performance_manager_instance is None:
        with _perf_manager_lock:
            if _performance_manager_instance is None:
                _performance_manager_instance = PerformanceManager()
    return _performance_manager_instance


