# 🆕 v101.0: УТИЛИТА ДЛЯ АВТОМАТИЧЕСКОЙ ОПТИМИЗАЦИИ ПОД SKU
# ============================================================================
def optimize_for_sku_count(sku_count: int) -> Dict[str, Any]:
    """
    🆕 v101.0: Автоматическая оптимизация под количество SKU.

    Usage:
        profile = optimize_for_sku_count(300_000)
        # profile = {"max_workers": 12, "chunk_size": 10000, ...}
    """
    manager = get_performance_manager()
    profile = manager.get_profile_for_sku_count(sku_count)
    manager.apply_profile(profile)
    return profile


