# 🆕 v101.0: КОНТЕКСТНЫЙ МЕНЕДЖЕР ДЛЯ RATE LIMITING
# ============================================================================
@contextmanager
def google_sheets_rate_limit(is_write: bool = False):
    """
    🆕 v101.0: Контекстный менеджер для rate limiting Google Sheets.

    Usage:
        with google_sheets_rate_limit(is_write=True):
            sheets_api.write(...)
    """
    limiter = get_google_sheets_rate_limiter()
    with limiter.rate_limit(is_write=is_write):
        yield


