# ============================================================================
# 🆕 v101.0: ДАТАКЛАСС ДЛЯ РЕЗУЛЬТАТА API-ЗАПРОСА
# ============================================================================
@dataclass
class APIResponse:
    """Результат API-запроса с метаданными"""
    success: bool = False
    data: Optional[Dict[str, Any]] = None
    error: Optional[str] = None
    status_code: Optional[int] = None
    latency_ms: float = 0.0
    from_cache: bool = False
    timestamp: datetime = field(default_factory=datetime.now)
    marketplace: str = ""
    endpoint: str = ""
    request_id: str = field(default_factory=lambda: hashlib.md5(
        str(time.time()).encode()
    ).hexdigest()[:12])

    def to_dict(self) -> Dict[str, Any]:
        return {
            "success": self.success,
            "data": self.data,
            "error": self.error,
            "status_code": self.status_code,
            "latency_ms": self.latency_ms,
            "from_cache": self.from_cache,
            "timestamp": self.timestamp.isoformat(),
            "marketplace": self.marketplace,
            "endpoint": self.endpoint,
            "request_id": self.request_id,
        }


# ============================================================================
# 🆕 v101.0: КЭШ API ОТВЕТОВ
# ============================================================================
class APICache:
    """
    🆕 v101.0: Кэш API ответов с TTL и лимитом размера.
    """

    def __init__(self, cache_dir: Optional[Path] = None,
                 ttl_seconds: int = 3600,
                 max_size: int = 1000):
        self.cache_dir = cache_dir or Path(API_CONNECTOR_CONFIG["cache_dir"])
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.ttl_seconds = ttl_seconds
        self.max_size = max_size
        self._memory_cache = {}
        self._access_times = {}
        self.stats = {
            "hits": 0,
            "misses": 0,
            "writes": 0,
            "evictions": 0,
        }

    def _make_key(self, marketplace: str, endpoint: str, params: Dict) -> str:
        """Создание уникального ключа кэша"""
        params_str = json.dumps(params, sort_keys=True)
        raw_key = f"{marketplace}|{endpoint}|{params_str}"
        return hashlib.md5(raw_key.encode()).hexdigest()

    def get(self, marketplace: str, endpoint: str,
            params: Optional[Dict] = None) -> Optional[Dict]:
        """Получение данных из кэша"""
        params = params or {}
        key = self._make_key(marketplace, endpoint, params)

        # Проверяем memory cache
        if key in self._memory_cache:
            entry = self._memory_cache[key]
            if time.time() - entry["timestamp"] < self.ttl_seconds:
                self.stats["hits"] += 1
                self._access_times[key] = time.time()
                return entry["data"]
            else:
                # Удаляем устаревшее
                del self._memory_cache[key]

        # Проверяем файл
        cache_file = self.cache_dir / f"{key}.json"
        if cache_file.exists():
            try:
                with open(cache_file, 'r', encoding='utf-8') as f:
                    entry = json.load(f)
                if time.time() - entry.get("timestamp", 0) < self.ttl_seconds:
                    self.stats["hits"] += 1
                    self._memory_cache[key] = entry
                    self._access_times[key] = time.time()
                    return entry["data"]
                else:
                    cache_file.unlink()
            except Exception as e:
                logger.warning(f"Ошибка чтения кэша: {e}")

        self.stats["misses"] += 1
        return None

    def set(self, marketplace: str, endpoint: str,
            data: Dict, params: Optional[Dict] = None):
        """Сохранение данных в кэш"""
        params = params or {}
        key = self._make_key(marketplace, endpoint, params)

        entry = {
            "data": data,
            "timestamp": time.time(),
            "marketplace": marketplace,
            "endpoint": endpoint,
        }

        # Memory cache
        if len(self._memory_cache) >= self.max_size:
            # Удаляем самый старый
            oldest_key = min(self._access_times, key=self._access_times.get)
            del self._memory_cache[oldest_key]
            self.stats["evictions"] += 1

        self._memory_cache[key] = entry
        self._access_times[key] = time.time()

        # File cache
        try:
            cache_file = self.cache_dir / f"{key}.json"
            with open(cache_file, 'w', encoding='utf-8') as f:
                json.dump(entry, f, ensure_ascii=False, indent=2)
            self.stats["writes"] += 1
        except Exception as e:
            logger.warning(f"Ошибка записи в кэш: {e}")

    def clear(self, marketplace: Optional[str] = None):
        """Очистка кэша"""
        if marketplace:
            keys_to_delete = [
                k for k, v in self._memory_cache.items()
                if v.get("marketplace") == marketplace
            ]
            for key in keys_to_delete:
                del self._memory_cache[key]
                self._access_times.pop(key, None)
                cache_file = self.cache_dir / f"{key}.json"
                if cache_file.exists():
                    cache_file.unlink()
        else:
            self._memory_cache.clear()
            self._access_times.clear()
            for file in self.cache_dir.glob("*.json"):
                try:
                    file.unlink()
                except Exception:
                    pass

    def get_stats(self) -> Dict[str, Any]:
        """Получение статистики кэша"""
        return {
            **self.stats,
            "memory_cache_size": len(self._memory_cache),
            "ttl_seconds": self.ttl_seconds,
            "max_size": self.max_size,
        }


# ============================================================================
# 🆕 v101.0: ГЛАВНЫЙ КЛАСС API КОННЕКТОРА
# ============================================================================
class MarketplaceAPIConnector:
    """
    🆕 v101.0: Расширенный API коннектор для всех маркетплейсов.

    Поддерживает:
    ✅ Яндекс Маркет (приоритет)
    ✅ Ozon Seller API
    ✅ Wildberries API
    ✅ AliExpress API
    ✅ Мегамаркет API
    ✅ Rate limiting
    ✅ Кэширование
    ✅ Retry с backoff
    ✅ Профилирование
    """

    # 🆕 v101.0: Эндпоинты API
    ENDPOINTS = {
        "Яндекс Маркет": {
            "base_url": "https://api.partner.market.yandex.ru",
            "campaigns": "/v2/campaigns",
            "tariffs": "/v2/campaigns/{campaign_id}/deliveries/fees",
            "stocks": "/v2/campaigns/{campaign_id}/offers/stocks",
            "orders": "/v2/campaigns/{campaign_id}/orders",
            "products": "/v2/campaigns/{campaign_id}/products",
        },
        "Ozon": {
            "base_url": "https://api-seller.ozon.ru",
            "tariffs": "/v1/finance/tariff-rates",
            "stocks": "/v2/products/info/stocks",
            "orders": "/v2/posting/fbs/list",
            "products": "/v2/product/list",
            "prices": "/v1/pricing/import",
        },
        "Wildberries": {
            "base_url": "https://common-api.wildberries.ru",
            "tariffs": "/tariffs/box",
            "warehouses": "/api/v1/warehouses",
            "stocks": "/api/v1/stocks",
            "orders": "/api/v1/supplier/reportDetailByPeriod",
        },
        "AliExpress": {
            "base_url": "https://api.aliexpress.ru",
            "products": "/api/v1/products",
            "orders": "/api/v1/orders",
        },
        "Мегамаркет": {
            "base_url": "https://api.megamarket.ru",
            "products": "/api/v1/products",
            "orders": "/api/v1/orders",
        },
    }

    def __init__(self, enable_caching: bool = True,
                 enable_rate_limiting: bool = True,
                 enable_profiling: bool = True):
        """
        Инициализация API коннектора.

        Args:
            enable_caching: Включить кэширование
            enable_rate_limiting: Включить rate limiting
            enable_profiling: Включить профилирование
        """
        self.session = self._create_session()
        self.logger = logging.getLogger('MarketplaceAPI')

        # Кэш
        self.enable_caching = enable_caching
        self.cache = APICache(
            ttl_seconds=API_CONNECTOR_CONFIG["cache_ttl_seconds"],
            max_size=API_CONNECTOR_CONFIG["cache_max_size"],
        ) if enable_caching else None

        # Rate limiting
        self.enable_rate_limiting = enable_rate_limiting
        if enable_rate_limiting and PERF_MANAGER_AVAILABLE:
            try:
                self.rate_limiter = get_google_sheets_rate_limiter()
            except Exception:
                self.rate_limiter = None
        else:
            self.rate_limiter = None

        # Профилирование
        self.enable_profiling = enable_profiling

        # Метрики
        self.metrics = {
            "total_requests": 0,
            "successful_requests": 0,
            "failed_requests": 0,
            "cached_requests": 0,
            "total_latency_ms": 0.0,
            "by_marketplace": defaultdict(int),
            "by_endpoint": defaultdict(int),
            "last_error": None,
            "last_request_time": None,
        }

        self.logger.info("🔌 MarketplaceAPIConnector v101.0 инициализирован")
        self.logger.info(f"   Кэширование: {'✅' if enable_caching else '❌'}")
        self.logger.info(f"   Rate limiting: {'✅' if enable_rate_limiting else '❌'}")
        self.logger.info(f"   Профилирование: {'✅' if enable_profiling else '❌'}")

    def _create_session(self) -> requests.Session:
        """Создание HTTP сессии с retry"""
        session = requests.Session()

        # Retry strategy
        retry_strategy = Retry(
            total=API_CONNECTOR_CONFIG["max_retries"],
            backoff_factor=API_CONNECTOR_CONFIG["retry_backoff_factor"],
            status_forcelist=API_CONNECTOR_CONFIG["retry_statuses"],
            allowed_methods=["HEAD", "GET", "POST", "PUT", "DELETE"],
        )

        adapter = HTTPAdapter(max_retries=retry_strategy)
        session.mount("http://", adapter)
        session.mount("https://", adapter)

        # Headers
        session.headers.update({
            "Content-Type": "application/json",
            "User-Agent": "AutoPartsUnitEconomicsPro/101.0",
            "Accept": "application/json",
        })

        return session

    # ========================================================================
    # 🆕 v101.0: ОСНОВНОЙ МЕТОД ВЫПОЛНЕНИЯ ЗАПРОСА
    # ========================================================================
    def _make_request(self, marketplace: str, endpoint: str,
                      method: str = "GET",
                      params: Optional[Dict] = None,
                      json_data: Optional[Dict] = None,
                      headers: Optional[Dict] = None,
                      use_cache: bool = True,
                      timeout: Optional[int] = None) -> APIResponse:
        """
        🆕 v101.0: Основной метод выполнения API-запроса.

        Args:
            marketplace: Название МП
            endpoint: URL эндпоинта
            method: HTTP метод
            params: Query параметры
            json_data: JSON body
            headers: Дополнительные headers
            use_cache: Использовать кэш
            timeout: Таймаут в секундах

        Returns:
            APIResponse с результатом
        """
        self.metrics["total_requests"] += 1
        self.metrics["by_marketplace"][marketplace] += 1
        self.metrics["by_endpoint"][endpoint] += 1

        start_time = time.perf_counter()

        response = APIResponse(
            marketplace=marketplace,
            endpoint=endpoint,
        )

        try:
            # 1. Проверяем кэш
            if use_cache and self.enable_caching and method == "GET" and self.cache:
                cached_data = self.cache.get(marketplace, endpoint, params)
                if cached_data:
                    response.success = True
                    response.data = cached_data
                    response.from_cache = True
                    response.latency_ms = (time.perf_counter() - start_time) * 1000
                    self.metrics["cached_requests"] += 1
                    self.logger.info(
                        f"💾 Кэш: {marketplace} {endpoint} "
                        f"({response.latency_ms:.0f} мс)"
                    )
                    return response

            # 2. Rate limiting
            if self.enable_rate_limiting and self.rate_limiter:
                try:
                    self.rate_limiter.acquire(is_write=(method != "GET"))
                except Exception as e:
                    self.logger.warning(f"Rate limit error: {e}")

            # 3. Выполняем запрос
            timeout = timeout or API_CONNECTOR_CONFIG["default_timeout"]

            if method == "GET":
                http_response = self.session.get(
                    endpoint,
                    params=params,
                    headers=headers,
                    timeout=timeout,
                )
            elif method == "POST":
                http_response = self.session.post(
                    endpoint,
                    json=json_data,
                    params=params,
                    headers=headers,
                    timeout=timeout,
                )
            else:
                response.error = f"Метод {method} не поддерживается"
                return response

            response.status_code = http_response.status_code

            # 4. Обработка ответа
            if http_response.status_code == 200:
                response.success = True
                try:
                    response.data = http_response.json()
                except Exception as e:
                    response.data = {"raw": http_response.text}
                    self.logger.warning(f"Ошибка парсинга JSON: {e}")

                # Сохраняем в кэш
                if use_cache and self.enable_caching and method == "GET" and self.cache:
                    self.cache.set(marketplace, endpoint, response.data, params)

                self.metrics["successful_requests"] += 1

            elif http_response.status_code == 429:
                response.error = "Превышен лимит запросов (429)"
                self.metrics["failed_requests"] += 1
                self.logger.warning(f"Rate limit exceeded: {marketplace} {endpoint}")

            elif http_response.status_code >= 400:
                response.error = f"HTTP {http_response.status_code}: {http_response.text[:200]}"
                self.metrics["failed_requests"] += 1
                self.metrics["last_error"] = response.error
                self.logger.error(f"API error: {marketplace} {endpoint} - {response.error}")

            else:
                response.error = f"Неожиданный статус: {http_response.status_code}"
                self.metrics["failed_requests"] += 1

        except requests.exceptions.Timeout:
            response.error = "Таймаут запроса"
            self.metrics["failed_requests"] += 1
            self.logger.error(f"Timeout: {marketplace} {endpoint}")

        except requests.exceptions.ConnectionError as e:
            response.error = f"Ошибка соединения: {str(e)[:100]}"
            self.metrics["failed_requests"] += 1
            self.logger.error(f"Connection error: {marketplace} {endpoint}")

        except Exception as e:
            response.error = f"Неожиданная ошибка: {str(e)}"
            self.metrics["failed_requests"] += 1
            self.logger.error(f"Unexpected error: {marketplace} {endpoint} - {e}")
            self.logger.error(traceback.format_exc())

        finally:
            response.latency_ms = (time.perf_counter() - start_time) * 1000
            self.metrics["total_latency_ms"] += response.latency_ms
            self.metrics["last_request_time"] = datetime.now()

        return response

