    # ========================================================================
    # 🆕 v101.0: УНИВЕРСАЛЬНЫЕ МЕТОДЫ
    # ========================================================================
    def get_tariffs(self, marketplace: str,
                    api_key: str,
                    client_id: Optional[str] = None,
                    oauth_token: Optional[str] = None,
                    campaign_id: Optional[int] = None) -> APIResponse:
        """
        🆕 v101.0: Универсальный метод получения тарифов для любого МП.

        Args:
            marketplace: Название МП
            api_key: API ключ
            client_id: Client ID (для Ozon)
            oauth_token: OAuth токен (для Яндекс Маркет)
            campaign_id: ID кампании (для Яндекс Маркет)

        Returns:
            APIResponse с тарифами
        """
        if marketplace == "Яндекс Маркет":
            if not oauth_token or not campaign_id:
                return APIResponse(
                    success=False,
                    error="Для Яндекс Маркет нужны oauth_token и campaign_id",
                    marketplace=marketplace,
                )
            return self.get_yandex_market_tariffs(oauth_token, campaign_id)

        elif marketplace == "Ozon":
            if not api_key or not client_id:
                return APIResponse(
                    success=False,
                    error="Для Ozon нужны api_key и client_id",
                    marketplace=marketplace,
                )
            return self.get_ozon_tariffs(api_key, client_id)

        elif marketplace == "Wildberries":
            if not api_key:
                return APIResponse(
                    success=False,
                    error="Для Wildberries нужен api_key",
                    marketplace=marketplace,
                )
            return self.get_wildberries_tariffs(api_key)

        else:
            return APIResponse(
                success=False,
                error=f"API для {marketplace} не поддерживается",
                marketplace=marketplace,
            )

    def validate_api_key(self, marketplace: str,
                         api_key: str,
                         client_id: Optional[str] = None,
                         oauth_token: Optional[str] = None,
                         campaign_id: Optional[int] = None) -> Dict[str, Any]:
        """
        🆕 v101.0: Проверка валидности API ключа.

        Returns:
            Dict с результатами проверки
        """
        result = {
            "valid": False,
            "marketplace": marketplace,
            "error": None,
            "details": {},
        }

        try:
            response = self.get_tariffs(
                marketplace=marketplace,
                api_key=api_key,
                client_id=client_id,
                oauth_token=oauth_token,
                campaign_id=campaign_id,
            )

            if response.success:
                result["valid"] = True
                result["details"] = {
                    "latency_ms": response.latency_ms,
                    "from_cache": response.from_cache,
                }
            else:
                result["error"] = response.error

        except Exception as e:
            result["error"] = str(e)

        return result

    # ========================================================================
    # 🆕 v101.0: BATCH-ЗАПРОСЫ
    # ========================================================================
    def batch_get_tariffs(self, marketplaces: List[str],
                          credentials: Dict[str, Dict]) -> Dict[str, APIResponse]:
        """
        🆕 v101.0: Массовое получение тарифов для нескольких МП.

        Args:
            marketplaces: Список МП
            credentials: Dict с credentials для каждого МП
                         {"Ozon": {"api_key": "...", "client_id": "..."}, ...}

        Returns:
            Dict {marketplace: APIResponse}
        """
        results = {}

        for mp in marketplaces:
            creds = credentials.get(mp, {})
            response = self.get_tariffs(
                marketplace=mp,
                api_key=creds.get("api_key", ""),
                client_id=creds.get("client_id"),
                oauth_token=creds.get("oauth_token"),
                campaign_id=creds.get("campaign_id"),
            )
            results[mp] = response

            # Задержка между запросами
            if API_CONNECTOR_CONFIG["batch_delay_ms"] > 0:
                time.sleep(API_CONNECTOR_CONFIG["batch_delay_ms"] / 1000)

        return results

    # ========================================================================
    # 🆕 v101.0: УПРАВЛЕНИЕ КЭШЕМ
    # ========================================================================
    def clear_cache(self, marketplace: Optional[str] = None):
        """Очистка кэша"""
        if self.cache:
            self.cache.clear(marketplace)
            self.logger.info(
                f"🗑️ Кэш очищен"
                f"{f' для {marketplace}' if marketplace else ''}"
            )

    def get_cache_stats(self) -> Dict[str, Any]:
        """Получение статистики кэша"""
        if self.cache:
            return self.cache.get_stats()
        return {"error": "Кэш отключён"}

    # ========================================================================
    # 🆕 v101.0: МЕТРИКИ
    # ========================================================================
    def get_metrics(self) -> Dict[str, Any]:
        """Получение метрик API"""
        metrics = self.metrics.copy()

        # Добавляем средние значения
        if metrics["successful_requests"] > 0:
            metrics["avg_latency_ms"] = (
                metrics["total_latency_ms"] / metrics["successful_requests"]
            )
        else:
            metrics["avg_latency_ms"] = 0.0

        if metrics["total_requests"] > 0:
            metrics["success_rate"] = (
                metrics["successful_requests"] / metrics["total_requests"]
            )
        else:
            metrics["success_rate"] = 0.0

        # Кэш
        if self.cache:
            metrics["cache_stats"] = self.cache.get_stats()

        return metrics

    def reset_metrics(self):
        """Сброс метрик"""
        self.metrics = {
            "total_requests": 0,
            "successful_requests": 0,
            "failed_requests": 0,
            "cached_requests": 0,
            "total_latency_ms": 0.0,
            "by_marketplace": defaultdict(int),
            "by_endpoint": defaultdict(int),
            "last_error": None,
            "last_request_time": None,
        }

    def print_metrics_summary(self):
        """Вывод сводки метрик в лог"""
        metrics = self.get_metrics()

        self.logger.info("=" * 60)
        self.logger.info("📊 API МЕТРИКИ")
        self.logger.info("=" * 60)
        self.logger.info(f"🔢 Всего запросов: {metrics['total_requests']}")
        self.logger.info(f"✅ Успешных: {metrics['successful_requests']}")
        self.logger.info(f"❌ Ошибок: {metrics['failed_requests']}")
        self.logger.info(f"💾 Из кэша: {metrics['cached_requests']}")
        self.logger.info(f"📈 Success rate: {metrics['success_rate']:.1%}")
        self.logger.info(f"⏱️ Avg latency: {metrics['avg_latency_ms']:.0f} мс")

        if metrics['by_marketplace']:
            self.logger.info("🏪 По маркетплейсам:")
            for mp, count in metrics['by_marketplace'].items():
                self.logger.info(f"   - {mp}: {count}")

        self.logger.info("=" * 60)

    # ========================================================================
    # 🆕 v101.0: ЗАКРЫТИЕ
    # ========================================================================
    def close(self):
        """Закрытие сессии"""
        if self.session:
            self.session.close()
        self.print_metrics_summary()
        self.logger.info("🔌 API коннектор закрыт")


