    def calculate_for_catalog_batch(self, *args, **kwargs):
        """Расчет юнит-экономики для каталога с выбором режима."""
        df = kwargs.get('df')
        use_parallel = kwargs.get('use_parallel', True)

        if use_parallel and len(df) > 100 and DUCKDB_AVAILABLE:
            return self.calculate_for_catalog_batch_parallel(*args, **kwargs)

        # Fallback на последовательный расчёт
        # ... (код из оригинала)
        return pd.DataFrame()

    def calculate_for_all_marketplaces(self, *args, **kwargs) -> pd.DataFrame:
        results = []
        for marketplace in self._configs.keys():
            try:
                result = self.calculate_unit_economics(
                    marketplace=marketplace,
                    *args, **kwargs
                )
                results.append(result)
            except Exception as e:
                self._logger.error(f"Ошибка расчета для {marketplace}: {e}")
                self._stats["errors_count"] += 1
                self._stats["last_error"] = str(e)

        if not results:
            return pd.DataFrame()

        return pd.DataFrame([r.to_dict() for r in results])

