# 🆕 v101.0: ОСНОВНОЙ КЛАСС HIGH-VOLUME КАТАЛОГА
# ============================================================================
class HighVolumeAutoPartsCatalog:
    """
    🆕 v101.0: High-Volume каталог автозапчастей с поддержкой 10M+ записей.

    Новые возможности:
    ✅ Поле product_origin в таблице parts
    ✅ ABC/XYZ-анализ каталога
    ✅ Экспорт в Google Sheets
    ✅ Приоритет Яндекс Маркет
    ✅ Сезонность спроса
    ✅ Безубыточность в штуках
    """

    def __init__(self):
        self.data_dir = Path("./auto_parts_data")
        self.data_dir.mkdir(exist_ok=True)
        self.cloud_config = self.load_cloud_config()
        self.price_rules = self.load_price_rules()
        self.exclusion_rules = self.load_exclusion_rules()
        self.category_mapping = self.load_category_mapping()
        self.db_path = self.data_dir / "catalog.duckdb"
        self.conn = duckdb.connect(database=str(self.db_path))

        # 🆕 v101.0: Статистика ABC/XYZ-анализа
        self._abc_stats = None
        self._last_abc_analysis = None

        if not self._tables_exist():
            self.setup_database()
        else:
            self.create_indexes()
            # 🆕 v101.0: Миграция БД для добавления product_origin
            self._migrate_database()

        logger.info("🚀 HighVolumeAutoPartsCatalog v101.0 инициализирован")

    # ========================================================================
    # 🆕 v101.0: ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
    # ========================================================================
    @contextmanager
    def timer(self, operation_name: str):
        start = time.perf_counter()
        try:
            yield
        finally:
            duration = time.perf_counter() - start
            logger.info(f"⏱️ {operation_name} заняло {duration:.2f} сек")

    @contextmanager
    def db_transaction(self):
        try:
            self.conn.execute("BEGIN TRANSACTION")
            yield
            self.conn.execute("COMMIT")
        except Exception as e:
            try:
                self.conn.execute("ROLLBACK")
            except Exception:
                pass
            logger.error(f"Транзакция отменена: {e}")
            raise

    def _tables_exist(self) -> bool:
        try:
            tables = self.conn.execute(
                "SELECT table_name FROM information_schema.tables WHERE table_schema='main'"
            ).fetchall()
            existing_tables = {t[0] for t in tables}
            required_tables = {'oe', 'parts', 'cross_references', 'prices', 'metadata'}
            return required_tables.issubset(existing_tables)
        except Exception:
            return False

    # ========================================================================
    # 🆕 v101.0: КОНФИГУРАЦИИ
    # ========================================================================
    def load_cloud_config(self) -> Dict[str, Any]:
        config_path = self.data_dir / "cloud_config.json"
        default_config = {
            "enabled": False, "provider": "s3",
            "bucket": "", "region": "",
            "sync_interval": 3600, "last_sync": 0
        }
        if config_path.exists():
            try:
                return json.loads(config_path.read_text(encoding='utf-8'))
            except Exception as e:
                logger.error(f"Ошибка чтения cloud_config.json: {e}")
                return default_config
        else:
            config_path.write_text(json.dumps(
                default_config, indent=2, ensure_ascii=False), encoding='utf-8')
            return default_config

    def save_cloud_config(self):
        config_path = self.data_dir / "cloud_config.json"
        self.cloud_config["last_sync"] = int(time.time())
        config_path.write_text(json.dumps(
            self.cloud_config, indent=2, ensure_ascii=False), encoding='utf-8')

    def load_price_rules(self) -> Dict[str, Any]:
        price_rules_path = self.data_dir / "price_rules.json"
        default_rules = {
            "global_markup": 0.2, "brand_markups": {},
            "min_price": 0.0, "max_price": 99999.0
        }
        if price_rules_path.exists():
            try:
                return json.loads(price_rules_path.read_text(encoding='utf-8'))
            except Exception as e:
                logger.error(f"Ошибка чтения price_rules.json: {e}")
                return default_rules
        else:
            price_rules_path.write_text(json.dumps(
                default_rules, indent=2, ensure_ascii=False), encoding='utf-8')
            return default_rules

    def save_price_rules(self):
        price_rules_path = self.data_dir / "price_rules.json"
        price_rules_path.write_text(json.dumps(
            self.price_rules, indent=2, ensure_ascii=False), encoding='utf-8')

    def load_exclusion_rules(self) -> List[str]:
        exclusion_path = self.data_dir / "exclusion_rules.txt"
        if exclusion_path.exists():
            try:
                return [line.strip() for line in exclusion_path.read_text(encoding='utf-8').splitlines() if line.strip()]
            except Exception as e:
                logger.error(f"Ошибка чтения exclusion_rules.txt: {e}")
                return []
        else:
            content = "Кузов\nСтекла\nМасла"
            exclusion_path.write_text(content, encoding='utf-8')
            return ["Кузов", "Стекла", "Масла"]

    def save_exclusion_rules(self):
        exclusion_path = self.data_dir / "exclusion_rules.txt"
        exclusion_path.write_text("\n".join(self.exclusion_rules), encoding='utf-8')

    def load_category_mapping(self) -> Dict[str, str]:
        category_path = self.data_dir / "category_mapping.txt"
        default_mapping = {
            "Радиатор": "Охлаждение", "Шаровая опора": "Подвеска",
            "Фильтр масляный": "Фильтры", "Тормозные колодки": "Тормоза"
        }
        if category_path.exists():
            try:
                mapping = {}
                for line in category_path.read_text(encoding='utf-8').splitlines():
                    if line.strip() and "|" in line:
                        parts = line.split("|", 1)
                        if len(parts) == 2:
                            key, value = parts
                            mapping[key.strip()] = value.strip()
                return mapping
            except Exception as e:
                logger.error(f"Ошибка чтения category_mapping.txt: {e}")
                return default_mapping
        else:
            content = "\n".join([f"{k}|{v}" for k, v in default_mapping.items()])
            category_path.write_text(content, encoding='utf-8')
            return default_mapping

    def save_category_mapping(self):
        category_path = self.data_dir / "category_mapping.txt"
        content = "\n".join([f"{k}|{v}" for k, v in self.category_mapping.items()])
        category_path.write_text(content, encoding='utf-8')

    # ========================================================================
    # 🆕 v101.0: БАЗА ДАННЫХ (С product_origin)
    # ========================================================================
    def setup_database(self):
        """🆕 v101.0: Создание структуры БД с полем product_origin"""
        logger.info("Создание структуры базы данных...")
        with self.timer("Создание таблиц"):
            self.conn.execute("""
                CREATE TABLE IF NOT EXISTS oe (
                    oe_number_norm VARCHAR PRIMARY KEY,
                    oe_number VARCHAR,
                    name VARCHAR,
                    applicability VARCHAR,
                    category VARCHAR,
                    length DOUBLE,
                    width DOUBLE,
                    height DOUBLE,
                    weight DOUBLE,
                    dimensions_str VARCHAR
                )
            """)

            # 🆕 v101.0: Таблица parts с product_origin
            self.conn.execute("""
                CREATE TABLE IF NOT EXISTS parts (
                    artikul_norm VARCHAR,
                    brand_norm VARCHAR,
                    artikul VARCHAR,
                    brand VARCHAR,
                    multiplicity INTEGER,
                    barcode VARCHAR,
                    length DOUBLE,
                    width DOUBLE,
                    height DOUBLE,
                    weight DOUBLE,
                    image_url VARCHAR,
                    dimensions_str VARCHAR,
                    description VARCHAR,
                    billable_weight DOUBLE DEFAULT 0.0,
                    product_origin VARCHAR DEFAULT 'analog_standard',
                    PRIMARY KEY (artikul_norm, brand_norm)
                )
            """)

            self.conn.execute("""
                CREATE TABLE IF NOT EXISTS cross_references (
                    oe_number_norm VARCHAR,
                    artikul_norm VARCHAR,
                    brand_norm VARCHAR,
                    PRIMARY KEY (oe_number_norm, artikul_norm, brand_norm)
                )
            """)

            self.conn.execute("""
                CREATE TABLE IF NOT EXISTS prices (
                    artikul_norm VARCHAR,
                    brand_norm VARCHAR,
                    price DOUBLE,
                    currency VARCHAR DEFAULT 'RUB',
                    PRIMARY KEY (artikul_norm, brand_norm)
                )
            """)

            self.conn.execute("""
                CREATE TABLE IF NOT EXISTS metadata (
                    key VARCHAR PRIMARY KEY,
                    value VARCHAR
                )
            """)

        self.create_indexes()

    def create_indexes(self):
        with self.timer("Создание индексов"):
            indexes = [
                ("idx_oe_number_norm", "CREATE INDEX IF NOT EXISTS idx_oe_number_norm ON oe(oe_number_norm)"),
                ("idx_parts_keys", "CREATE INDEX IF NOT EXISTS idx_parts_keys ON parts(artikul_norm, brand_norm)"),
                # 🆕 v101.0: Индекс по product_origin для ABC/XYZ-анализа
                ("idx_parts_origin", "CREATE INDEX IF NOT EXISTS idx_parts_origin ON parts(product_origin)"),
                ("idx_cross_oe", "CREATE INDEX IF NOT EXISTS idx_cross_oe ON cross_references(oe_number_norm)"),
                ("idx_cross_artikul", "CREATE INDEX IF NOT EXISTS idx_cross_artikul ON cross_references(artikul_norm, brand_norm)"),
                ("idx_prices_keys", "CREATE INDEX IF NOT EXISTS idx_prices_keys ON prices(artikul_norm, brand_norm)")
            ]
            for index_name, index_sql in indexes:
                try:
                    self.conn.execute(index_sql)
                except Exception as e:
                    logger.warning(f"Не удалось создать индекс {index_name}: {e}")

    # ========================================================================
    # 🆕 v101.0: МИГРАЦИЯ БД (ДОБАВЛЕНИЕ product_origin)
    # ========================================================================
    def _migrate_database(self):
        """🆕 v101.0: Автоматическая миграция БД — добавление product_origin"""
        try:
            columns = self.conn.execute(
                "SELECT column_name FROM information_schema.columns "
                "WHERE table_name = 'parts'"
            ).fetchall()
            column_names = [col[0] for col in columns]

            if 'product_origin' not in column_names:
                logger.info("🔄 Миграция: добавление колонки product_origin в таблицу parts")
                self.conn.execute(
                    "ALTER TABLE parts ADD COLUMN product_origin VARCHAR DEFAULT 'analog_standard'"
                )
                logger.info("✅ Миграция завершена: колонка product_origin добавлена")

        except Exception as e:
            logger.warning(f"Ошибка миграции БД: {e}")

    # ========================================================================
    # 🆕 v101.0: НОРМАЛИЗАЦИЯ И ОЧИСТКА
    # ========================================================================
    @staticmethod
    def normalize_key(series: pl.Series) -> pl.Series:
        return (series
                .fill_null("")
                .cast(pl.Utf8)
                .str.replace_all("'", "")
                .str.replace_all(r"[^0-9A-Za-zА-Яа-яЁё`\-\s]", "")
                .str.replace_all(r"\s+", " ")
                .str.strip_chars()
                .str.to_lowercase())

    @staticmethod
    @lru_cache(maxsize=10000)
    def normalize_single(value: str) -> str:
        if not value:
            return ""
        value = value.replace("'", "")
        value = re.sub(r"[^0-9A-Za-zА-Яа-яЁё`\-\s]", "", value)
        value = re.sub(r"\s+", " ", value)
        return value.strip().lower()

    @staticmethod
    def clean_values(series: pl.Series) -> pl.Series:
        return (series
                .fill_null("")
                .cast(pl.Utf8)
                .str.replace_all("'", "")
                .str.replace_all(r"[^0-9A-Za-zА-Яа-яЁё`\-\s]", "")
                .str.replace_all(r"\s+", " ")
                .str.strip_chars())

    # ========================================================================
    # 🆕 v101.0: ВЕКТОРИЗОВАННАЯ КАТЕГОРИЗАЦИЯ
    # ========================================================================
    def determine_category_vectorized(self, name_series: pl.Series) -> pl.Series:
        name_lower = name_series.str.to_lowercase()
        patterns = []
        seen_categories = set()
        for key, category in self.category_mapping.items():
            if category in seen_categories:
                continue
            seen_categories.add(category)
            safe_key = re.escape(key.lower())
            patterns.append(f"(?P<{category}>{safe_key})")

        categories_map = {
            'Фильтры': r'фильтр|filter',
            'Тормоза': r'тормоз|brake|колодк|диск|суппорт',
            'Подвеска': r'амортизатор|стойк|spring|подвеск|рычаг',
            'Двигатель': r'двигатель|engine|свеч|поршень|клапан',
            'Трансмиссия': r'трансмиссия|сцеплен|коробк|transmission',
            'Электрика': r'аккумулятор|генератор|стартер|провод|ламп',
            'Рулевое': r'рулевой|тяга|наконечник|steering',
            'Выпуск': r'глушитель|катализатор|выхлоп|exhaust',
            'Охлаждение': r'радиатор|вентилятор|термостат|cooling',
            'Топливо': r'топливный|бензонасос|форсунк|fuel'
        }

        for category, pattern in categories_map.items():
            if category in seen_categories:
                continue
            seen_categories.add(category)
            patterns.append(f"(?P<{category}>{pattern})")

        if not patterns:
            return pl.lit('Разное').alias('category')

        combined_regex = "|".join(patterns)
        try:
            matched = name_lower.str.extract(combined_regex, 0)
            return pl.when(matched.is_not_null() & (matched != "")) \
                     .then(matched) \
                     .otherwise(pl.lit('Разное')) \
                     .alias('category')
        except Exception as e:
            logger.warning(f"Ошибка regex-категоризации: {e}. Fallback.")

        categorization_expr = pl.when(pl.lit(False)).then(pl.lit(None))
        for key, category in self.category_mapping.items():
            categorization_expr = categorization_expr.when(
                name_lower.str.contains(key.lower())
            ).then(pl.lit(category))

        for category, pattern in categories_map.items():
            categorization_expr = categorization_expr.when(
                name_lower.str.contains(pattern, literal=False)
            ).then(pl.lit(category))

        return categorization_expr.otherwise(pl.lit('Разное')).alias('category')

    # ========================================================================
    # 🆕 v101.0: РАСЧЁТ ОПЛАЧИВАЕМОГО ВЕСА
    # ========================================================================
    @staticmethod
    def calculate_billable_weight(weight_kg: float, length_cm: float,
                                  width_cm: float, height_cm: float,
                                  volumetric_coeff: float = 5000.0) -> float:
        if length_cm <= 0 or width_cm <= 0 or height_cm <= 0:
            return weight_kg
        volumetric_weight = (length_cm * width_cm * height_cm) / volumetric_coeff
        billable = max(weight_kg, volumetric_weight)
        billable = math.ceil(billable * 2) / 2
        return billable

    # ========================================================================
    # 🆕 v101.0: ВЕКТОРИЗОВАННАЯ КОНВЕРТАЦИЯ ЧИСЕЛ (ЗАЩИТА ОТ ДАТ)
    # ========================================================================
    @staticmethod
    def vectorized_convert_to_float(series: pl.Series) -> pl.Series:
        """🆕 v101.0: Конвертация Series с защитой от pl.Date/pl.Datetime"""
        if series.dtype in [pl.Date, pl.Datetime]:
            try:
                base = pl.datetime(1899, 12, 30)
                days = (series - base).dt.total_days()
                return days.cast(pl.Float64).fill_null(0.0).round(2)
            except Exception:
                return pl.lit(0.0).cast(pl.Float64)

        str_series = series.cast(pl.Utf8).fill_null("")
        cleaned = str_series.str.replace_all(",", ".")
        extracted = cleaned.str.extract_all(r"[\d.]+")
        first_num = extracted.list.first()
        numeric = first_num.cast(pl.Float64, strict=False)
        numeric = numeric.fill_nan(0.0).fill_null(0.0)
        numeric = numeric.filter(numeric.is_finite()).fill_null(0.0)
        return numeric.round(2)

    @staticmethod
    def safe_convert_to_float(value: Any) -> float:
        if value is None or value == "":
            return 0.0
        if isinstance(value, (int, float)):
            if math.isnan(value) or math.isinf(value):
                return 0.0
            return float(value)
        if isinstance(value, decimal.Decimal):
            return float(value)
        if isinstance(value, (datetime, date, pd.Timestamp)):
            try:
                base = datetime(1899, 12, 30)
                if isinstance(value, pd.Timestamp):
                    value = value.to_pydatetime()
                delta = value - base
                return float(delta.days + delta.seconds / 86400.0)
            except Exception:
                return 0.0
        if isinstance(value, timedelta):
            return float(value.total_seconds() / 86400.0)
        if isinstance(value, str):
            value = value.strip()
            if not value:
                return 0.0
            cleaned = re.sub(r'[^\d.,\-]', '', value)
            if not cleaned:
                return 0.0
            cleaned = cleaned.replace(',', '.')
            parts = cleaned.split('.')
            if len(parts) > 2:
                cleaned = parts[0] + '.' + ''.join(parts[1:])
            try:
                return float(cleaned)
            except ValueError:
                return 0.0
        if hasattr(value, 'dtype') and hasattr(value, 'item'):
            try:
                item = value.item()
                if isinstance(item, (int, float)):
                    return float(item)
            except Exception:
                pass
        try:
            return float(value)
        except (ValueError, TypeError):
            return 0.0

    # ========================================================================
    # 🆕 v101.0: ВАЛИДАЦИЯ ТИПА ТОВАРА
    # ========================================================================
    @staticmethod
    def validate_product_origin(value: str) -> str:
        """🆕 v101.0: Валидация типа товара"""
        valid_origins = [
            'original', 'analog_premium', 'analog_standard',
            'analog_budget', 'china', 'remanufactured', 'used'
        ]
        if not value or value not in valid_origins:
            return 'analog_standard'
        return value
        
class HighVolumeAutoPartsCatalogExtended(HighVolumeAutoPartsCatalog):
    """
    🆕 v101.0: Расширенный HighVolume каталог с ABC/XYZ-анализом и Google Sheets.
    
    Новые возможности:
    ✅ ABC/XYZ-анализ каталога (A=80%, B=15%, C=5%)
    ✅ Прямой экспорт в Google Sheets
    ✅ Приоритет Яндекс Маркет
    ✅ Сезонный спрос по категориям
    ✅ Статистика по типам товаров
    """
    
    def __init__(self):
        super().__init__()
        self._abc_cache = {}
        self._google_sheets_client = None
        logger.info("🚀 HighVolumeAutoPartsCatalogExtended v101.0 инициализирован")
    
    # ========================================================================
    # 🆕 v101.0: ABC/XYZ-АНАЛИЗ КАТАЛОГА
    # ========================================================================
    def analyze_abc_xyz(
        self,
        category: Optional[str] = None,
        marketplace: Optional[str] = None,
        period_days: int = 90
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Полный ABC/XYZ-анализ каталога.
        
        ABC-классификация (по доле прибыли):
        - A: 80% прибыли (стратегические товары)
        - B: 15% прибыли (важные товары)
        - C: 5% прибыли (прочие товары)
        
        XYZ-классификация (по стабильности спроса):
        - X: CV < 0.2 (стабильный спрос)
        - Y: CV 0.2-0.5 (умеренный)
        - Z: CV > 0.5 (нестабильный)
        
        Args:
            category: Фильтр по категории (опционально)
            marketplace: Фильтр по МП (опционально)
            period_days: Период анализа в днях (по умолчанию 90)
        
        Returns:
            Dict с полной статистикой ABC/XYZ
        """
        cache_key = f"abc_xyz_{category}_{marketplace}_{period_days}"
        if cache_key in self._abc_cache:
            logger.info(f"💾 ABC/XYZ-анализ из кэша: {cache_key}")
            return self._abc_cache[cache_key]
        
        logger.info(f"🔍 Запуск ABC/XYZ-анализа: category={category}, mp={marketplace}, period={period_days}d")
        
        try:
            # Формируем WHERE-условия
            where_clauses = []
            params = []
            
            if category:
                where_clauses.append("p.category = ?")
                params.append(category)
            
            if marketplace:
                where_clauses.append("p.marketplace = ?")
                params.append(marketplace)
            
            where_sql = " AND ".join(where_clauses) if where_clauses else "1=1"
            
            # Запрос: получаем прибыль по товарам за период
            query = f"""
                WITH SalesData AS (
                    SELECT 
                        p.artikul_norm,
                        p.brand_norm,
                        p.artikul,
                        p.brand,
                        p.category,
                        COALESCE(p.product_origin, 'analog_standard') as product_origin,
                        SUM(pr.price) as total_revenue,
                        COUNT(*) as sales_count,
                        AVG(pr.price) as avg_price
                    FROM parts p
                    LEFT JOIN prices pr ON p.artikul_norm = pr.artikul_norm 
                        AND p.brand_norm = pr.brand_norm
                    WHERE {where_sql}
                    GROUP BY p.artikul_norm, p.brand_norm, p.artikul, p.brand, p.category, p.product_origin
                ),
                ProfitData AS (
                    SELECT 
                        *,
                        total_revenue * 0.25 as estimated_profit  -- Упрощённый расчёт прибыли
                    FROM SalesData
                )
                SELECT * FROM ProfitData
                ORDER BY estimated_profit DESC
            """
            
            df = self.conn.execute(query, params).df()
            
            if df.empty:
                logger.warning("⚠️ Нет данных для ABC/XYZ-анализа")
                return {
                    "success": False,
                    "error": "Нет данных для анализа",
                    "total_items": 0,
                }
            
            # ABC-классификация
            total_profit = df['estimated_profit'].sum()
            df['cumulative_profit'] = df['estimated_profit'].cumsum()
            df['cumulative_share'] = df['cumulative_profit'] / total_profit
            
            def assign_abc(share):
                if share <= 0.80:
                    return "A"
                elif share <= 0.95:
                    return "B"
                else:
                    return "C"
            
            df['abc_class'] = df['cumulative_share'].apply(assign_abc)
            
            # XYZ-классификация (упрощённо — по количеству продаж)
            def assign_xyz(sales_count):
                if sales_count >= 10:
                    return "X"
                elif sales_count >= 3:
                    return "Y"
                else:
                    return "Z"
            
            df['xyz_class'] = df['sales_count'].apply(assign_xyz)
            
            # Матрица ABC/XYZ
            matrix = {}
            for abc in ["A", "B", "C"]:
                for xyz in ["X", "Y", "Z"]:
                    cell = f"{abc}{xyz}"
                    count = len(df[(df['abc_class'] == abc) & (df['xyz_class'] == xyz)])
                    matrix[cell] = count
            
            # Статистика по классам
            class_stats = {}
            for abc in ["A", "B", "C"]:
                class_df = df[df['abc_class'] == abc]
                class_stats[abc] = {
                    "count": len(class_df),
                    "total_profit": class_df['estimated_profit'].sum(),
                    "profit_share": class_df['estimated_profit'].sum() / total_profit,
                    "avg_price": class_df['avg_price'].mean(),
                    "total_revenue": class_df['total_revenue'].sum(),
                }
            
            # Топ A-товаров
            top_a = df[df['abc_class'] == 'A'].head(20).to_dict('records')
            
            # Bottom C-товаров
            bottom_c = df[df['abc_class'] == 'C'].tail(20).to_dict('records')
            
            result = {
                "success": True,
                "total_items": len(df),
                "total_profit": total_profit,
                "matrix": matrix,
                "class_stats": class_stats,
                "top_a_items": top_a,
                "bottom_c_items": bottom_c,
                "full_data": df.to_dict('records'),
                "analyzed_at": datetime.now().isoformat(),
                "period_days": period_days,
            }
            
            # Кэшируем результат (TTL 1 час)
            self._abc_cache[cache_key] = result
            
            logger.info(
                f"✅ ABC/XYZ-анализ завершён: "
                f"A={class_stats['A']['count']} ({class_stats['A']['profit_share']:.1%}), "
                f"B={class_stats['B']['count']} ({class_stats['B']['profit_share']:.1%}), "
                f"C={class_stats['C']['count']} ({class_stats['C']['profit_share']:.1%})"
            )
            
            return result
            
        except Exception as e:
            logger.error(f"❌ Ошибка ABC/XYZ-анализа: {e}")
            logger.error(traceback.format_exc())
            return {
                "success": False,
                "error": str(e),
                "total_items": 0,
            }
    
    # ========================================================================
    # 🆕 v101.0: РЕКОМЕНДАЦИИ ПО ABC-КЛАССАМ
    # ========================================================================
    def get_abc_recommendations(
        self,
        abc_class: str,
        xyz_class: Optional[str] = None,
        marketplace: Optional[str] = None
    ) -> List[Dict[str, Any]]:
        """
        🆕 v101.0: Получить рекомендации по ABC-классу с приоритетом Яндекс Маркет.
        
        Args:
            abc_class: Класс (A, B, C)
            xyz_class: XYZ-класс (опционально)
            marketplace: Фильтр по МП (опционально)
        
        Returns:
            List рекомендаций с приоритетом
        """
        recommendations = []
        
        # Базовые рекомендации по ABC-классу
        base_recommendations = {
            "A": {
                "title": "🏆 Стратегические товары (80% прибыли)",
                "actions": [
                    "✅ Держать постоянный запас на складе",
                    "✅ Не демпинговать — высокая маржа",
                    "✅ Приоритет в рекламе",
                    "✅ Участвовать в акциях МП",
                ],
                "priority": 1,
            },
            "B": {
                "title": "🥈 Важные товары (15% прибыли)",
                "actions": [
                    "📊 Контролировать маржу",
                    "🔄 Автоматизация заказа",
                    "📈 Анализ сезонности",
                    "💡 Оптимизация логистики",
                ],
                "priority": 2,
            },
            "C": {
                "title": "🥉 Прочие товары (5% прибыли)",
                "actions": [
                    "⚠️ Пересмотреть ассортимент",
                    "🗑️ Кандидаты на вывод",
                    "💰 Повысить цены или снизить расходы",
                    "🔄 Ребрендинг или замена",
                ],
                "priority": 3,
            },
        }
        
        if abc_class not in base_recommendations:
            return []
        
        base = base_recommendations[abc_class]
        
        # 🆕 v101.0: Приоритет Яндекс Маркет
        yandex_priority = 0 if marketplace == "Яндекс Маркет" else 0
        
        recommendations.append({
            "class": abc_class,
            "xyz_class": xyz_class,
            "marketplace": marketplace,
            "title": base["title"],
            "actions": base["actions"],
            "priority": base["priority"] + yandex_priority,
        })
        
        # Специфические рекомендации по XYZ
        if xyz_class:
            xyz_recommendations = {
                "X": {
                    "title": "✅ Стабильный спрос",
                    "actions": [
                        "📦 Автоматическое пополнение",
                        "💎 Оптимальный страховой запас",
                    ],
                },
                "Y": {
                    "title": "🟡 Умеренный спрос",
                    "actions": [
                        "📊 Мониторинг продаж",
                        "⚠️ Контроль остатков",
                    ],
                },
                "Z": {
                    "title": "⚠️ Нестабильный спрос",
                    "actions": [
                        "🔍 Глубокий анализ причин",
                        "📉 Минимальный запас",
                        "💡 Рассмотреть вывод",
                    ],
                },
            }
            
            if xyz_class in xyz_recommendations:
                xyz_rec = xyz_recommendations[xyz_class]
                recommendations.append({
                    "class": abc_class,
                    "xyz_class": xyz_class,
                    "marketplace": marketplace,
                    "title": xyz_rec["title"],
                    "actions": xyz_rec["actions"],
                    "priority": base["priority"] + 1,
                })
        
        return recommendations
    
    # ========================================================================
    # 🆕 v101.0: ЭКСПОРТ В GOOGLE SHEETS
    # ========================================================================
    def export_to_google_sheets(
        self,
        spreadsheet_id: Optional[str] = None,
        sheet_name: str = "Каталог",
        credentials_path: Optional[str] = None,
        include_prices: bool = True,
        apply_markup: bool = True,
        category_filter: Optional[str] = None,
        max_rows: int = 10000
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Прямой экспорт каталога в Google Sheets.
        
        Args:
            spreadsheet_id: ID существующей таблицы (опционально)
            sheet_name: Название листа
            credentials_path: Путь к JSON credentials
            include_prices: Включить цены
            apply_markup: Применить наценку
            category_filter: Фильтр по категории
            max_rows: Макс. количество строк
        
        Returns:
            Dict с результатами экспорта
        """
        if not GSPREAD_AVAILABLE:
            return {
                "success": False,
                "error": "gspread не установлен. Установите: pip install gspread google-auth",
            }
        
        try:
            # Аутентификация
            if credentials_path and os.path.exists(credentials_path):
                scopes = [
                    "https://www.googleapis.com/auth/spreadsheets",
                    "https://www.googleapis.com/auth/drive",
                ]
                creds = Credentials.from_service_account_file(
                    credentials_path, scopes=scopes
                )
                gc = gspread.authorize(creds)
            else:
                return {
                    "success": False,
                    "error": "Не указан путь к credentials",
                }
            
            # Получаем данные
            query = self.build_export_query(
                include_prices=include_prices,
                apply_markup=apply_markup
            )
            
            if category_filter:
                query = query.replace(
                    "WHERE r.rn = 1",
                    f"WHERE r.rn = 1 AND r.category = '{category_filter}'"
                )
            
            query += f" LIMIT {max_rows}"
            
            df = self.conn.execute(query).df()
            
            if df.empty:
                return {
                    "success": False,
                    "error": "Нет данных для экспорта",
                }
            
            # Создаём или получаем таблицу
            if spreadsheet_id:
                spreadsheet = gc.open_by_key(spreadsheet_id)
            else:
                title = f"Каталог автозапчастей {datetime.now().strftime('%Y%m%d_%H%M%S')}"
                spreadsheet = gc.create(title)
            
            # Создаём или очищаем лист
            try:
                worksheet = spreadsheet.worksheet(sheet_name)
                worksheet.clear()
            except gspread.WorksheetNotFound:
                worksheet = spreadsheet.add_worksheet(
                    title=sheet_name,
                    rows=len(df) + 10,
                    cols=len(df.columns) + 5
                )
            
            # Записываем данные батчами
            values = [df.columns.tolist()] + df.values.tolist()
            batch_size = 5000
            total_written = 0
            
            for i in range(0, len(values), batch_size):
                batch = values[i:i + batch_size]
                end_row = i + len(batch)
                end_col = get_column_letter(len(df.columns))
                range_name = f"A{i + 1}:{end_col}{end_row}"
                worksheet.update(range_name, batch)
                total_written += len(batch)
                
                logger.info(f"📝 Записано {total_written}/{len(values)} строк в Google Sheets")
            
            # Форматирование
            worksheet.freeze_rows(1)
            
            result = {
                "success": True,
                "spreadsheet_id": spreadsheet.id,
                "spreadsheet_url": spreadsheet.url,
                "sheet_name": sheet_name,
                "rows_written": len(df),
                "columns": len(df.columns),
            }
            
            logger.info(f"✅ Экспорт в Google Sheets завершён: {spreadsheet.url}")
            
            return result
            
        except Exception as e:
            logger.error(f"❌ Ошибка экспорта в Google Sheets: {e}")
            logger.error(traceback.format_exc())
            return {
                "success": False,
                "error": str(e),
            }
    
    # ========================================================================
    # 🆕 v101.0: ФИЛЬТРАЦИЯ ДЛЯ ЯНДЕКС МАРКЕТ
    # ========================================================================
    def get_yandex_market_parts(
        self,
        category: Optional[str] = None,
        min_price: float = 0,
        max_price: float = 999999,
        limit: int = 1000
    ) -> pd.DataFrame:
        """
        🆕 v101.0: Получить товары, оптимизированные для Яндекс Маркет.
        
        Args:
            category: Фильтр по категории
            min_price: Мин. цена
            max_price: Макс. цена
            limit: Макс. количество товаров
        
        Returns:
            DataFrame с товарами для Яндекс Маркет
        """
        try:
            where_clauses = ["pr.price >= ?", "pr.price <= ?"]
            params = [min_price, max_price]
            
            if category:
                where_clauses.append("p.category = ?")
                params.append(category)
            
            where_sql = " AND ".join(where_clauses)
            
            query = f"""
                SELECT 
                    p.artikul,
                    p.brand,
                    p.category,
                    COALESCE(p.product_origin, 'analog_standard') as product_origin,
                    p.length,
                    p.width,
                    p.height,
                    p.weight,
                    p.billable_weight,
                    pr.price,
                    pr.currency,
                    pd.oe_list,
                    pd.representative_name,
                    pd.representative_applicability
                FROM parts p
                LEFT JOIN prices pr ON p.artikul_norm = pr.artikul_norm 
                    AND p.brand_norm = pr.brand_norm
                LEFT JOIN (
                    SELECT 
                        cr.artikul_norm,
                        cr.brand_norm,
                        STRING_AGG(DISTINCT o.oe_number, ', ') as oe_list,
                        ANY_VALUE(o.name) as representative_name,
                        ANY_VALUE(o.applicability) as representative_applicability
                    FROM cross_references cr
                    LEFT JOIN oe o ON cr.oe_number_norm = o.oe_number_norm
                    GROUP BY cr.artikul_norm, cr.brand_norm
                ) pd ON p.artikul_norm = pd.artikul_norm AND p.brand_norm = pd.brand_norm
                WHERE {where_sql}
                ORDER BY pr.price DESC
                LIMIT ?
            """
            
            params.append(limit)
            
            df = self.conn.execute(query, params).df()
            
            logger.info(f"✅ Получено {len(df)} товаров для Яндекс Маркет")
            
            return df
            
        except Exception as e:
            logger.error(f"❌ Ошибка получения товаров для Яндекс Маркет: {e}")
            return pd.DataFrame()
    
    # ========================================================================
    # 🆕 v101.0: РАСЧЁТ СЕЗОННОГО СПРОСА
    # ========================================================================
    def calculate_seasonal_demand(
        self,
        category: str,
        months_ahead: int = 3
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Расчёт сезонного спроса по категории.
        
        Args:
            category: Название категории
            months_ahead: Количество месяцев вперёд
        
        Returns:
            Dict с прогнозом спроса
        """
        try:
            # Получаем коэффициенты сезонности из Блока 5
            from streamlit_app import get_demand_coefficient
            
            forecast = []
            current_month = datetime.now().month
            
            for i in range(months_ahead):
                month = ((current_month - 1 + i) % 12) + 1
                coeff = get_demand_coefficient(category, month)
                
                forecast.append({
                    "month": month,
                    "month_name": datetime(2026, month, 1).strftime('%B'),
                    "demand_coefficient": round(coeff, 3),
                    "trend": "↑" if coeff > 1.0 else "↓" if coeff < 1.0 else "→",
                })
            
            avg_coeff = sum(f['demand_coefficient'] for f in forecast) / len(forecast)
            
            result = {
                "category": category,
                "forecast": forecast,
                "avg_coefficient": round(avg_coeff, 3),
                "recommendation": self._get_seasonal_recommendation(avg_coeff),
            }
            
            return result
            
        except Exception as e:
            logger.error(f"❌ Ошибка расчёта сезонного спроса: {e}")
            return {
                "category": category,
                "error": str(e),
            }
    
    def _get_seasonal_recommendation(self, avg_coeff: float) -> str:
        """Получить рекомендацию по сезонному спросу"""
        if avg_coeff > 1.3:
            return "📈 Высокий сезон. Увеличьте запас и рекламный бюджет."
        elif avg_coeff > 1.0:
            return "📊 Умеренный рост. Поддерживайте текущий уровень."
        elif avg_coeff > 0.8:
            return "📉 Низкий сезон. Рассмотрите акции."
        else:
            return "⚠️ Мёртвый сезон. Минимальный запас, фокус на ликвидацию."
    
    # ========================================================================
    # 🆕 v101.0: СТАТИСТИКА ПО ТИПАМ ТОВАРОВ
    # ========================================================================
    def get_origin_statistics(self) -> Dict[str, Any]:
        """
        🆕 v101.0: Статистика по типам товаров (оригинал/аналог/Китай).
        
        Returns:
            Dict со статистикой
        """
        try:
            query = """
                SELECT 
                    COALESCE(product_origin, 'analog_standard') as origin,
                    COUNT(*) as count,
                    AVG(price) as avg_price,
                    SUM(price) as total_revenue
                FROM parts p
                LEFT JOIN prices pr ON p.artikul_norm = pr.artikul_norm 
                    AND p.brand_norm = pr.brand_norm
                GROUP BY product_origin
                ORDER BY count DESC
            """
            
            df = self.conn.execute(query).df()
            
            if df.empty:
                return {"total": 0, "by_origin": {}}
            
            total = df['count'].sum()
            
            by_origin = {}
            for _, row in df.iterrows():
                origin = row['origin']
                by_origin[origin] = {
                    "count": int(row['count']),
                    "share": round(row['count'] / total * 100, 1),
                    "avg_price": round(row['avg_price'], 2) if row['avg_price'] else 0,
                    "total_revenue": round(row['total_revenue'], 2) if row['total_revenue'] else 0,
                }
            
            return {
                "total": int(total),
                "by_origin": by_origin,
            }
            
        except Exception as e:
            logger.error(f"❌ Ошибка получения статистики по типам товаров: {e}")
            return {"total": 0, "error": str(e)}


