logger = logging.getLogger(__name__)


# ============================================================================
# 🆕 v101.0: КОНСТАНТЫ ВАЛИДАТОРА
# ============================================================================
VALIDATOR_CONFIG = {
    # Пороги отклонений по типу товара
    "tolerance_by_origin": {
        "original": 0.10,           # 10% — оригиналы точные
        "analog_premium": 0.15,     # 15% — премиум аналоги
        "analog_standard": 0.20,    # 20% — стандартные
        "analog_budget": 0.30,      # 30% — бюджетные
        "china": 0.40,              # 40% — Китай (большие отклонения)
        "remanufactured": 0.25,     # 25% — восстановленные
        "used": 0.35,               # 35% — б/у
    },
    
    # Сезонные коэффициенты для габаритов
    "seasonal_dimension_multipliers": {
        "шины_летние": {
            "winter": 1.0, "spring": 1.1, "summer": 1.2, "autumn": 1.0
        },
        "шины_зимние": {
            "winter": 1.3, "spring": 1.0, "summer": 0.9, "autumn": 1.1
        },
        "аккумуляторы": {
            "winter": 1.15, "spring": 1.0, "summer": 0.95, "autumn": 1.1
        },
    },
    
    # Приоритет Яндекс Маркет
    "yandex_market_rounding": {
        "weight_step_kg": 0.1,      # Округление до 100 г
        "dimension_step_cm": 1.0,   # Округление до 1 см
    },
    
    # ABC-классы и приоритеты
    "abc_validation_priority": {
        "A": 1,  # Стратегические — максимальная точность
        "B": 2,  # Важные — средняя точность
        "C": 3,  # Прочие — базовая точность
    },
    
    # Лимиты
    "max_weight_kg": 25.0,
    "max_dimension_cm": 200.0,
    "min_weight_kg": 0.01,
    "min_dimension_cm": 0.1,
}


# ============================================================================
# 🆕 v101.0: РЕЗУЛЬТАТ ВАЛИДАЦИИ
# ============================================================================
@dataclass
class DimensionValidationResult:
    """Результат валидации весогабаритов"""
    valid: bool = True
    category: str = ""
    product_origin: str = "analog_standard"
    abc_class: Optional[str] = None
    deviations: List[Dict[str, Any]] = field(default_factory=list)
    warnings: List[str] = field(default_factory=list)
    recommendations: List[str] = field(default_factory=list)
    corrected_dimensions: Optional[Dict[str, float]] = None
    validation_score: float = 1.0  # 0-1, где 1 = идеальная валидация
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            "valid": self.valid,
            "category": self.category,
            "product_origin": self.product_origin,
            "abc_class": self.abc_class,
            "deviations": self.deviations,
            "warnings": self.warnings,
            "recommendations": self.recommendations,
            "corrected_dimensions": self.corrected_dimensions,
            "validation_score": self.validation_score,
        }


# ============================================================================
# 🆕 v101.0: ОСНОВНОЙ КЛАСС ВАЛИДАТОРА
# ============================================================================
class AdvancedDimensionsValidator:
    """
    🆕 v101.0: Расширенный валидатор весогабаритов с ABC/XYZ и Google Sheets.
    
    Новые возможности:
    ✅ Валидация по типу товара (оригинал/аналог/Китай)
    ✅ Сезонная корректировка габаритов
    ✅ Интеграция с ABC/XYZ-анализом
    ✅ Приоритет Яндекс Маркет
    ✅ Массовая валидация для 300K+ SKU
    ✅ Google Sheets экспорт отчёта
    """
    
    def __init__(self):
        self.logger = logging.getLogger('AdvancedDimensionsValidator')
        self._validation_cache = {}
        self._stats = {
            "total_validations": 0,
            "valid_count": 0,
            "invalid_count": 0,
            "cache_hits": 0,
            "cache_misses": 0,
        }
        
        # 🆕 v101.0: База категорий с весогабаритами
        self._category_defaults = self._init_category_defaults()
        
        self.logger.info("🔧 AdvancedDimensionsValidator v101.0 инициализирован")
    
    # ========================================================================
    # 🆕 v101.0: БАЗА КАТЕГОРИЙ С ТОЧНЫМИ ГАБАРИТАМИ
    # ========================================================================
    def _init_category_defaults(self) -> Dict[str, Dict[str, float]]:
        """🆕 v101.0: Точные габариты для 25+ категорий"""
        return {
            # Фильтры
            "фильтры": {"l": 15, "w": 15, "h": 15, "weight": 0.5},
            "масляные_фильтры": {"l": 8, "w": 8, "h": 12, "weight": 0.3},
            "воздушные_фильтры": {"l": 25, "w": 20, "h": 5, "weight": 0.4},
            "топливные_фильтры": {"l": 10, "w": 10, "h": 15, "weight": 0.3},
            "салонные_фильтры": {"l": 25, "w": 20, "h": 3, "weight": 0.2},
            
            # Тормозная система
            "тормозная_система": {"l": 30, "w": 20, "h": 10, "weight": 2.0},
            "тормозные_диски": {"l": 30, "w": 30, "h": 5, "weight": 5.0},
            "тормозные_колодки": {"l": 15, "w": 10, "h": 5, "weight": 1.5},
            
            # Масла и жидкости
            "масла": {"l": 10, "w": 10, "h": 25, "weight": 1.0},
            "моторные_масла": {"l": 10, "w": 10, "h": 25, "weight": 4.0},
            "антифриз": {"l": 15, "w": 15, "h": 30, "weight": 5.0},
            
            # Шины и диски
            "шины": {"l": 60, "w": 60, "h": 20, "weight": 10.0},
            "летние_шины": {"l": 60, "w": 60, "h": 20, "weight": 10.0},
            "зимние_шины": {"l": 60, "w": 60, "h": 22, "weight": 12.0},
            "диски": {"l": 50, "w": 50, "h": 15, "weight": 12.0},
            
            # Аккумуляторы
            "аккумуляторы": {"l": 35, "w": 20, "h": 22, "weight": 18.0},
            
            # Оптика
            "фары": {"l": 40, "w": 25, "h": 25, "weight": 3.0},
            "лампы": {"l": 5, "w": 5, "h": 10, "weight": 0.05},
            "led_лампы": {"l": 5, "w": 5, "h": 10, "weight": 0.03},
            
            # Двигатель
            "двигатель": {"l": 60, "w": 50, "h": 50, "weight": 80.0},
            "свечи_зажигания": {"l": 3, "w": 3, "h": 8, "weight": 0.05},
            
            # Подвеска
            "амортизаторы": {"l": 10, "w": 10, "h": 50, "weight": 3.0},
            "пружины": {"l": 30, "w": 15, "h": 40, "weight": 3.0},
            "шаровые_опоры": {"l": 10, "w": 10, "h": 15, "weight": 0.5},
            
            # Электрика
            "стартеры": {"l": 20, "w": 15, "h": 15, "weight": 4.0},
            "генераторы": {"l": 25, "w": 20, "h": 20, "weight": 6.0},
            
            # Кузов
            "бамперы": {"l": 120, "w": 30, "h": 25, "weight": 8.0},
            "крылья": {"l": 80, "w": 40, "h": 30, "weight": 5.0},
            
            # Инструменты
            "домкраты": {"l": 25, "w": 15, "h": 10, "weight": 3.0},
            "наборы_ключей": {"l": 20, "w": 15, "h": 5, "weight": 2.0},
        }
    
    # ========================================================================
    # 🆕 v101.0: НОРМАЛИЗАЦИЯ С УЧЁТОМ ЕДИНИЦ ИЗМЕРЕНИЯ
    # ========================================================================
    @staticmethod
    @lru_cache(maxsize=10000)
    def normalize_dimension(value: float, unit_hint: str = "") -> float:
        """🆕 v101.0: Нормализация размеров с кэшированием"""
        if not value or value <= 0:
            return 0.0
        
        unit_lower = unit_hint.lower() if unit_hint else ""
        
        # Миллиметры → сантиметры
        if any(x in unit_lower for x in ['mm', 'мм', 'millimeter']):
            return value / 10.0
        
        # Метры → сантиметры
        if any(x in unit_lower for x in ['m', 'метр', 'meter']) and value < 10:
            return value * 100.0
        
        # Если значение слишком большое — вероятно, миллиметры
        if value > 300:
            return value / 10.0
        
        return value
    
    @staticmethod
    @lru_cache(maxsize=10000)
    def normalize_weight(value: float, unit_hint: str = "") -> float:
        """🆕 v101.0: Нормализация веса с кэшированием"""
        if not value or value <= 0:
            return 0.0
        
        unit_lower = unit_hint.lower() if unit_hint else ""
        
        # Граммы → килограммы
        if any(x in unit_lower for x in ['g', 'гр', 'gram']):
            return value / 1000.0
        
        # Тонны → килограммы
        if any(x in unit_lower for x in ['t', 'тонн', 'ton']) and value < 10:
            return value * 1000.0
        
        # Если значение слишком большое — вероятно, граммы
        if value > 100:
            return value / 1000.0
        
        return value
    
    # ========================================================================
    # 🆕 v101.0: ЭВРИСТИКА С УЧЁТОМ ТИПА ТОВАРА
    # ========================================================================
    def infer_missing_dimensions(
        self,
        category: str,
        weight: float,
        product_origin: str = "analog_standard"
    ) -> Dict[str, float]:
        """
        🆕 v101.0: Эвристическое определение габаритов с учётом типа товара.
        
        Для Китая габариты могут быть больше (плохая упаковка).
        Для оригинала — точнее.
        """
        cat_key = category.lower().strip()
        
        # Получаем базовые габариты
        if cat_key in self._category_defaults:
            dims = self._category_defaults[cat_key]
        else:
            # Поиск по подстроке
            dims = None
            for key, value in self._category_defaults.items():
                if key in cat_key or cat_key in key:
                    dims = value
                    break
            
            if dims is None:
                dims = {"l": 20, "w": 20, "h": 20, "weight": 1.0}
        
        # 🆕 v101.0: Масштабирование по весу
        scale = max(0.5, min(3.0, weight / dims.get("weight", 2.0)))
        
        # 🆕 v101.0: Корректировка по типу товара
        origin_multiplier = {
            "original": 1.0,
            "analog_premium": 1.0,
            "analog_standard": 1.05,    # Чуть больше (упаковка)
            "analog_budget": 1.10,      # Больше (плохая упаковка)
            "china": 1.20,              # Ещё больше
            "remanufactured": 1.05,
            "used": 1.10,
        }.get(product_origin, 1.0)
        
        return {
            "length_cm": round(dims["l"] * scale * origin_multiplier, 2),
            "width_cm": round(dims["w"] * scale * origin_multiplier, 2),
            "height_cm": round(dims["h"] * scale * origin_multiplier, 2),
            "weight_kg": round(weight, 2),
        }
    
    # ========================================================================
    # 🆕 v101.0: СЕЗОННАЯ КОРРЕКТИРОВКА
    # ========================================================================
    def apply_seasonal_adjustment(
        self,
        category: str,
        dimensions: Dict[str, float],
        month: Optional[int] = None
    ) -> Dict[str, float]:
        """
        🆕 v101.0: Корректировка габаритов по сезону.
        
        Например, зимние шины летом занимают меньше места (сжатые).
        """
        if month is None:
            month = datetime.now().month
        
        # Определяем сезон
        if month in [12, 1, 2]:
            season = "winter"
        elif month in [3, 4, 5]:
            season = "spring"
        elif month in [6, 7, 8]:
            season = "summer"
        else:
            season = "autumn"
        
        cat_key = category.lower().strip()
        
        # Проверяем, есть ли сезонные коэффициенты
        if cat_key in VALIDATOR_CONFIG["seasonal_dimension_multipliers"]:
            multipliers = VALIDATOR_CONFIG["seasonal_dimension_multipliers"][cat_key]
            multiplier = multipliers.get(season, 1.0)
            
            # Применяем только к высоте (объём упаковки)
            dimensions = dimensions.copy()
            dimensions["height_cm"] = round(
                dimensions["height_cm"] * multiplier, 2
            )
            
            logger.debug(
                f"🌤️ Сезонная корректировка для {category}: "
                f"высота × {multiplier}"
            )
        
        return dimensions
    
    # ========================================================================
    # 🆕 v101.0: ОКРУГЛЕНИЕ ДЛЯ ЯНДЕКС МАРКЕТ
    # ========================================================================
    def round_for_yandex_market(
        self,
        dimensions: Dict[str, float]
    ) -> Dict[str, float]:
        """
        🆕 v101.0: Округление габаритов под требования Яндекс Маркет.
        
        Яндекс Маркет округляет:
        - Вес до 100 г (0.1 кг)
        - Размеры до 1 см
        """
        rounding = VALIDATOR_CONFIG["yandex_market_rounding"]
        
        return {
            "length_cm": math.ceil(dimensions["length_cm"] / rounding["dimension_step_cm"]) * rounding["dimension_step_cm"],
            "width_cm": math.ceil(dimensions["width_cm"] / rounding["dimension_step_cm"]) * rounding["dimension_step_cm"],
            "height_cm": math.ceil(dimensions["height_cm"] / rounding["dimension_step_cm"]) * rounding["dimension_step_cm"],
            "weight_kg": math.ceil(dimensions["weight_kg"] / rounding["weight_step_kg"]) * rounding["weight_step_kg"],
        }
    
    # ========================================================================
    # 🆕 v101.0: ОСНОВНАЯ ВАЛИДАЦИЯ (С НОВЫМИ ВОЗМОЖНОСТЯМИ)
    # ========================================================================
    def validate_and_normalize_row(
        self,
        row: pd.Series,
        length_col: Optional[str] = None,
        width_col: Optional[str] = None,
        height_col: Optional[str] = None,
        weight_col: Optional[str] = None,
        category: str = "",
        product_origin: str = "analog_standard",
        abc_class: Optional[str] = None,
        marketplace: str = "Яндекс Маркет",
        month: Optional[int] = None
    ) -> DimensionValidationResult:
        """
        🆕 v101.0: Валидация строки с учётом типа товара, ABC-класса и МП.
        """
        self._stats["total_validations"] += 1
        
        result = DimensionValidationResult(
            category=category,
            product_origin=product_origin,
            abc_class=abc_class,
        )
        
        try:
            # Извлекаем сырые значения
            raw_l = self._safe_float(row.get(length_col, 0)) if length_col else 0
            raw_w = self._safe_float(row.get(width_col, 0)) if width_col else 0
            raw_h = self._safe_float(row.get(height_col, 0)) if height_col else 0
            raw_weight = self._safe_float(row.get(weight_col, 0)) if weight_col else 0
            
            # Нормализация
            length = self.normalize_dimension(raw_l)
            width = self.normalize_dimension(raw_w)
            height = self.normalize_dimension(raw_h)
            weight = self.normalize_weight(raw_weight)
            
            # 🆕 v101.0: Получаем допустимое отклонение по типу товара
            tolerance = VALIDATOR_CONFIG["tolerance_by_origin"].get(
                product_origin, 0.20
            )
            
            # 🆕 v101.0: Для класса A — более строгая валидация
            if abc_class == "A":
                tolerance *= 0.7  # На 30% строже
            
            # Получаем ожидаемые габариты
            expected = self.infer_missing_dimensions(
                category, weight, product_origin
            )
            
            # 🆕 v101.0: Сезонная корректировка
            expected = self.apply_seasonal_adjustment(
                category, expected, month
            )
            
            # Проверяем отклонения
            deviations = []
            
            if length > 0 and expected["length_cm"] > 0:
                dev = abs(length - expected["length_cm"]) / expected["length_cm"]
                if dev > tolerance:
                    deviations.append({
                        "parameter": "Длина",
                        "actual": length,
                        "expected": expected["length_cm"],
                        "deviation_percent": round(dev * 100, 1),
                    })
            
            if width > 0 and expected["width_cm"] > 0:
                dev = abs(width - expected["width_cm"]) / expected["width_cm"]
                if dev > tolerance:
                    deviations.append({
                        "parameter": "Ширина",
                        "actual": width,
                        "expected": expected["width_cm"],
                        "deviation_percent": round(dev * 100, 1),
                    })
            
            if height > 0 and expected["height_cm"] > 0:
                dev = abs(height - expected["height_cm"]) / expected["height_cm"]
                if dev > tolerance:
                    deviations.append({
                        "parameter": "Высота",
                        "actual": height,
                        "expected": expected["height_cm"],
                        "deviation_percent": round(dev * 100, 1),
                    })
            
            if weight > 0 and expected["weight_kg"] > 0:
                dev = abs(weight - expected["weight_kg"]) / expected["weight_kg"]
                if dev > tolerance:
                    deviations.append({
                        "parameter": "Вес",
                        "actual": weight,
                        "expected": expected["weight_kg"],
                        "deviation_percent": round(dev * 100, 1),
                    })
            
            result.deviations = deviations
            result.valid = len(deviations) == 0
            
            # 🆕 v101.0: Если есть отклонения — предлагаем исправленные габариты
            if deviations:
                result.corrected_dimensions = expected
                
                # 🆕 v101.0: Округление для Яндекс Маркет
                if "яндекс" in marketplace.lower():
                    result.corrected_dimensions = self.round_for_yandex_market(
                        result.corrected_dimensions
                    )
                
                result.warnings.append(
                    f"⚠️ Обнаружены отклонения в {len(deviations)} параметрах"
                )
                
                # Рекомендации
                result.recommendations.append(
                    f"💡 Рекомендуется использовать исправленные габариты: "
                    f"{expected['length_cm']}x{expected['width_cm']}x{expected['height_cm']} см, "
                    f"{expected['weight_kg']} кг"
                )
            
            # 🆕 v101.0: Если габариты отсутствуют — заполняем
            if length == 0 or width == 0 or height == 0:
                result.corrected_dimensions = expected
                result.warnings.append(
                    "⚠️ Некоторые габариты отсутствуют — заполнены автоматически"
                )
                result.recommendations.append(
                    "💡 Проверьте реальные габариты товара"
                )
            
            # 🆕 v101.0: Расчёт validation score
            if result.valid:
                result.validation_score = 1.0
                self._stats["valid_count"] += 1
            else:
                # Чем больше отклонений — тем ниже score
                max_dev = max(d["deviation_percent"] for d in deviations) if deviations else 0
                result.validation_score = max(0.0, 1.0 - max_dev / 100)
                self._stats["invalid_count"] += 1
            
        except Exception as e:
            logger.error(f"Ошибка валидации: {e}")
            result.warnings.append(f"❌ Ошибка валидации: {str(e)}")
            result.valid = False
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: МАССОВАЯ ВАЛИДАЦИЯ (ДЛЯ 300K+ SKU)
    # ========================================================================
    def validate_batch(
        self,
        df: pd.DataFrame,
        length_col: Optional[str] = None,
        width_col: Optional[str] = None,
        height_col: Optional[str] = None,
        weight_col: Optional[str] = None,
        category_col: Optional[str] = None,
        origin_col: Optional[str] = None,
        abc_col: Optional[str] = None,
        marketplace: str = "Яндекс Маркет",
        progress_callback: Optional[callable] = None
    ) -> pd.DataFrame:
        """
        🆕 v101.0: Массовая валидация для больших каталогов.
        
        Returns:
            DataFrame с результатами валидации
        """
        results = []
        total = len(df)
        
        logger.info(f"🔍 Запуск массовой валидации: {total} записей")
        
        for idx, row in df.iterrows():
            try:
                category = str(row.get(category_col, "")) if category_col else ""
                origin = str(row.get(origin_col, "analog_standard")) if origin_col else "analog_standard"
                abc_class = str(row.get(abc_col, None)) if abc_col else None
                
                validation = self.validate_and_normalize_row(
                    row=row,
                    length_col=length_col,
                    width_col=width_col,
                    height_col=height_col,
                    weight_col=weight_col,
                    category=category,
                    product_origin=origin,
                    abc_class=abc_class,
                    marketplace=marketplace,
                )
                
                result_dict = validation.to_dict()
                result_dict["index"] = idx
                result_dict["Артикул"] = row.get("Артикул", "")
                result_dict["Бренд"] = row.get("Бренд", "")
                
                results.append(result_dict)
                
                # Progress callback
                if progress_callback and (idx + 1) % 1000 == 0:
                    progress_callback((idx + 1) / total)
                
            except Exception as e:
                logger.error(f"Ошибка валидации строки {idx}: {e}")
                results.append({
                    "index": idx,
                    "valid": False,
                    "warnings": [f"❌ Ошибка: {str(e)}"],
                })
        
        if progress_callback:
            progress_callback(1.0)
        
        logger.info(
            f"✅ Массовая валидация завершена: "
            f"{self._stats['valid_count']} валидных, "
            f"{self._stats['invalid_count']} невалидных"
        )
        
        return pd.DataFrame(results)
    
    # ========================================================================
    # 🆕 v101.0: ЭКСПОРТ ОТЧЁТА В GOOGLE SHEETS
    # ========================================================================
    def export_validation_report_to_sheets(
        self,
        validation_df: pd.DataFrame,
        credentials_path: str,
        spreadsheet_title: Optional[str] = None,
        share_email: Optional[str] = None
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Экспорт отчёта о валидации в Google Sheets.
        """
        if not GSPREAD_AVAILABLE:
            return {
                "success": False,
                "error": "gspread не установлен",
            }
        
        try:
            # Аутентификация
            scopes = [
                "https://www.googleapis.com/auth/spreadsheets",
                "https://www.googleapis.com/auth/drive",
            ]
            creds = Credentials.from_service_account_file(
                credentials_path, scopes=scopes
            )
            gc = gspread.authorize(creds)
            
            # Создаём таблицу
            title = spreadsheet_title or (
                f"Отчёт валидации габаритов {datetime.now().strftime('%Y%m%d_%H%M%S')}"
            )
            spreadsheet = gc.create(title)
            
            # Лист 1: Сводка
            summary_data = {
                "Показатель": [
                    "Всего проверено",
                    "Валидных",
                    "Невалидных",
                    "% валидных",
                    "Средний validation score",
                ],
                "Значение": [
                    len(validation_df),
                    validation_df["valid"].sum(),
                    (~validation_df["valid"]).sum(),
                    f"{validation_df['valid'].mean() * 100:.1f}%",
                    f"{validation_df['validation_score'].mean():.2f}",
                ],
            }
            summary_df = pd.DataFrame(summary_data)
            
            ws_summary = spreadsheet.sheet1
            ws_summary.update_title("Сводка")
            ws_summary.update(
                "A1",
                [summary_df.columns.tolist()] + summary_df.values.tolist()
            )
            
            # Лист 2: Проблемные товары
            invalid_df = validation_df[~validation_df["valid"]].copy()
            if not invalid_df.empty:
                ws_invalid = spreadsheet.add_worksheet(
                    title="Проблемные товары",
                    rows=len(invalid_df) + 10,
                    cols=10
                )
                
                # Преобразуем в список списков
                values = [invalid_df.columns.tolist()] + invalid_df.values.tolist()
                ws_invalid.update("A1", values)
            
            # Лист 3: Рекомендации
            recommendations = []
            for _, row in invalid_df.head(50).iterrows():
                recs = row.get("recommendations", [])
                if isinstance(recs, list):
                    for rec in recs:
                        recommendations.append({
                            "Артикул": row.get("Артикул", ""),
                            "Рекомендация": rec,
                        })
            
            if recommendations:
                rec_df = pd.DataFrame(recommendations)
                ws_rec = spreadsheet.add_worksheet(
                    title="Рекомендации",
                    rows=len(rec_df) + 10,
                    cols=5
                )
                ws_rec.update(
                    "A1",
                    [rec_df.columns.tolist()] + rec_df.values.tolist()
                )
            
            # Шаринг
            if share_email:
                spreadsheet.share(share_email, perm_type="user", role="writer")
            
            return {
                "success": True,
                "spreadsheet_id": spreadsheet.id,
                "spreadsheet_url": spreadsheet.url,
                "sheets_created": ["Сводка", "Проблемные товары", "Рекомендации"],
            }
        
        except Exception as e:
            logger.error(f"Ошибка экспорта в Google Sheets: {e}")
            return {
                "success": False,
                "error": str(e),
            }
    
    # ========================================================================
    # 🆕 v101.0: СТАТИСТИКА ВАЛИДАТОРА
    # ========================================================================
    def get_stats(self) -> Dict[str, Any]:
        """Получение статистики валидатора"""
        return self._stats.copy()
    
    def reset_stats(self):
        """Сброс статистики"""
        self._stats = {
            "total_validations": 0,
            "valid_count": 0,
            "invalid_count": 0,
            "cache_hits": 0,
            "cache_misses": 0,
        }
    
    # ========================================================================
    # 🆕 v101.0: ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
    # ========================================================================
    @staticmethod
    def _safe_float(value: Any, default: float = 0.0) -> float:
        """Безопасное преобразование в float"""
        if value is None or value == "":
            return default
        try:
            return float(value)
        except (ValueError, TypeError):
            return default


# ============================================================================
# 🆕 v101.0: ФАБРИКА ДЛЯ ПОЛУЧЕНИЯ ЭКЗЕМПЛЯРА
# ============================================================================
_validator_instance = None


def get_advanced_dimensions_validator() -> AdvancedDimensionsValidator:
    """Получение глобального экземпляра валидатора (singleton)"""
    global _validator_instance
    if _validator_instance is None:
        _validator_instance = AdvancedDimensionsValidator()
    return _validator_instance
    
