# 🆕 v101.0: ABC/XYZ-АНАЛИЗ КАТАЛОГА
# ============================================================================
def show_catalog_abc_xyz_analysis(catalog):
    """
    🏆 ABC/XYZ-анализ каталога (🆕 v101.0)
    
    Классификация товаров по:
    - ABC: доле прибыли (A=80%, B=15%, C=5%)
    - XYZ: стабильности спроса (X=стабильный, Y=умеренный, Z=нестабильный)
    """
    st.subheader("🏆 ABC/XYZ-анализ каталога")
    st.info("""
📋 **О АНАЛИЗЕ:**
ABC/XYZ-анализ помогает классифицировать товары по:
- **ABC** — доле прибыли (A=80%, B=15%, C=5%)
- **XYZ** — стабильности спроса (X=стабильный, Y=умеренный, Z=нестабильный)

💡 **Рекомендации:**
- Класс A — стратегические товары, держать запас
- Класс B — важные товары, контролировать маржу
- Класс C — кандидаты на вывод
""")
    
    # ====================================================================
    # 🔍 ФИЛЬТРЫ
    # ====================================================================
    st.subheader("🔍 Параметры анализа")
    
    col1, col2, col3 = st.columns(3)
    
    with col1:
        category_filter = st.text_input(
            "📂 Категория (опционально)",
            placeholder="например: фильтры",
            key="catalog_abc_category"
        )
    
    with col2:
        origin_filter = st.selectbox(
            "🏷️ Тип товара",
            list(CATALOG_UI_CONSTANTS["PRODUCT_ORIGINS"].keys()),
            format_func=lambda x: CATALOG_UI_CONSTANTS["PRODUCT_ORIGINS"][x],
            key="catalog_abc_origin"
        )
    
    with col3:
        period_days = st.number_input(
            "📅 Период анализа (дней)",
            min_value=30,
            max_value=365,
            value=90,
            step=30,
            key="catalog_abc_period"
        )
    
    # ====================================================================
    # 🚀 ЗАПУСК АНАЛИЗА
    # ====================================================================
    if st.button("🔍 Запустить ABC/XYZ-анализ", type="primary", key="catalog_abc_analyze"):
        with st.spinner("Анализ каталога..."):
            try:
                # Формируем SQL-запрос
                where_clauses = []
                params = []
                
                if category_filter:
                    where_clauses.append("p.category LIKE ?")
                    params.append(f"%{category_filter}%")
                
                if origin_filter != "all":
                    where_clauses.append("p.product_origin = ?")
                    params.append(origin_filter)
                
                where_sql = " AND ".join(where_clauses) if where_clauses else "1=1"
                
                # Запрос: получаем прибыль по товарам за период
                query = f"""
                    WITH SalesData AS (
                        SELECT 
                            p.artikul_norm,
                            p.brand_norm,
                            p.artikul,
                            p.brand,
                            p.category,
                            COALESCE(p.product_origin, 'analog_standard') as product_origin,
                            SUM(pr.price) as total_revenue,
                            COUNT(*) as sales_count,
                            AVG(pr.price) as avg_price
                        FROM parts p
                        LEFT JOIN prices pr ON p.artikul_norm = pr.artikul_norm 
                            AND p.brand_norm = pr.brand_norm
                        WHERE {where_sql}
                        GROUP BY p.artikul_norm, p.brand_norm, p.artikul, p.brand, 
                                 p.category, p.product_origin
                    ),
                    ProfitData AS (
                        SELECT 
                            *,
                            total_revenue * 0.25 as estimated_profit
                        FROM SalesData
                    )
                    SELECT * FROM ProfitData
                    ORDER BY estimated_profit DESC
                """
                
                df = catalog.conn.execute(query, params).df()
                
                if df.empty:
                    st.warning("⚠️ Нет данных для ABC/XYZ-анализа")
                    return
                
                # ABC-классификация
                total_profit = df['estimated_profit'].sum()
                df['cumulative_profit'] = df['estimated_profit'].cumsum()
                df['cumulative_share'] = df['cumulative_profit'] / total_profit
                
                def assign_abc(share):
                    if share <= 0.80:
                        return "A"
                    elif share <= 0.95:
                        return "B"
                    else:
                        return "C"
                
                df['abc_class'] = df['cumulative_share'].apply(assign_abc)
                
                # XYZ-классификация (упрощённо — по количеству продаж)
                def assign_xyz(sales_count):
                    if sales_count >= 10:
                        return "X"
                    elif sales_count >= 3:
                        return "Y"
                    else:
                        return "Z"
                
                df['xyz_class'] = df['sales_count'].apply(assign_xyz)
                
                # Сохраняем результат
                st.session_state.catalog_abc_result = {
                    "df": df,
                    "total_profit": total_profit,
                    "total_items": len(df),
                }
                
                st.success(f"✅ Анализ завершён! Проанализировано {len(df)} товаров")
                
            except Exception as e:
                st.error(f"❌ Ошибка анализа: {e}")
                logger.error(traceback.format_exc())
    
    # ====================================================================
    # 📊 РЕЗУЛЬТАТЫ АНАЛИЗА
    # ====================================================================
    if 'catalog_abc_result' in st.session_state:
        result = st.session_state.catalog_abc_result
        df = result['df']
        total_profit = result['total_profit']
        
        # ====================================================================
        # 📊 KPI-МЕТРИКИ
        # ====================================================================
        st.subheader("📊 Результаты анализа")
        
        col1, col2, col3, col4 = st.columns(4)
        
        with col1:
            st.metric("📦 Всего товаров", f"{result['total_items']:,}")
        
        with col2:
            st.metric("💰 Общая прибыль", f"{total_profit:,.0f} ₽")
        
        with col3:
            class_a_count = (df['abc_class'] == 'A').sum()
            st.metric("🏆 Класс A", f"{class_a_count} товаров")
        
        with col4:
            class_a_profit = df[df['abc_class'] == 'A']['estimated_profit'].sum()
            class_a_share = class_a_profit / total_profit if total_profit > 0 else 0
            st.metric("📈 Доля A", f"{class_a_share:.1%}")
        
        # ====================================================================
        # 📊 МАТРИЦА ABC/XYZ
        # ====================================================================
        st.subheader("📊 Матрица ABC/XYZ")
        
        matrix_data = []
        for abc in ["A", "B", "C"]:
            row_data = {"Класс": abc}
            for xyz in ["X", "Y", "Z"]:
                count = len(df[(df['abc_class'] == abc) & (df['xyz_class'] == xyz)])
                row_data[xyz] = count
            matrix_data.append(row_data)
        
        matrix_df = pd.DataFrame(matrix_data)
        st.dataframe(matrix_df, use_container_width=True)
        
