# 🆕 v101.0: ПОИСК И ФИЛЬТРАЦИЯ (РАСШИРЕННАЯ)
# ============================================================================
def show_catalog_search(catalog):
    """🔍 Поиск и фильтрация в каталоге (🆕 v101.0)"""
    st.subheader("🔍 Поиск и фильтрация")
    
    # ====================================================================
    # 🔍 ОСНОВНЫЕ ФИЛЬТРЫ
    # ====================================================================
    col1, col2 = st.columns(2)
    
    with col1:
        search_artikul = st.text_input("🔢 Артикул", key="search_artikul")
        search_brand = st.text_input("🏷️ Бренд", key="search_brand")
    
    with col2:
        search_oe = st.text_input("🔗 OE номер", key="search_oe")
        search_category = st.text_input("📂 Категория", key="search_category")
    
    # 🆕 v101.0: Фильтрация по типу товара
    st.subheader("🏷️ Дополнительные фильтры")
    
    col1, col2, col3 = st.columns(3)
    
    with col1:
        origin_filter = st.selectbox(
            "Тип товара",
            list(CATALOG_UI_CONSTANTS["PRODUCT_ORIGINS"].keys()),
            format_func=lambda x: CATALOG_UI_CONSTANTS["PRODUCT_ORIGINS"][x],
            key="search_origin"
        )
    
    with col2:
        season_filter = st.selectbox(
            "Сезон",
            list(CATALOG_UI_CONSTANTS["SEASONS"].keys()),
            format_func=lambda x: CATALOG_UI_CONSTANTS["SEASONS"][x],
            key="search_season"
        )
    
    with col3:
        min_price = st.number_input(
            "💰 Мин. цена",
            min_value=0.0,
            value=0.0,
            step=100.0,
            key="search_min_price"
        )
    
    # ====================================================================
    # 🔍 ЗАПРОС
    # ====================================================================
    if st.button("🔍 Найти", key="catalog_search"):
        query_parts = []
        params = []
        
        if search_artikul:
            query_parts.append("artikul LIKE ?")
            params.append(f"%{search_artikul}%")
        
        if search_brand:
            query_parts.append("brand LIKE ?")
            params.append(f"%{search_brand}%")
        
        if search_oe:
            query_parts.append("""
                artikul_norm IN (
                    SELECT artikul_norm FROM cross_references
                    WHERE oe_number_norm LIKE ?
                )
            """)
            params.append(f"%{search_oe}%")
        
        if search_category:
            query_parts.append("category LIKE ?")
            params.append(f"%{search_category}%")
        
        # 🆕 v101.0: Фильтр по типу товара
        if origin_filter != "all":
            query_parts.append("product_origin = ?")
            params.append(origin_filter)
        
        # 🆕 v101.0: Фильтр по цене
        if min_price > 0:
            query_parts.append("""
                artikul_norm IN (
                    SELECT artikul_norm FROM prices WHERE price >= ?
                )
            """)
            params.append(min_price)
        
        if query_parts:
            where_clause = " AND ".join(query_parts)
            query = f"SELECT * FROM parts WHERE {where_clause} LIMIT 100"
            
            try:
                df = catalog.conn.execute(query, params).df()
                
                if df.empty:
                    st.warning("⚠️ Ничего не найдено")
                else:
                    st.success(f"✅ Найдено {len(df)} товаров")
                    
                    # 🆕 v101.0: Выделяем Яндекс Маркет
                    display_df = df.copy()
                    st.dataframe(display_df, use_container_width=True)
                    
            except duckdb.Error as e:
                st.error(f"❌ Ошибка поиска: {e}")
        else:
            st.warning("⚠️ Введите хотя бы один критерий поиска")


