def show_catalog_export(catalog):
    """📤 Экспорт каталога (🆕 v101.0)"""
    st.subheader("📤 Экспорт каталога")
    
    total = catalog.conn.execute(
        "SELECT COUNT(*) FROM (SELECT DISTINCT artikul_norm, brand_norm FROM parts)"
    ).fetchone()[0]
    
    st.info(f"📊 Всего записей: {total:,}")
    
    if total == 0:
        st.warning("⚠️ Нет данных для экспорта")
        return
    
    col1, col2 = st.columns(2)
    
    with col1:
        format_choice = st.radio(
            "📁 Формат файла",
            ["CSV", "Excel", "Parquet", "Google Sheets"],  # 🆕 v101.0
            key="catalog_export_format"
        )
        
        selected_columns = st.multiselect(
            "📋 Выберите колонки для экспорта",
            [
                "Артикул бренда", "Бренд", "Наименование", "Применимость", "Описание",
                "Категория товара", "Кратность", "Длинна", "Ширина", "Высота", "Вес",
                "Длинна/Ширина/Высота", "OE номер", "аналоги", "Ссылка на изображение",
                "Цена", "Валюта"
            ]
        )
    
    with col2:
        include_prices = st.checkbox("💰 Включить цены", value=True)
        apply_markup = st.checkbox("📈 Применить наценку", value=True, disabled=not include_prices)
        
        # 🆕 v101.0: Google Sheets настройки
        if format_choice == "Google Sheets":
            credentials_path = st.text_input(
                "🔑 Путь к credentials",
                placeholder="/path/to/credentials.json",
                key="catalog_gs_credentials"
            )
            
            share_email = st.text_input(
                "📧 Email для шаринга",
                placeholder="user@example.com",
                key="catalog_gs_share_email"
            )
    
    st.markdown("---")
    st.caption("💡 Если не выбраны колонки - экспортируются все")
    
    if st.button("🚀 Экспортировать", type="primary", key="catalog_export_btn"):
        # 🆕 v101.0: Маппинг формата к расширению файла
        format_extensions = CATALOG_UI_CONSTANTS["EXPORT_FORMATS"]
        ext = format_extensions.get(format_choice, {}).get("ext", format_choice.lower())
        
        output_path = catalog.data_dir / f"export_{datetime.now().strftime('%Y%m%d_%H%M%S')}.{ext}"
        
        with st.spinner(f"Генерация файла {format_choice}..."):
            if format_choice == "CSV":
                success = catalog.export_to_csv_optimized(
                    str(output_path),
                    selected_columns if selected_columns else None,
                    include_prices,
                    apply_markup
                )
            elif format_choice == "Excel":
                success = catalog.export_to_excel_optimized(
                    str(output_path),
                    selected_columns if selected_columns else None,
                    include_prices,
                    apply_markup
                )
            elif format_choice == "Parquet":
                success = catalog.export_to_parquet(
                    str(output_path),
                    selected_columns if selected_columns else None,
                    include_prices,
                    apply_markup
                )
            elif format_choice == "Google Sheets":
                # 🆕 v101.0: Экспорт в Google Sheets
                if not credentials_path:
                    st.error("❌ Укажите путь к credentials")
                    return
                
                if not os.path.exists(credentials_path):
                    st.error(f"❌ Файл не найден: {credentials_path}")
                    return
                
                try:
                    # Получаем данные
                    query = catalog.build_export_query(
                        selected_columns if selected_columns else None,
                        include_prices,
                        apply_markup
                    )
                    df = catalog.conn.execute(query).df()
                    
                    if df.empty:
                        st.error("❌ Нет данных для экспорта")
                        return
                    
                    # Экспортируем в Google Sheets
                    scopes = [
                        "https://www.googleapis.com/auth/spreadsheets",
                        "https://www.googleapis.com/auth/drive",
                    ]
                    creds = Credentials.from_service_account_file(
                        credentials_path, scopes=scopes
                    )
                    gc = gspread.authorize(creds)
                    
                    title = f"Каталог автозапчастей {datetime.now().strftime('%Y%m%d_%H%M%S')}"
                    spreadsheet = gc.create(title)
                    
                    # Записываем данные батчами
                    worksheet = spreadsheet.sheet1
                    worksheet.update_title("Каталог")
                    
                    values = [df.columns.tolist()] + df.values.tolist()
                    batch_size = 5000
                    
                    for i in range(0, len(values), batch_size):
                        batch = values[i:i + batch_size]
                        end_row = i + len(batch)
                        end_col = get_column_letter(len(df.columns))
                        range_name = f"A{i + 1}:{end_col}{end_row}"
                        worksheet.update(range_name, batch)
                    
                    worksheet.freeze_rows(1)
                    
                    # Шаринг
                    if share_email:
                        spreadsheet.share(share_email, perm_type="user", role="writer")
                    
                    st.success("✅ Экспорт в Google Sheets завершён!")
                    st.info(f"📊 Таблица: [{spreadsheet.url}]({spreadsheet.url})")
                    
                    return
                    
                except Exception as e:
                    st.error(f"❌ Ошибка экспорта в Google Sheets: {e}")
                    logger.error(traceback.format_exc())
                    return
            else:
                st.warning("Неподдерживаемый формат")
                return
        
        # Для файловых форматов
        if success and output_path.exists():
            with open(output_path, "rb") as f:
                file_data = f.read()
            
            mime_map = {
                "CSV": "text/csv; charset=utf-8",
                "Excel": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                "Parquet": "application/octet-stream"
            }
            mime_type = mime_map.get(format_choice, "application/octet-stream")
            
            st.download_button(
                label=f"⬇️ Скачать {format_choice} файл",
                data=file_data,
                file_name=output_path.name,
                mime=mime_type,
                key="catalog_download"
            )
            st.success(f"✅ Файл {output_path.name} готов к скачиванию!")
        else:
            st.error("❌ Ошибка при экспорте")


