# ============================================================================
# 🆕 v101.0: ДАТАКЛАСС ДЛЯ РЕЗУЛЬТАТА AI-ЗАПРОСА
# ============================================================================
@dataclass
class AIRequestResult:
    """Результат запроса к DeepSeek API"""
    success: bool = False
    rates: Optional[Dict[str, Any]] = None
    forecast: Optional[Dict[str, Any]] = None
    source: str = "AI_LIVE"
    confidence: float = 0.0
    latency_ms: float = 0.0
    tokens_used: int = 0
    error: Optional[str] = None
    timestamp: datetime = field(default_factory=datetime.now)
    from_cache: bool = False
    validation_errors: List[str] = field(default_factory=list)
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            "success": self.success,
            "rates": self.rates,
            "forecast": self.forecast,
            "source": self.source,
            "confidence": self.confidence,
            "latency_ms": self.latency_ms,
            "tokens_used": self.tokens_used,
            "error": self.error,
            "timestamp": self.timestamp.isoformat(),
            "from_cache": self.from_cache,
            "validation_errors": self.validation_errors,
        }


# ============================================================================
# 🆕 v101.0: ОСНОВНОЙ КЛАСС DEEPSEEK AI UPDATER
# ============================================================================
class DeepSeekRateUpdater:
    """
    🤖 Обновление тарифов через DeepSeek AI.
    
    🆕 v101.0:
    ✅ Реальная интеграция с DeepSeek API
    ✅ Структурированный промпт с JSON schema
    ✅ Кэширование AI-ответов
    ✅ Профилирование и метрики
    ✅ Валидация ответа
    ✅ Fallback на базовые тарифы
    """
    
    # 🆕 v101.0: Шаблон промпта для получения тарифов
    TARIFF_PROMPT_TEMPLATE = """
Ты — эксперт по маркетплейсам России. Твоя задача — предоставить актуальные тарифы для маркетплейса "{marketplace}" на {current_date}.

**ВАЖНО:** Ответь ТОЛЬКО в формате JSON без дополнительного текста.

**Требуемая структура JSON:**
{{
    "commission_rate": <float, от 0.01 до 0.50, комиссия в долях>,
    "min_commission": <float, минимальная комиссия в рублях>,
    "logistics_base": <float, базовая стоимость логистики в рублях>,
    "logistics_per_kg": <float, стоимость логистики за кг>,
    "logistics_per_liter": <float, стоимость логистики за литр объёма>,
    "storage_per_day": <float, стоимость хранения за литр в день>,
    "return_fee": <float, процент возвратов в долях>,
    "acquiring_fee": <float, процент эквайринга в долях>,
    "last_mile_fee": <float, стоимость последней мили в рублях>,
    "delivery_fee_percent": <float, процент доставки в долях>,
    "hazardous_surcharge": <float, надбавка за опасные в долях>,
    "fragile_surcharge": <float, надбавка за хрупкие в долях>,
    "oversized_surcharge": <float, надбавка за крупногабарит в долях>,
    "subscription_fee": <float, ежемесячная подписка в рублях>,
    "seasonal_multipliers": {{
        "winter": <float, коэффициент зимой>,
        "spring": <float, коэффициент весной>,
        "summer": <float, коэффициент летом>,
        "autumn": <float, коэффициент осенью>
    }},
    "category_rates": {{
        "фильтры": <float>,
        "масла": <float>,
        "аккумуляторы": <float>,
        "шины": <float>,
        "тормозная_система": <float>
    }},
    "confidence": <float, от 0.0 до 1.0, уверенность в данных>,
    "notes": "<строка, примечания о тарифах>"
}}

**Дополнительная информация:**
{additional_context}

**Правила:**
1. Используй актуальные данные на {current_date}
2. Если не уверен — укажи низкий confidence (0.3-0.5)
3. Все числовые значения — в долях (не в процентах)
4. Ответь ТОЛЬКО JSON, без markdown, без пояснений
"""

    # 🆕 v101.0: Шаблон промпта для прогноза
    FORECAST_PROMPT_TEMPLATE = """
Ты — эксперт по прогнозированию тарифов маркетплейсов.

**Текущие тарифы для {marketplace}:**
{current_rates}

**Задача:** Спрогнозируй изменение тарифов на следующие {months_ahead} месяцев.

**Формат ответа (ТОЛЬКО JSON):**
{{
    "forecast": {{
        "month_1": {{
            "commission_rate": <float>,
            "logistics_base": <float>,
            "trend": "<string: stable_up/stable_down/volatile>",
            "confidence": <float 0-1>
        }},
        "month_2": {{...}},
        "month_3": {{...}},
        "month_4": {{...}},
        "month_5": {{...}},
        "month_6": {{...}}
    }},
    "overall_trend": "<string>",
    "risk_factors": ["<string>", ...],
    "confidence": <float 0-1>
}}

**Учитывай:**
- Сезонность (зима/лето)
- Инфляцию в России
- Конкуренцию между маркетплейсами
- Исторические тренды
"""
    
    def __init__(self, api_key: Optional[str] = None):
        """
        Инициализация DeepSeek AI Updater.
        
        Args:
            api_key: API ключ DeepSeek (опционально, можно из env)
        """
        self.api_key = api_key or os.environ.get("DEEPSEEK_API_KEY", "")
        self.logger = logging.getLogger("DeepSeekRateUpdater")
        
        # HTTP сессия с retry
        self.session = self._create_session()
        
        # Rate limiter
        self._last_request_time = 0
        self._request_times = []
        
        # Кэш (используем SmartTariffCache если доступен)
        try:
            self.tariff_cache = get_smart_tariff_cache()
        except Exception:
            self.tariff_cache = None
        
        # 🆕 v101.0: Метрики
        self.metrics = {
            "total_requests": 0,
            "successful_requests": 0,
            "failed_requests": 0,
            "cached_requests": 0,
            "total_tokens_used": 0,
            "total_latency_ms": 0.0,
            "rate_limited_requests": 0,
            "validation_errors": 0,
            "last_error": None,
            "last_success": None,
        }
        
        # 🆕 v101.0: Конфигурация
        self.config = DEEPSEEK_CONFIG.copy()
        
        self.logger.info(
            f"🤖 DeepSeekRateUpdater v101.0 инициализирован. "
            f"API ключ: {'✅ найден' if self.api_key else '❌ НЕ задан (fallback режим)'}"
        )
    
    # ========================================================================
    # 🆕 v101.0: СОЗДАНИЕ HTTP СЕССИИ С RETRY
    # ========================================================================
    def _create_session(self) -> requests.Session:
        """Создание HTTP сессии с retry стратегией"""
        session = requests.Session()
        
        retry_strategy = Retry(
            total=self.config["max_retries"],
            backoff_factor=self.config["retry_backoff_factor"],
            status_forcelist=self.config["retry_statuses"],
            allowed_methods=["POST"],
        )
        
        adapter = HTTPAdapter(max_retries=retry_strategy)
        session.mount("https://", adapter)
        session.mount("http://", adapter)
        
        session.headers.update({
            "Content-Type": "application/json",
            "User-Agent": "AutoPartsUnitEconomicsPro/101.0",
            "Accept": "application/json",
        })
        
        if self.api_key:
            session.headers["Authorization"] = f"Bearer {self.api_key}"
        
        return session
    
    # ========================================================================
    # 🆕 v101.0: RATE LIMITING
    # ========================================================================
    def _check_rate_limit(self) -> bool:
        """Проверка rate limit"""
        now = time.time()
        
        # Минимальная задержка между запросами
        if now - self._last_request_time < self.config["min_delay_between_requests"]:
            sleep_time = self.config["min_delay_between_requests"] - (now - self._last_request_time)
            self.logger.debug(f"⏳ Rate limit: ожидание {sleep_time:.1f} сек")
            time.sleep(sleep_time)
        
        # Лимит запросов в минуту
        self._request_times = [t for t in self._request_times if now - t < 60]
        if len(self._request_times) >= self.config["max_requests_per_minute"]:
            oldest = min(self._request_times)
            wait_time = 60 - (now - oldest)
            self.logger.warning(f"⏳ Превышен лимит запросов. Ожидание {wait_time:.1f} сек")
            time.sleep(wait_time)
            self.metrics["rate_limited_requests"] += 1
            return False
        
        return True
    
    # ========================================================================
    # 🆕 v101.0: ОСНОВНОЙ МЕТОД ПОЛУЧЕНИЯ ТАРИФОВ
    # ========================================================================
    def get_rates_from_ai(
        self,
        marketplace: str,
        category: Optional[str] = None,
        force_refresh: bool = False,
        use_cache: bool = True,
        include_forecast: bool = False,
    ) -> Tuple[Optional[Dict[str, Any]], 'TariffSource', Optional[Dict[str, Any]]]:
        """
        🆕 v101.0: Получение тарифов через DeepSeek AI.
        
        Args:
            marketplace: Название маркетплейса
            category: Категория (опционально)
            force_refresh: Принудительное обновление (игнорировать кэш)
            use_cache: Использовать кэш
            include_forecast: Включить прогноз
        
        Returns:
            Tuple: (rates_dict, tariff_source, forecast_dict_or_None)
        """
        self.metrics["total_requests"] += 1
        start_time = time.perf_counter()
        
        result = AIRequestResult()
        
        try:
            # 🆕 v101.0: Проверка кэша
            if use_cache and not force_refresh and self.tariff_cache:
                cached_entry = self.tariff_cache.get(marketplace, category, use_expired=False)
                if cached_entry and cached_entry.data:
                    result.success = True
                    result.rates = cached_entry.data
                    result.source = cached_entry.source.value
                    result.confidence = cached_entry.confidence if hasattr(cached_entry, 'confidence') else 0.9
                    result.from_cache = True
                    result.latency_ms = (time.perf_counter() - start_time) * 1000
                    
                    self.metrics["cached_requests"] += 1
                    self.metrics["successful_requests"] += 1
                    
                    self.logger.info(
                        f"💾 Тарифы для {marketplace} из кэша "
                        f"({result.latency_ms:.0f} мс)"
                    )
                    
                    # Прогноз из кэша
                    forecast = None
                    if include_forecast:
                        forecast = self.tariff_cache.get_forecast(marketplace, category)
                    
                    return result.rates, self._source_from_string(result.source), forecast
            
            # 🆕 v101.0: Если нет API ключа — fallback
            if not self.api_key:
                self.logger.info("🔑 API ключ не задан. Используем fallback на базовые тарифы")
                return self._fallback_to_hardcoded(marketplace, category, include_forecast)
            
            # 🆕 v101.0: Rate limiting
            if not self._check_rate_limit():
                self.logger.warning("⏳ Rate limit превышен. Fallback на базовые тарифы")
                return self._fallback_to_hardcoded(marketplace, category, include_forecast)
            
            # 🆕 v101.0: Формируем промпт
            prompt = self._build_tariff_prompt(marketplace, category)
            
            # 🆕 v101.0: Отправляем запрос
            response = self._call_deepseek_api(prompt)
            
            if not response:
                self.metrics["failed_requests"] += 1
                result.error = "Пустой ответ от API"
                return self._fallback_to_hardcoded(marketplace, category, include_forecast)
            
            # 🆕 v101.0: Парсим ответ
            parsed = self._parse_ai_response(response)
            
            if not parsed:
                self.metrics["failed_requests"] += 1
                self.metrics["validation_errors"] += 1
                result.error = "Ошибка парсинга ответа AI"
                return self._fallback_to_hardcoded(marketplace, category, include_forecast)
            
            # 🆕 v101.0: Валидация
            validation_errors = self._validate_rates(parsed)
            if validation_errors:
                self.metrics["validation_errors"] += 1
                result.validation_errors = validation_errors
                self.logger.warning(f"⚠️ Ошибки валидации: {validation_errors}")
                # Не фатально — используем с пониженным confidence
            
            # 🆕 v101.0: Успех
            result.success = True
            result.rates = parsed
            result.source = "AI_LIVE"
            result.confidence = parsed.get("confidence", 0.85)
            result.latency_ms = (time.perf_counter() - start_time) * 1000
            result.tokens_used = response.get("usage", {}).get("total_tokens", 0)
            
            self.metrics["successful_requests"] += 1
            self.metrics["total_tokens_used"] += result.tokens_used
            self.metrics["total_latency_ms"] += result.latency_ms
            self.metrics["last_success"] = datetime.now().isoformat()
            
            # 🆕 v101.0: Сохраняем в кэш
            if self.tariff_cache:
                try:
                    from streamlit_app import TariffSource
                    self.tariff_cache.set(
                        marketplace=marketplace,
                        category=category,
                        data=parsed,
                        source=TariffSource.AI_LIVE,
                        ttl_seconds=self.config["cache_ttl_seconds"],
                        notes=f"AI запрос {datetime.now().strftime('%Y-%m-%d %H:%M')}",
                    )
                except Exception as e:
                    self.logger.warning(f"Не удалось сохранить в кэш: {e}")
            
            self.logger.info(
                f"✅ Тарифы для {marketplace} получены от AI "
                f"({result.latency_ms:.0f} мс, {result.tokens_used} токенов, "
                f"confidence: {result.confidence:.0%})"
            )
            
            # 🆕 v101.0: Прогноз
            forecast = None
            if include_forecast:
                forecast = self.get_tariff_forecast(marketplace, category)
                if forecast:
                    try:
                        self.tariff_cache.set_forecast(marketplace, category, forecast)
                    except Exception as e:
                        self.logger.warning(f"Не удалось сохранить прогноз: {e}")
            
            return result.rates, self._source_from_string(result.source), forecast
            
        except Exception as e:
            self.metrics["failed_requests"] += 1
            self.metrics["last_error"] = str(e)
            result.error = str(e)
            self.logger.error(f"❌ Ошибка get_rates_from_ai: {e}")
            self.logger.error(traceback.format_exc())
            return self._fallback_to_hardcoded(marketplace, category, include_forecast)
    
    # ========================================================================
    # 🆕 v101.0: ПОСТРОЕНИЕ ПРОМПТА
    # ========================================================================
    def _build_tariff_prompt(self, marketplace: str, category: Optional[str]) -> str:
        """Построение промпта для получения тарифов"""
        current_date = datetime.now().strftime("%d.%m.%Y")
        
        # Дополнительный контекст
        additional_context = []
        if category:
            additional_context.append(f"- Категория: {category}")
        
        # Исторические данные (если есть)
        if self.tariff_cache:
            try:
                cached = self.tariff_cache.get(marketplace, category, use_expired=True)
                if cached and cached.data:
                    additional_context.append(f"- Предыдущие тарифы (от {datetime.fromtimestamp(cached.timestamp).strftime('%d.%m.%Y')}):")
                    additional_context.append(f"  - Комиссия: {cached.data.get('commission_rate', 'N/A')}")
                    additional_context.append(f"  - Логистика база: {cached.data.get('logistics_base', 'N/A')}")
            except Exception:
                pass
        
        additional_context_str = "\n".join(additional_context) if additional_context else "Нет дополнительной информации"
        
        return self.TARIFF_PROMPT_TEMPLATE.format(
            marketplace=marketplace,
            current_date=current_date,
            additional_context=additional_context_str,
        )
    
    # ========================================================================
    # 🆕 v101.0: ВЫЗОВ DEEPSEEK API
    # ========================================================================
    def _call_deepseek_api(self, prompt: str) -> Optional[Dict[str, Any]]:
        """Вызов DeepSeek API"""
        try:
            payload = {
                "model": self.config["model"],
                "messages": [
                    {
                        "role": "system",
                        "content": "Ты — эксперт по маркетплейсам России. Отвечай ТОЛЬКО в формате JSON."
                    },
                    {
                        "role": "user",
                        "content": prompt
                    }
                ],
                "max_tokens": self.config["max_tokens"],
                "temperature": self.config["temperature"],
                "top_p": self.config["top_p"],
                "response_format": {"type": "json_object"},
            }
            
            self._last_request_time = time.time()
            self._request_times.append(self._last_request_time)
            
            response = self.session.post(
                self.config["api_url"],
                json=payload,
                timeout=self.config["timeout_seconds"],
            )
            
            if response.status_code == 200:
                return response.json()
            elif response.status_code == 429:
                self.logger.warning("⏳ Rate limit от DeepSeek API (429)")
                self.metrics["rate_limited_requests"] += 1
                return None
            else:
                self.logger.error(f"❌ HTTP {response.status_code}: {response.text[:200]}")
                return None
                
        except requests.exceptions.Timeout:
            self.logger.error("⏱️ Таймаут запроса к DeepSeek API")
            return None
        except requests.exceptions.RequestException as e:
            self.logger.error(f"❌ Ошибка запроса: {e}")
            return None
        except Exception as e:
            self.logger.error(f"❌ Неожиданная ошибка: {e}")
            return None
    
    # ========================================================================
    # 🆕 v101.0: ПАРСИНГ ОТВЕТА AI
    # ========================================================================
    def _parse_ai_response(self, response: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        """Парсинг ответа от DeepSeek API"""
        try:
            # Извлекаем content из ответа
            content = response.get("choices", [{}])[0].get("message", {}).get("content", "")
            
            if not content:
                self.logger.error("Пустой content в ответе")
                return None
            
            # 🆕 v101.0: Пробуем распарсить JSON
            # AI может вернуть markdown с ```json ... ```
            content_clean = content.strip()
            
            # Удаляем markdown обёртку
            if content_clean.startswith("```"):
                content_clean = re.sub(r"^```(?:json)?\s*", "", content_clean)
                content_clean = re.sub(r"\s*```$", "", content_clean)
            
            # Парсим JSON
            parsed = json.loads(content_clean)
            
            if not isinstance(parsed, dict):
                self.logger.error("Ответ не является словарём")
                return None
            
            return parsed
            
        except json.JSONDecodeError as e:
            self.logger.error(f"❌ Ошибка парсинга JSON: {e}")
            self.logger.error(f"Content: {content[:500]}")
            return None
        except Exception as e:
            self.logger.error(f"❌ Ошибка парсинга: {e}")
            return None
    
    # ========================================================================
    # 🆕 v101.0: ВАЛИДАЦИЯ ОТВЕТА AI
    # ========================================================================
    def _validate_rates(self, rates: Dict[str, Any]) -> List[str]:
        """Валидация полученных тарифов"""
        errors = []
        
        # Обязательные поля
        required_fields = [
            "commission_rate", "logistics_base", "logistics_per_kg",
            "storage_per_day", "return_fee", "acquiring_fee"
        ]
        
        for field in required_fields:
            if field not in rates:
                errors.append(f"Отсутствует поле: {field}")
        
        # Проверка диапазонов
        if "commission_rate" in rates:
            val = rates["commission_rate"]
            if not (self.config["min_commission_rate"] <= val <= self.config["max_commission_rate"]):
                errors.append(f"commission_rate вне диапазона: {val}")
        
        if "logistics_base" in rates:
            val = rates["logistics_base"]
            if not (self.config["min_logistics_base"] <= val <= self.config["max_logistics_base"]):
                errors.append(f"logistics_base вне диапазона: {val}")
        
        if "logistics_per_kg" in rates:
            val = rates["logistics_per_kg"]
            if not (self.config["min_logistics_per_kg"] <= val <= self.config["max_logistics_per_kg"]):
                errors.append(f"logistics_per_kg вне диапазона: {val}")
        
        # Проверка seasonal_multipliers
        if "seasonal_multipliers" in rates:
            sm = rates["seasonal_multipliers"]
            if not isinstance(sm, dict):
                errors.append("seasonal_multipliers должен быть словарём")
            else:
                for season in ["winter", "spring", "summer", "autumn"]:
                    if season not in sm:
                        errors.append(f"Отсутствует сезон: {season}")
                    elif not (0.5 <= sm[season] <= 2.0):
                        errors.append(f"seasonal_multipliers.{season} вне диапазона: {sm[season]}")
        
        return errors
    
    # ========================================================================
    # 🆕 v101.0: FALLBACK НА БАЗОВЫЕ ТАРИФЫ
    # ========================================================================
    def _fallback_to_hardcoded(
        self,
        marketplace: str,
        category: Optional[str],
        include_forecast: bool
    ) -> Tuple[Optional[Dict[str, Any]], 'TariffSource', Optional[Dict[str, Any]]]:
        """Fallback на базовые тарифы из конфигурации"""
        try:
            configs = get_marketplace_configs_2026()
            config = configs.get(marketplace)
            
            if not config:
                self.logger.warning(f"Маркетплейс {marketplace} не найден в конфигурации")
                return None, TariffSource.HARDCODED, None
            
            # Базовые тарифы из конфигурации
            rates = {
                "commission_rate": config.commission_rate,
                "min_commission": config.min_commission,
                "logistics_base": config.logistics_base,
                "logistics_per_kg": config.logistics_per_kg,
                "logistics_per_liter": config.logistics_per_liter,
                "storage_per_day": config.storage_per_day,
                "return_fee": config.return_fee,
                "acquiring_fee": config.acquiring_fee,
                "last_mile_fee": config.last_mile_fee,
                "delivery_fee_percent": config.delivery_fee_percent,
                "hazardous_surcharge": config.hazardous_surcharge,
                "fragile_surcharge": config.fragile_surcharge,
                "oversized_surcharge": config.oversized_surcharge,
                "seasonal_multipliers": config.seasonal_multipliers,
                "confidence": 0.75,  # Пониженная уверенность
                "notes": "Fallback: базовые тарифы из конфигурации",
            }
            
            # Если указана категория — подтягиваем её комиссию
            if category and category in config.category_rates:
                rates["commission_rate"] = config.category_rates[category]
            
            # Прогноз (упрощённый)
            forecast = None
            if include_forecast:
                forecast = self._generate_simple_forecast(rates)
            
            self.logger.info(f"💾 Fallback: базовые тарифы для {marketplace}")
            
            return rates, TariffSource.HARDCODED, forecast
            
        except Exception as e:
            self.logger.error(f"❌ Ошибка fallback: {e}")
            return None, TariffSource.HARDCODED, None
    
    # ========================================================================
    # 🆕 v101.0: ПРОГНОЗ ТАРИФОВ
    # ========================================================================
    def get_tariff_forecast(
        self,
        marketplace: str,
        category: Optional[str] = None,
        months_ahead: int = 3,
    ) -> Optional[Dict[str, Any]]:
        """
        🆕 v101.0: Получение прогноза тарифов.
        
        Сначала пробуем через AI, если не получилось — упрощённый прогноз.
        """
        try:
            # 🆕 v101.0: Если есть API ключ — пробуем AI
            if self.api_key:
                current_rates = self.get_rates_from_ai(
                    marketplace=marketplace,
                    category=category,
                    use_cache=True,
                    include_forecast=False,
                )[0]
                
                if current_rates:
                    prompt = self.FORECAST_PROMPT_TEMPLATE.format(
                        marketplace=marketplace,
                        current_rates=json.dumps(current_rates, indent=2, ensure_ascii=False),
                        months_ahead=months_ahead,
                    )
                    
                    response = self._call_deepseek_api(prompt)
                    if response:
                        parsed = self._parse_ai_response(response)
                        if parsed and "forecast" in parsed:
                            return parsed
            
            # 🆕 v101.0: Упрощённый прогноз (fallback)
            configs = get_marketplace_configs_2026()
            config = configs.get(marketplace)
            if not config:
                return None
            
            base_rate = config.commission_rate
            if category and category in config.category_rates:
                base_rate = config.category_rates[category]
            
            return self._generate_simple_forecast({
                "commission_rate": base_rate,
                "logistics_base": config.logistics_base,
            }, months_ahead)
            
        except Exception as e:
            self.logger.error(f"❌ Ошибка get_tariff_forecast: {e}")
            return None
    
    def _generate_simple_forecast(
        self,
        rates: Dict[str, Any],
        months_ahead: int = 6
    ) -> Dict[str, Any]:
        """Упрощённый прогноз (без AI)"""
        forecast = {}
        base_commission = rates.get("commission_rate", 0.15)
        base_logistics = rates.get("logistics_base", 50.0)
        
        for i in range(1, months_ahead + 1):
            # Стабильный рост 2% в месяц
            forecast[f"month_{i}"] = {
                "commission_rate": round(base_commission * (1 + 0.02 * i), 4),
                "logistics_base": round(base_logistics * (1 + 0.01 * i), 2),
                "trend": "stable_up",
                "confidence": max(0.5, 0.85 - 0.05 * i),  # Снижается с временем
            }
        
        return {
            "forecast": forecast,
            "overall_trend": "stable_up",
            "risk_factors": ["Инфляция", "Конкуренция между МП"],
            "confidence": 0.70,
        }
    
    # ========================================================================
    # 🆕 v101.0: ОБНОВЛЕНИЕ ВСЕХ МАРКЕТПЛЕЙСОВ
    # ========================================================================
    def update_all_marketplaces(
        self,
        force_refresh: bool = False,
        include_forecast: bool = False,
    ) -> Dict[str, Tuple[Optional[Dict], 'TariffSource', Optional[Dict]]]:
        """Обновляет тарифы для всех маркетплейсов"""
        results = {}
        try:
            configs = get_marketplace_configs_2026()
            for mp_name in configs.keys():
                rates, source, forecast = self.get_rates_from_ai(
                    mp_name,
                    force_refresh=force_refresh,
                    include_forecast=include_forecast,
                )
                results[mp_name] = (rates, source, forecast)
                
                # 🆕 v101.0: Задержка между запросами
                if self.api_key:
                    time.sleep(self.config["min_delay_between_requests"])
            
            self.logger.info(f"✅ Обновлено тарифов: {len(results)} маркетплейсов")
        except Exception as e:
            self.logger.error(f"Ошибка update_all_marketplaces: {e}")
        return results
    
    # ========================================================================
    # 🆕 v101.0: ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
    # ========================================================================
    def _source_from_string(self, source_str: str) -> 'TariffSource':
        """Преобразование строки в TariffSource enum"""
        try:
            from streamlit_app import TariffSource
            return TariffSource(source_str)
        except Exception:
            # Fallback — возвращаем HARDCODED
            try:
                from streamlit_app import TariffSource
                return TariffSource.HARDCODED
            except Exception:
                return "HARDCODED"
    
    # ========================================================================
    # 🆕 v101.0: МЕТРИКИ
    # ========================================================================
    def get_metrics(self) -> Dict[str, Any]:
        """Получение метрик работы AI updater"""
        metrics = self.metrics.copy()
        
        if metrics["successful_requests"] > 0:
            metrics["avg_latency_ms"] = (
                metrics["total_latency_ms"] / metrics["successful_requests"]
            )
            metrics["avg_tokens_per_request"] = (
                metrics["total_tokens_used"] / metrics["successful_requests"]
            )
        else:
            metrics["avg_latency_ms"] = 0
            metrics["avg_tokens_per_request"] = 0
        
        if metrics["total_requests"] > 0:
            metrics["success_rate"] = (
                metrics["successful_requests"] / metrics["total_requests"]
            )
        else:
            metrics["success_rate"] = 0
        
        metrics["api_key_configured"] = bool(self.api_key)
        
        return metrics
    
    def reset_metrics(self):
        """Сброс метрик"""
        self.metrics = {
            "total_requests": 0,
            "successful_requests": 0,
            "failed_requests": 0,
            "cached_requests": 0,
            "total_tokens_used": 0,
            "total_latency_ms": 0.0,
            "rate_limited_requests": 0,
            "validation_errors": 0,
            "last_error": None,
            "last_success": None,
        }
    
    def print_metrics_summary(self):
        """Вывод сводки метрик в лог"""
        metrics = self.get_metrics()
        
        self.logger.info("=" * 60)
        self.logger.info("🤖 AI UPDATER МЕТРИКИ")
        self.logger.info("=" * 60)
        self.logger.info(f"🔢 Всего запросов: {metrics['total_requests']}")
        self.logger.info(f"✅ Успешных: {metrics['successful_requests']}")
        self.logger.info(f"❌ Ошибок: {metrics['failed_requests']}")
        self.logger.info(f"💾 Из кэша: {metrics['cached_requests']}")
        self.logger.info(f"📈 Success rate: {metrics['success_rate']:.1%}")
        self.logger.info(f"⏱️ Avg latency: {metrics['avg_latency_ms']:.0f} мс")
        self.logger.info(f"🔤 Avg tokens: {metrics['avg_tokens_per_request']:.0f}")
        self.logger.info(f"⏳ Rate limited: {metrics['rate_limited_requests']}")
        self.logger.info(f"⚠️ Validation errors: {metrics['validation_errors']}")
        self.logger.info(f"🔑 API key: {'✅' if metrics['api_key_configured'] else '❌'}")
        self.logger.info("=" * 60)


# ============================================================================
# 🆕 v101.0: ФАБРИКА ДЛЯ ПОЛУЧЕНИЯ ЭКЗЕМПЛЯРА
# ============================================================================
_ai_updater_instance = None


def get_deepseek_rate_updater() -> DeepSeekRateUpdater:
    """Получение глобального экземпляра DeepSeekRateUpdater (singleton)"""
    global _ai_updater_instance
    if _ai_updater_instance is None:
        _ai_updater_instance = DeepSeekRateUpdater()
    return _ai_updater_instance
    

