# ============================================================================
# 🆕 v101.0: ДАТАКЛАСС ДЛЯ РЕЗУЛЬТАТА ЗАГРУЗКИ
# ============================================================================
@dataclass
class TariffLoadResult:
    """Результат загрузки тарифов"""
    success: bool = False
    marketplace: str = ""
    source_used: str = ""
    confidence: float = 0.0
    data: Optional[Dict[str, Any]] = None
    forecast: Optional[Dict[str, Any]] = None
    latency_ms: float = 0.0
    tokens_used: int = 0
    errors: List[str] = field(default_factory=list)
    warnings: List[str] = field(default_factory=list)
    timestamp: datetime = field(default_factory=datetime.now)
    validation_passed: bool = True
    validation_errors: List[str] = field(default_factory=list)
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            "success": self.success,
            "marketplace": self.marketplace,
            "source_used": self.source_used,
            "confidence": self.confidence,
            "data": self.data,
            "forecast": self.forecast,
            "latency_ms": self.latency_ms,
            "tokens_used": self.tokens_used,
            "errors": self.errors,
            "warnings": self.warnings,
            "timestamp": self.timestamp.isoformat(),
            "validation_passed": self.validation_passed,
            "validation_errors": self.validation_errors,
        }


# ============================================================================
# 🆕 v101.0: ОСНОВНОЙ КЛАСС SMART TARIFF LOADER
# ============================================================================
class SmartTariffLoader:
    """
    🧠 УМНАЯ ЗАГРУЗКА ТАРИФОВ С ВЫБОРОМ ИСТОЧНИКА (🆕 v101.0)
    
    Поддерживает 4 режима:
    ✅ API маркетплейса (прямое подключение)
    ✅ AI анализ документации (DeepSeek)
    ✅ Загруженные ранее тарифы (кэш)
    ✅ Гибридный режим (комбинация источников)
    
    Новые возможности v101.0:
    ✅ Интеграция с новым DeepSeekRateUpdater
    ✅ Профилирование через @profile_execution
    ✅ Расширенные метрики по источникам
    ✅ Автоматический выбор лучшего источника
    ✅ Google Sheets экспорт тарифов
    ✅ Rate limiting через PerformanceManager
    ✅ Fallback-стратегия с приоритетами
    ✅ Валидация данных из разных источников
    """
    
    SOURCES = {
        "api": "🔌 API Маркетплейса",
        "ai": "🤖 AI (документация)",
        "cache": "💾 Загруженные ранее",
        "hybrid": "🔄 Гибридный (AI + API)",
    }
    
    def __init__(self):
        self.api_connector = MarketplaceAPIConnector()
        
        # 🆕 v101.0: Используем новый DeepSeekRateUpdater из Блока 18
        try:
            self.ai_updater = get_deepseek_rate_updater()
        except Exception as e:
            logger.warning(f"Не удалось инициализировать DeepSeekRateUpdater: {e}")
            self.ai_updater = DeepSeekRateUpdater()
        
        self.tariff_cache = get_smart_tariff_cache()
        self.logger = logging.getLogger('SmartTariffLoader')
        
        # 🆕 v101.0: Метрики по источникам
        self.source_metrics = {
            "api": {"requests": 0, "success": 0, "errors": 0, "total_latency_ms": 0.0},
            "ai": {"requests": 0, "success": 0, "errors": 0, "total_latency_ms": 0.0, "tokens": 0},
            "cache": {"requests": 0, "hits": 0, "misses": 0},
            "hybrid": {"requests": 0, "success": 0, "errors": 0},
        }
        
        self.logger.info("🧠 SmartTariffLoader v101.0 инициализирован")
    
    # ========================================================================
    # 🆕 v101.0: ГЛАВНЫЙ МЕТОД ЗАГРУЗКИ С ПРОФИЛИРОВАНИЕМ
    # ========================================================================
    @profile_execution(operation_name="load_tariffs", log_slow=True)
    def load_tariffs(
        self,
        marketplace: str,
        source: str = "hybrid",
        api_key: Optional[str] = None,
        client_id: Optional[str] = None,
        force_refresh: bool = False,
        validate: bool = True,
    ) -> TariffLoadResult:
        """
        🆕 v101.0: Загрузка тарифов из выбранного источника с профилированием.
        
        Args:
            marketplace: Название маркетплейса
            source: "api", "ai", "cache", "hybrid"
            api_key: API ключ (для API режима)
            client_id: Client ID (для Ozon)
            force_refresh: Принудительное обновление
            validate: Валидировать данные
        
        Returns:
            TariffLoadResult с полной информацией
        """
        result = TariffLoadResult(
            marketplace=marketplace,
            source_used=source,
        )
        
        start_time = time.perf_counter()
        
        try:
            # 🆕 v101.0: Rate limiting через PerformanceManager
            if PERF_MANAGER_AVAILABLE:
                try:
                    perf_manager = get_performance_manager()
                    perf_manager.check_memory_usage()
                except Exception as e:
                    self.logger.warning(f"Ошибка проверки памяти: {e}")
            
            # 🆕 v101.0: Выбор источника
            if source == "api":
                result = self._load_from_api(marketplace, api_key, client_id, result)
            elif source == "ai":
                result = self._load_from_ai(marketplace, result, force_refresh)
            elif source == "cache":
                result = self._load_from_cache(marketplace, result)
            elif source == "hybrid":
                result = self._load_hybrid(marketplace, api_key, client_id, result, force_refresh)
            else:
                result.errors.append(f"Неизвестный источник: {source}")
                return result
            
            # 🆕 v101.0: Валидация данных
            if validate and result.data:
                validation_result = self._validate_tariffs(result.data)
                result.validation_passed = validation_result["valid"]
                result.validation_errors = validation_result["errors"]
                
                if not result.validation_passed:
                    result.warnings.append(
                        f"⚠️ Обнаружены ошибки валидации: {len(validation_result['errors'])}"
                    )
            
            # 🆕 v101.0: Сохранение в кэш (если успешно)
            if result.success and result.data and source != "cache":
                try:
                    ttl = SMART_TARIFF_CONFIG["cache_ttl"].get(source, 3600)
                    self.tariff_cache.set(
                        marketplace=marketplace,
                        category=None,
                        data=result.data,
                        source=self._source_enum_from_string(result.source_used),
                        ttl_seconds=ttl,
                        notes=f"Загружено через {result.source_used}",
                        forecast_data=result.forecast,
                    )
                    result.warnings.append(f"💾 Сохранено в кэш (TTL: {ttl // 3600} ч)")
                except Exception as e:
                    result.warnings.append(f"⚠️ Не удалось сохранить в кэш: {e}")
            
            # 🆕 v101.0: Обновление метрик
            self._update_metrics(source, result)
            
        except Exception as e:
            self.logger.error(f"Ошибка загрузки тарифов: {e}")
            self.logger.error(traceback.format_exc())
            result.errors.append(str(e))
        
        finally:
            result.latency_ms = (time.perf_counter() - start_time) * 1000
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЗАГРУЗКА ИЗ API
    # ========================================================================
    def _load_from_api(
        self,
        marketplace: str,
        api_key: Optional[str],
        client_id: Optional[str],
        result: TariffLoadResult,
    ) -> TariffLoadResult:
        """Загрузка через официальное API маркетплейса"""
        result.source_used = "API"
        
        try:
            if not api_key:
                result.errors.append("API ключ не указан")
                return result
            
            # 🆕 v101.0: Вызов API с замером времени
            api_start = time.perf_counter()
            
            if marketplace == "Ozon" and client_id:
                data = self.api_connector.get_ozon_tariffs(api_key, client_id)
            elif marketplace == "Wildberries":
                data = self.api_connector.get_wildberries_tariffs(api_key)
            elif marketplace == "Яндекс Маркет":
                # 🆕 v101.0: Получаем список кампаний
                campaigns = self.api_connector.get_yandex_market_campaigns(api_key)
                if campaigns.get("success") and campaigns.get("data"):
                    campaign_list = campaigns["data"].get("campaigns", [])
                    if campaign_list:
                        campaign_id = campaign_list[0].get("id")
                        if campaign_id:
                            data = self.api_connector.get_yandex_market_tariffs(
                                api_key, campaign_id
                            )
                        else:
                            data = None
                    else:
                        data = None
                else:
                    data = None
            else:
                result.errors.append(f"API для {marketplace} не поддерживается")
                return result
            
            api_latency = (time.perf_counter() - api_start) * 1000
            
            if data:
                # 🆕 v101.0: Извлекаем тарифы из сырых данных
                rates = self._extract_rates_from_api_response(marketplace, data)
                
                if rates:
                    result.data = rates
                    result.confidence = 0.95
                    result.warnings.append(f"✅ Тарифы загружены напрямую из API {marketplace}")
                    result.warnings.append(f"⏱️ Latency API: {api_latency:.0f} мс")
                else:
                    result.errors.append("Не удалось извлечь тарифы из ответа API")
            else:
                result.errors.append(f"Не удалось получить данные из API {marketplace}")
        
        except Exception as e:
            result.errors.append(f"Ошибка API: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЗАГРУЗКА ИЗ AI (НОВЫЙ DEEPSEEK)
    # ========================================================================
    def _load_from_ai(
        self,
        marketplace: str,
        result: TariffLoadResult,
        force_refresh: bool,
    ) -> TariffLoadResult:
        """Загрузка через AI анализ документации (новый DeepSeek)"""
        result.source_used = "AI"
        
        try:
            # 🆕 v101.0: Используем новый DeepSeekRateUpdater из Блока 18
            ai_start = time.perf_counter()
            
            rates, source, forecast = self.ai_updater.get_rates_from_ai(
                marketplace=marketplace,
                force_refresh=force_refresh,
                use_cache=True,
                include_forecast=True,
            )
            
            ai_latency = (time.perf_counter() - ai_start) * 1000
            
            if rates:
                result.data = rates
                result.forecast = forecast
                result.source_used = source.value if hasattr(source, 'value') else str(source)
                
                # 🆕 v101.0: Confidence из AI ответа
                result.confidence = rates.get("confidence", 0.85)
                
                result.warnings.append(f"🤖 Тарифы получены через AI анализ документации")
                result.warnings.append(f"⏱️ Latency AI: {ai_latency:.0f} мс")
                
                # 🆕 v101.0: Токены
                tokens = rates.get("tokens_used", 0)
                if tokens:
                    result.tokens_used = tokens
                    result.warnings.append(f"🔤 Использовано токенов: {tokens}")
                
                if forecast:
                    result.warnings.append("📈 Прогноз тарифов на 3 месяца получен")
            else:
                result.errors.append("AI не смог получить актуальные тарифы")
        
        except Exception as e:
            result.errors.append(f"Ошибка AI: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЗАГРУЗКА ИЗ КЭША
    # ========================================================================
    def _load_from_cache(
        self,
        marketplace: str,
        result: TariffLoadResult,
    ) -> TariffLoadResult:
        """Загрузка из кэша (ранее загруженные тарифы)"""
        result.source_used = "Cache"
        
        try:
            cached = self.tariff_cache.get(marketplace, None, use_expired=False)
            
            if cached:
                result.data = cached.data
                result.forecast = cached.forecast_data
                result.confidence = 0.90
                
                timestamp = datetime.fromtimestamp(cached.timestamp)
                age_hours = (datetime.now() - timestamp).total_seconds() / 3600
                
                result.warnings.append(
                    f"💾 Использованы кэшированные тарифы от "
                    f"{timestamp.strftime('%d.%m.%Y %H:%M')} "
                    f"(возраст: {age_hours:.1f} ч)"
                )
            else:
                result.errors.append("Кэшированные тарифы не найдены или устарели")
        
        except Exception as e:
            result.errors.append(f"Ошибка кэша: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ГИБРИДНЫЙ РЕЖИМ С ПРИОРИТЕТАМИ
    # ========================================================================
    def _load_hybrid(
        self,
        marketplace: str,
        api_key: Optional[str],
        client_id: Optional[str],
        result: TariffLoadResult,
        force_refresh: bool,
    ) -> TariffLoadResult:
        """
        🆕 v101.0: Гибридный режим с приоритетами источников.
        
        Приоритеты:
        1. API (если есть ключ) — confidence 0.95
        2. AI (если есть ключ) — confidence 0.85
        3. Cache — confidence 0.90
        4. Hardcoded — confidence 0.50
        """
        result.source_used = "Hybrid"
        result.warnings.append("🔄 Используется гибридный режим загрузки")
        
        # 🆕 v101.0: Пробуем источники в порядке приоритета
        sources_to_try = []
        
        # 1. API (если есть ключ)
        if api_key and marketplace in ["Ozon", "Wildberries", "Яндекс Маркет"]:
            sources_to_try.append(("api", 0.95))
        
        # 2. AI (если есть ключ)
        if self.ai_updater.api_key:
            sources_to_try.append(("ai", 0.85))
        
        # 3. Cache
        sources_to_try.append(("cache", 0.90))
        
        # 4. Hardcoded (всегда доступен)
        sources_to_try.append(("hardcoded", 0.50))
        
        # 🆕 v101.0: Пробуем каждый источник
        for source, expected_confidence in sources_to_try:
            try:
                self.logger.info(f"🔄 Пробуем источник: {source}")
                
                if source == "api":
                    source_result = self._load_from_api(
                        marketplace, api_key, client_id, TariffLoadResult()
                    )
                elif source == "ai":
                    source_result = self._load_from_ai(
                        marketplace, TariffLoadResult(), force_refresh
                    )
                elif source == "cache":
                    source_result = self._load_from_cache(
                        marketplace, TariffLoadResult()
                    )
                elif source == "hardcoded":
                    source_result = self._load_from_hardcoded(marketplace)
                else:
                    continue
                
                # 🆕 v101.0: Проверяем успех и confidence
                if source_result.success and source_result.data:
                    min_conf = SMART_TARIFF_CONFIG["min_confidence"].get(source, 0.50)
                    
                    if source_result.confidence >= min_conf:
                        # ✅ Успех — используем этот источник
                        result.data = source_result.data
                        result.forecast = source_result.forecast
                        result.source_used = f"{source.title()} (Hybrid)"
                        result.confidence = source_result.confidence
                        result.warnings.append(
                            f"✅ Использованы тарифы из {source.title()} "
                            f"(confidence: {source_result.confidence:.0%})"
                        )
                        result.warnings.extend(source_result.warnings)
                        return result
                    else:
                        result.warnings.append(
                            f"⚠️ {source.title()}: confidence {source_result.confidence:.0%} "
                            f"ниже порога {min_conf:.0%}"
                        )
                else:
                    result.warnings.append(
                        f"⚠️ {source.title()}: не удалось загрузить "
                        f"({', '.join(source_result.errors[:2])})"
                    )
            
            except Exception as e:
                result.warnings.append(f"⚠️ {source.title()}: ошибка {str(e)}")
                continue
        
        # 🆕 v101.0: Ни один источник не сработал
        result.errors.append("Не удалось загрузить тарифы ни из одного источника")
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЗАГРУЗКА ИЗ HARDCODED (FALLBACK)
    # ========================================================================
    def _load_from_hardcoded(self, marketplace: str) -> TariffLoadResult:
        """Загрузка из захардкоженных тарифов (fallback)"""
        result = TariffLoadResult(
            marketplace=marketplace,
            source_used="Hardcoded",
        )
        
        try:
            configs = get_marketplace_configs_2026()
            config = configs.get(marketplace)
            
            if not config:
                result.errors.append(f"Маркетплейс {marketplace} не найден в конфигурации")
                return result
            
            # Базовые тарифы из конфигурации
            rates = {
                "commission_rate": config.commission_rate,
                "min_commission": config.min_commission,
                "logistics_base": config.logistics_base,
                "logistics_per_kg": config.logistics_per_kg,
                "logistics_per_liter": config.logistics_per_liter,
                "storage_per_day": config.storage_per_day,
                "return_fee": config.return_fee,
                "acquiring_fee": config.acquiring_fee,
                "last_mile_fee": config.last_mile_fee,
                "delivery_fee_percent": config.delivery_fee_percent,
                "hazardous_surcharge": config.hazardous_surcharge,
                "fragile_surcharge": config.fragile_surcharge,
                "oversized_surcharge": config.oversized_surcharge,
                "seasonal_multipliers": config.seasonal_multipliers,
                "confidence": 0.50,
                "notes": "Fallback: захардкоженные тарифы из конфигурации",
            }
            
            result.data = rates
            result.confidence = 0.50
            result.warnings.append("💾 Использованы захардкоженные тарифы из конфигурации")
        
        except Exception as e:
            result.errors.append(f"Ошибка hardcoded: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ВАЛИДАЦИЯ ТАРИФОВ
    # ========================================================================
    def _validate_tariffs(self, rates: Dict[str, Any]) -> Dict[str, Any]:
        """
        🆕 v101.0: Валидация тарифов по диапазонам.
        
        Returns:
            Dict с результатами валидации
        """
        result = {
            "valid": True,
            "errors": [],
            "warnings": [],
        }
        
        ranges = SMART_TARIFF_CONFIG["validation_ranges"]
        
        for field, (min_val, max_val) in ranges.items():
            if field in rates:
                value = rates[field]
                
                # Проверяем, что это число
                if not isinstance(value, (int, float)):
                    result["errors"].append(f"{field}: не число ({type(value).__name__})")
                    result["valid"] = False
                    continue
                
                # Проверяем диапазон
                if not (min_val <= value <= max_val):
                    result["errors"].append(
                        f"{field}: {value} вне диапазона [{min_val}, {max_val}]"
                    )
                    result["valid"] = False
        
        # 🆕 v101.0: Проверка seasonal_multipliers
        if "seasonal_multipliers" in rates:
            sm = rates["seasonal_multipliers"]
            if isinstance(sm, dict):
                for season in ["winter", "spring", "summer", "autumn"]:
                    if season not in sm:
                        result["warnings"].append(f"Отсутствует сезон: {season}")
                    elif not (0.5 <= sm[season] <= 2.0):
                        result["errors"].append(
                            f"seasonal_multipliers.{season}: {sm[season]} вне диапазона"
                        )
                        result["valid"] = False
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ИЗВЛЕЧЕНИЕ ТАРИФОВ ИЗ API ОТВЕТА
    # ========================================================================
    def _extract_rates_from_api_response(
        self,
        marketplace: str,
        raw_data: Dict[str, Any],
    ) -> Optional[Dict[str, Any]]:
        """
        🆕 v101.0: Извлечение тарифов из сырого ответа API.
        
        Каждый МП имеет свою структуру ответа.
        """
        try:
            if marketplace == "Ozon":
                # Ozon возвращает список тарифов по категориям
                if "result" in raw_data and "items" in raw_data["result"]:
                    items = raw_data["result"]["items"]
                    if items:
                        # Берём первый тариф как базовый
                        item = items[0]
                        return {
                            "commission_rate": item.get("deliverySchema", {}).get("commission", 0.15),
                            "logistics_base": item.get("deliverySchema", {}).get("baseRate", 50.0),
                            "confidence": 0.95,
                            "source": "Ozon API",
                            "raw_data": raw_data,
                        }
            
            elif marketplace == "Wildberries":
                # WB возвращает тарифы коробов
                if "response" in raw_data and "data" in raw_data["response"]:
                    data = raw_data["response"]["data"]
                    if "box" in data:
                        box = data["box"]
                        return {
                            "logistics_base": box.get("deliveryBase", 60.0),
                            "logistics_per_kg": box.get("deliveryVolume", 18.0),
                            "confidence": 0.95,
                            "source": "WB API",
                            "raw_data": raw_data,
                        }
            
            elif marketplace == "Яндекс Маркет":
                # ЯМ возвращает тарифы доставки
                if "deliveries" in raw_data:
                    deliveries = raw_data["deliveries"]
                    if deliveries:
                        delivery = deliveries[0]
                        return {
                            "logistics_base": delivery.get("basePrice", 40.0),
                            "last_mile_fee": delivery.get("lastMilePrice", 35.0),
                            "confidence": 0.95,
                            "source": "Yandex Market API",
                            "raw_data": raw_data,
                        }
            
            return None
        
        except Exception as e:
            self.logger.error(f"Ошибка извлечения тарифов из API: {e}")
            return None
    
    # ========================================================================
    # 🆕 v101.0: ОБНОВЛЕНИЕ МЕТРИК
    # ========================================================================
    def _update_metrics(self, source: str, result: TariffLoadResult):
        """Обновление метрик по источникам"""
        if source not in self.source_metrics:
            return
        
        metrics = self.source_metrics[source]
        metrics["requests"] += 1
        
        if result.success:
            metrics["success"] += 1
        else:
            metrics["errors"] += 1
        
        metrics["total_latency_ms"] += result.latency_ms
        
        if source == "ai":
            metrics["tokens"] += result.tokens_used
    
    # ========================================================================
    # 🆕 v101.0: ПОЛУЧЕНИЕ ДОСТУПНЫХ ИСТОЧНИКОВ
    # ========================================================================
    def get_available_sources(self, marketplace: str) -> List[str]:
        """Получить список доступных источников для маркетплейса"""
        sources = []
        
        # API
        if marketplace in ["Ozon", "Wildberries", "Яндекс Маркет"]:
            sources.append("api")
        
        # AI
        if self.ai_updater.api_key:
            sources.append("ai")
        
        # Cache
        if self.tariff_cache.get(marketplace, None, use_expired=False):
            sources.append("cache")
        
        # Hybrid (всегда доступен)
        sources.append("hybrid")
        
        return sources
    
    # ========================================================================
    # 🆕 v101.0: СРАВНЕНИЕ ИСТОЧНИКОВ
    # ========================================================================
    def compare_sources(
        self,
        marketplace: str,
        api_key: Optional[str] = None,
        client_id: Optional[str] = None,
    ) -> pd.DataFrame:
        """
        🆕 v101.0: Сравнение тарифов из разных источников с confidence score.
        """
        results = []
        
        for source in ["api", "ai", "cache"]:
            if source == "api" and not api_key:
                continue
            
            result = self.load_tariffs(
                marketplace=marketplace,
                source=source,
                api_key=api_key,
                client_id=client_id,
                validate=False,  # Не валидируем при сравнении
            )
            
            if result.success:
                results.append({
                    "Источник": self.SOURCES.get(source, source),
                    "Статус": "✅ Доступен",
                    "Доверие": f"{result.confidence * 100:.0f}%",
                    "Latency": f"{result.latency_ms:.0f} мс",
                    "Токены": result.tokens_used if source == "ai" else "—",
                    "Валидация": "✅" if result.validation_passed else "❌",
                    "Рекомендация": self._get_source_recommendation(source, result.confidence),
                })
            else:
                results.append({
                    "Источник": self.SOURCES.get(source, source),
                    "Статус": "❌ Недоступен",
                    "Доверие": "0%",
                    "Latency": f"{result.latency_ms:.0f} мс",
                    "Токены": "—",
                    "Валидация": "—",
                    "Рекомендация": result.errors[0][:50] if result.errors else "Ошибка",
                })
        
        return pd.DataFrame(results)
    
    def _get_source_recommendation(self, source: str, confidence: float) -> str:
        """Получить рекомендацию по источнику"""
        if confidence >= 0.90:
            return "🏆 Отличный выбор"
        elif confidence >= 0.70:
            return "✅ Хороший выбор"
        elif confidence >= 0.50:
            return "⚠️ Приемлемо"
        else:
            return "❌ Низкое доверие"
    
    # ========================================================================
    # 🆕 v101.0: ЭКСПОРТ В GOOGLE SHEETS
    # ========================================================================
    def export_tariffs_to_sheets(
        self,
        marketplace: str,
        credentials_path: str,
        spreadsheet_title: Optional[str] = None,
        share_email: Optional[str] = None,
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Экспорт тарифов в Google Sheets.
        """
        if not GSPREAD_AVAILABLE:
            return {
                "success": False,
                "error": "gspread не установлен",
            }
        
        try:
            # Получаем текущие тарифы
            configs = get_marketplace_configs_2026()
            config = configs.get(marketplace)
            
            if not config:
                return {
                    "success": False,
                    "error": f"Маркетплейс {marketplace} не найден",
                }
            
            # Формируем DataFrame
            tariff_data = {
                "Параметр": [
                    "Комиссия", "Мин. комиссия", "Логистика база",
                    "Логистика за кг", "Логистика за л", "Хранение",
                    "Эквайринг", "Возвраты", "Последняя миля",
                    "Подписка", "Источник", "Обновлено"
                ],
                "Значение": [
                    f"{config.commission_rate * 100:.1f}%",
                    f"{config.min_commission:.2f} ₽",
                    f"{config.logistics_base:.2f} ₽",
                    f"{config.logistics_per_kg:.2f} ₽",
                    f"{config.logistics_per_liter:.2f} ₽",
                    f"{config.storage_per_day:.2f} ₽/л/день",
                    f"{config.acquiring_fee * 100:.1f}%",
                    f"{config.return_fee * 100:.1f}%",
                    f"{config.last_mile_fee:.2f} ₽",
                    f"{config.subscription_fee:.2f} ₽",
                    config.tariff_source.value if hasattr(config.tariff_source, 'value') else str(config.tariff_source),
                    config.last_updated.strftime('%d.%m.%Y %H:%M') if hasattr(config.last_updated, 'strftime') else str(config.last_updated),
                ],
            }
            
            df = pd.DataFrame(tariff_data)
            
            # Аутентификация
            scopes = [
                "https://www.googleapis.com/auth/spreadsheets",
                "https://www.googleapis.com/auth/drive",
            ]
            creds = Credentials.from_service_account_file(
                credentials_path, scopes=scopes
            )
            gc = gspread.authorize(creds)
            
            # Создаём таблицу
            title = spreadsheet_title or (
                f"Тарифы {marketplace} {datetime.now().strftime('%Y%m%d_%H%M%S')}"
            )
            spreadsheet = gc.create(title)
            
            # Записываем данные
            worksheet = spreadsheet.sheet1
            worksheet.update_title("Тарифы")
            worksheet.update(
                "A1",
                [df.columns.tolist()] + df.values.tolist()
            )
            
            # Форматирование
            worksheet.freeze_rows(1)
            
            # Шаринг
            if share_email:
                spreadsheet.share(share_email, perm_type="user", role="writer")
            
            return {
                "success": True,
                "spreadsheet_id": spreadsheet.id,
                "spreadsheet_url": spreadsheet.url,
            }
        
        except Exception as e:
            self.logger.error(f"Ошибка экспорта в Google Sheets: {e}")
            return {
                "success": False,
                "error": str(e),
            }
    
    # ========================================================================
    # 🆕 v101.0: ПОЛУЧЕНИЕ МЕТОРИК
    # ========================================================================
    def get_metrics(self) -> Dict[str, Any]:
        """Получение метрик по источникам"""
        metrics = {}
        
        for source, data in self.source_metrics.items():
            if data["requests"] > 0:
                success_rate = data["success"] / data["requests"]
                avg_latency = data["total_latency_ms"] / data["requests"]
                
                metrics[source] = {
                    "requests": data["requests"],
                    "success": data["success"],
                    "errors": data["errors"],
                    "success_rate": f"{success_rate:.1%}",
                    "avg_latency_ms": f"{avg_latency:.0f}",
                }
                
                if source == "ai":
                    metrics[source]["tokens"] = data.get("tokens", 0)
        
        return metrics
    
    # ========================================================================
    # 🆕 v101.0: ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
    # ========================================================================
    def _source_enum_from_string(self, source_str: str) -> 'TariffSource':
        """Преобразование строки в TariffSource enum"""
        try:
            from streamlit_app import TariffSource
            
            mapping = {
                "API": TariffSource.API_LIVE,
                "AI": TariffSource.AI_LIVE,
                "Cache": TariffSource.AI_CACHE,
                "Hardcoded": TariffSource.HARDCODED,
            }
            
            return mapping.get(source_str, TariffSource.HARDCODED)
        
        except Exception:
            return "HARDCODED"


