# 🆕 v101.0: ИСТОРИЯ ЗАГРУЗОК ТАРИФОВ
# ============================================================================
class TariffLoadHistory:
    """
    🆕 v101.0: История загрузок тарифов.
    Хранит последние N загрузок с метаданными.
    """
    
    def __init__(self, max_size: int = 50):
        self.max_size = max_size
        self.history = deque(maxlen=max_size)
        self._load_from_file()
    
    def _get_file_path(self) -> Path:
        return CONFIG_DIR / "tariff_load_history.json"
    
    def _load_from_file(self):
        """Загрузка истории из файла"""
        try:
            file_path = self._get_file_path()
            if file_path.exists():
                with open(file_path, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                self.history = deque(data, maxlen=self.max_size)
        except Exception as e:
            logger.warning(f"Не удалось загрузить историю загрузок: {e}")
    
    def _save_to_file(self):
        """Сохранение истории в файл"""
        try:
            file_path = self._get_file_path()
            file_path.parent.mkdir(parents=True, exist_ok=True)
            with open(file_path, 'w', encoding='utf-8') as f:
                json.dump(list(self.history), f, ensure_ascii=False, indent=2)
        except Exception as e:
            logger.warning(f"Не удалось сохранить историю: {e}")
    
    def add_entry(
        self,
        marketplace: str,
        source: str,
        success: bool,
        confidence: float = 0.0,
        latency_ms: float = 0.0,
        tokens_used: int = 0,
        errors: Optional[List[str]] = None,
        warnings: Optional[List[str]] = None,
        rates: Optional[Dict[str, Any]] = None,
    ):
        """Добавление записи в историю"""
        entry = {
            "timestamp": datetime.now().isoformat(),
            "marketplace": marketplace,
            "source": source,
            "success": success,
            "confidence": confidence,
            "latency_ms": latency_ms,
            "tokens_used": tokens_used,
            "errors": errors or [],
            "warnings": warnings or [],
            "rates_snapshot": rates,  # Снимок тарифов для отката
        }
        self.history.append(entry)
        self._save_to_file()
    
    def get_history(self, limit: int = 50) -> List[Dict[str, Any]]:
        """Получение истории"""
        return list(self.history)[-limit:]
    
    def get_last_entry(self, marketplace: str) -> Optional[Dict[str, Any]]:
        """Получение последней записи для МП"""
        for entry in reversed(self.history):
            if entry.get("marketplace") == marketplace and entry.get("success"):
                return entry
        return None
    
    def clear(self):
        """Очистка истории"""
        self.history.clear()
        self._save_to_file()


