# 🆕 v101.0: ВАЛИДАТОР ТАРИФОВ
# ============================================================================
class TariffValidator:
    """
    🆕 v101.0: Валидатор тарифов перед применением.
    Проверяет диапазоны значений и обязательные поля.
    """
    
    @staticmethod
    def validate(rates: Dict[str, Any]) -> Dict[str, Any]:
        """
        Валидация тарифов.
        
        Returns:
            Dict с результатами:
            {
                "valid": bool,
                "errors": List[str],
                "warnings": List[str],
            }
        """
        result = {
            "valid": True,
            "errors": [],
            "warnings": [],
        }
        
        ranges = TARIFF_UI_CONSTANTS["validation_ranges"]
        
        # Обязательные поля
        required_fields = [
            "commission_rate", "logistics_base", "logistics_per_kg",
            "storage_per_day", "return_fee", "acquiring_fee"
        ]
        
        for field in required_fields:
            if field not in rates:
                result["errors"].append(f"❌ Отсутствует поле: {field}")
                result["valid"] = False
        
        # Проверка диапазонов
        for field, (min_val, max_val) in ranges.items():
            if field in rates:
                value = rates[field]
                
                if not isinstance(value, (int, float)):
                    result["errors"].append(
                        f"❌ {field}: не число ({type(value).__name__})"
                    )
                    result["valid"] = False
                    continue
                
                if not (min_val <= value <= max_val):
                    result["errors"].append(
                        f"❌ {field}: {value} вне диапазона [{min_val}, {max_val}]"
                    )
                    result["valid"] = False
        
        # Предупреждения
        if "commission_rate" in rates and rates["commission_rate"] > 0.30:
            result["warnings"].append(
                f"⚠️ Комиссия {rates['commission_rate']*100:.1f}% выше 30% — проверьте"
            )
        
        if "return_fee" in rates and rates["return_fee"] > 0.20:
            result["warnings"].append(
                f"⚠️ Возвраты {rates['return_fee']*100:.1f}% выше 20% — проверьте"
            )
        
        # Проверка seasonal_multipliers
        if "seasonal_multipliers" in rates:
            sm = rates["seasonal_multipliers"]
            if isinstance(sm, dict):
                for season in ["winter", "spring", "summer", "autumn"]:
                    if season not in sm:
                        result["warnings"].append(f"⚠️ Отсутствует сезон: {season}")
                    elif not (0.5 <= sm[season] <= 2.0):
                        result["errors"].append(
                            f"❌ seasonal_multipliers.{season}: {sm[season]} вне диапазона"
                        )
                        result["valid"] = False
        
        return result


