logger = logging.getLogger(__name__)


# ============================================================================
# 🆕 v101.0: КОНСТАНТЫ БЛОКА 21
# ============================================================================
CATEGORY_DB_CONFIG = {
    # Лимиты
    "max_categories": 10000,
    "max_name_length": 100,
    "min_dimension": 0.01,
    "max_dimension": 10000.0,
    
    # Валидация
    "default_tolerance_percent": 20.0,
    "strict_tolerance_percent": 10.0,
    
    # Google Sheets
    "google_sheets_batch_size": 5000,
    
    # ABC-анализ
    "abc_a_threshold": 0.80,
    "abc_b_threshold": 0.95,
}


# ============================================================================
# 🆕 v101.0: ДАТАКЛАСС ДЛЯ КАТЕГОРИИ С РАСШИРЕННЫМИ ПОЛЯМИ
# ============================================================================
@dataclass
class CategoryRecord:
    """🆕 v101.0: Расширенная запись категории"""
    name: str
    length_cm: float
    width_cm: float
    height_cm: float
    weight_kg: float
    unit: str = "см"
    weight_unit: str = "кг"
    
    # 🆕 v101.0: Тип товара по умолчанию
    product_origin_default: str = "analog_standard"
    
    # 🆕 v101.0: Сезонные коэффициенты (12 месяцев)
    seasonality_demand: List[float] = field(
        default_factory=lambda: [1.0] * 12
    )
    
    # 🆕 v101.0: Базовые параметры
    return_rate_base: float = 0.05
    drr_base: float = 0.15
    avg_price: float = 0.0
    avg_margin: float = 0.0
    
    # 🆕 v101.0: Метаданные
    added_at: str = field(default_factory=lambda: datetime.now().isoformat())
    updated_at: Optional[str] = None
    source: str = "manual"  # manual, excel, google_sheets, ai
    notes: str = ""
    
    # 🆕 v101.0: ABC-класс (рассчитывается автоматически)
    abc_class: Optional[str] = None
    profit_share: float = 0.0
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "length_cm": self.length_cm,
            "width_cm": self.width_cm,
            "height_cm": self.height_cm,
            "weight_kg": self.weight_kg,
            "unit": self.unit,
            "weight_unit": self.weight_unit,
            "product_origin_default": self.product_origin_default,
            "seasonality_demand": self.seasonality_demand,
            "return_rate_base": self.return_rate_base,
            "drr_base": self.drr_base,
            "avg_price": self.avg_price,
            "avg_margin": self.avg_margin,
            "added_at": self.added_at,
            "updated_at": self.updated_at,
            "source": self.source,
            "notes": self.notes,
            "abc_class": self.abc_class,
            "profit_share": self.profit_share,
        }
    
    @staticmethod
    def from_dict(d: Dict[str, Any]) -> 'CategoryRecord':
        return CategoryRecord(
            name=d.get("name", ""),
            length_cm=float(d.get("length_cm", 0)),
            width_cm=float(d.get("width_cm", 0)),
            height_cm=float(d.get("height_cm", 0)),
            weight_kg=float(d.get("weight_kg", 0)),
            unit=d.get("unit", "см"),
            weight_unit=d.get("weight_unit", "кг"),
            product_origin_default=d.get("product_origin_default", "analog_standard"),
            seasonality_demand=d.get("seasonality_demand", [1.0] * 12),
            return_rate_base=float(d.get("return_rate_base", 0.05)),
            drr_base=float(d.get("drr_base", 0.15)),
            avg_price=float(d.get("avg_price", 0)),
            avg_margin=float(d.get("avg_margin", 0)),
            added_at=d.get("added_at", datetime.now().isoformat()),
            updated_at=d.get("updated_at"),
            source=d.get("source", "manual"),
            notes=d.get("notes", ""),
            abc_class=d.get("abc_class"),
            profit_share=float(d.get("profit_share", 0)),
        )
    
    def get_volume_liters(self) -> float:
        """Расчёт объёма в литрах"""
        return (self.length_cm * self.width_cm * self.height_cm) / 1000.0
    
    def get_demand_coefficient(self, month: int) -> float:
        """🆕 v101.0: Получить коэффициент спроса для месяца (1-12)"""
        if 1 <= month <= 12 and len(self.seasonality_demand) >= month:
            return self.seasonality_demand[month - 1]
        return 1.0
    
    def get_peak_month(self) -> int:
        """🆕 v101.0: Получить месяц с максимальным спросом"""
        if not self.seasonality_demand:
            return 1
        return self.seasonality_demand.index(max(self.seasonality_demand)) + 1
    
    def get_low_month(self) -> int:
        """🆕 v101.0: Получить месяц с минимальным спросом"""
        if not self.seasonality_demand:
            return 1
        return self.seasonality_demand.index(min(self.seasonality_demand)) + 1


# ============================================================================
# 🆕 v101.0: ОСНОВНОЙ КЛАСС БАЗЫ ДАННЫХ КАТЕГОРИЙ
# ============================================================================
class CategoryDimensionsDB:
    """
    📊 База данных категорий с весогабаритами (🆕 v101.0)
    
    Новые возможности:
    ✅ Интеграция с валидатором (Блок 12)
    ✅ Google Sheets импорт/экспорт
    ✅ Сезонные коэффициенты
    ✅ Типы товаров (оригинал/аналог/Китай)
    ✅ Массовая валидация каталога
    ✅ ABC-анализ категорий
    ✅ Конфликт-детектор
    """
    
    def __init__(self):
        self.db_path = DATA_DIR / "category_dimensions_v101.json"
        self.db_path.parent.mkdir(exist_ok=True, parents=True)
        self.categories: Dict[str, CategoryRecord] = {}
        self._load_from_file()
        self.logger = logging.getLogger('CategoryDimensionsDB')
        
        # 🆕 v101.0: Метрики
        self.metrics = {
            "total_categories": len(self.categories),
            "imported_from_excel": 0,
            "imported_from_sheets": 0,
            "added_manually": 0,
            "validated_count": 0,
            "conflicts_detected": 0,
        }
        
        self.logger.info(f"📊 CategoryDimensionsDB v101.0 инициализирован: {len(self.categories)} категорий")
    
    # ========================================================================
    # 🆕 v101.0: ЗАГРУЗКА/СОХРАНЕНИЕ
    # ========================================================================
    def _load_from_file(self):
        """Загрузка из JSON файла"""
        if self.db_path.exists():
            try:
                with open(self.db_path, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                
                # 🆕 v101.0: Поддержка старого и нового формата
                self.categories = {}
                for key, value in data.items():
                    if isinstance(value, dict) and "name" in value:
                        # Новый формат (CategoryRecord)
                        self.categories[key] = CategoryRecord.from_dict(value)
                    else:
                        # Старый формат (простой словарь)
                        self.categories[key] = CategoryRecord(
                            name=value.get("name", key),
                            length_cm=float(value.get("length_cm", 0)),
                            width_cm=float(value.get("width_cm", 0)),
                            height_cm=float(value.get("height_cm", 0)),
                            weight_kg=float(value.get("weight_kg", 0)),
                            unit=value.get("unit", "см"),
                            weight_unit=value.get("weight_unit", "кг"),
                            added_at=value.get("added_at", datetime.now().isoformat()),
                        )
                
                self.logger.info(f"✅ Загружено {len(self.categories)} категорий из файла")
            except Exception as e:
                self.logger.error(f"❌ Ошибка загрузки: {e}")
                self.categories = {}
    
    def save_to_file(self) -> bool:
        """Сохранение в JSON файл"""
        try:
            data = {k: v.to_dict() for k, v in self.categories.items()}
            with open(self.db_path, 'w', encoding='utf-8') as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            self.logger.info(f"✅ Сохранено {len(self.categories)} категорий")
            return True
        except Exception as e:
            self.logger.error(f"❌ Ошибка сохранения: {e}")
            return False
    
    # ========================================================================
    # 🆕 v101.0: БАЗОВЫЕ ОПЕРАЦИИ
    # ========================================================================
    def add_category(self, record: CategoryRecord) -> bool:
        """🆕 v101.0: Добавление категории с валидацией"""
        # Валидация
        if not record.name or len(record.name) > CATEGORY_DB_CONFIG["max_name_length"]:
            self.logger.error(f"❌ Некорректное название: {record.name}")
            return False
        
        if not all([
            CATEGORY_DB_CONFIG["min_dimension"] <= record.length_cm <= CATEGORY_DB_CONFIG["max_dimension"],
            CATEGORY_DB_CONFIG["min_dimension"] <= record.width_cm <= CATEGORY_DB_CONFIG["max_dimension"],
            CATEGORY_DB_CONFIG["min_dimension"] <= record.height_cm <= CATEGORY_DB_CONFIG["max_dimension"],
            CATEGORY_DB_CONFIG["min_dimension"] <= record.weight_kg <= CATEGORY_DB_CONFIG["max_dimension"],
        ]):
            self.logger.error(f"❌ Некорректные размеры для {record.name}")
            return False
        
        # Проверка на дубликаты
        key = record.name.lower().strip()
        if key in self.categories:
            self.logger.warning(f"⚠️ Категория '{record.name}' уже существует, обновляем")
            record.updated_at = datetime.now().isoformat()
        
        self.categories[key] = record
        self.metrics["total_categories"] = len(self.categories)
        self.save_to_file()
        
        return True
    
    def get_category(self, name: str) -> Optional[CategoryRecord]:
        """Получение категории по названию"""
        return self.categories.get(name.lower().strip())
    
    def get_all_categories(self) -> Dict[str, CategoryRecord]:
        """Получение всех категорий"""
        return self.categories.copy()
    
    def delete_category(self, name: str) -> bool:
        """Удаление категории"""
        key = name.lower().strip()
        if key in self.categories:
            del self.categories[key]
            self.metrics["total_categories"] = len(self.categories)
            self.save_to_file()
            return True
        return False
    
    def clear_all(self):
        """Очистка всех категорий"""
        self.categories = {}
        self.metrics["total_categories"] = 0
        self.save_to_file()
    
    # ========================================================================
    # 🆕 v101.0: ИМПОРТ ИЗ EXCEL (РАСШИРЕННЫЙ)
    # ========================================================================
    def import_from_excel(self, file_path: str) -> Dict[str, Any]:
        """
        🆕 v101.0: Импорт категорий из Excel файла с расширенными полями
        
        Ожидаемые колонки:
        - Категория (обязательно)
        - Длина (см)
        - Ширина (см)
        - Высота (см)
        - Вес (кг)
        - Тип товара (опционально)
        - Возвраты % (опционально)
        - ДРР % (опционально)
        - Средняя цена (опционально)
        - Средняя маржа % (опционально)
        - Сезон Янв...Сен (опционально)
        """
        result = {
            "success": False,
            "imported": 0,
            "errors": [],
            "warnings": [],
            "by_origin": {},
        }
        
        try:
            df = pd.read_excel(file_path, engine='openpyxl')
            if df.empty:
                result["errors"].append("Файл пустой")
                return result
            
            # Нормализация названий колонок
            df.columns = [col.strip().lower() for col in df.columns]
            
            # Маппинг колонок
            column_mapping = {
                'категория': 'category', 'category': 'category',
                'название': 'category', 'name': 'category',
                'длина': 'length', 'length': 'length',
                'длина (см)': 'length',
                'ширина': 'width', 'width': 'width',
                'ширина (см)': 'width',
                'высота': 'height', 'height': 'height',
                'высота (см)': 'height',
                'вес': 'weight', 'weight': 'weight',
                'вес (кг)': 'weight',
                'единица длины': 'length_unit',
                'единица веса': 'weight_unit',
                # 🆕 v101.0: Новые колонки
                'тип товара': 'product_origin',
                'product_origin': 'product_origin',
                'происхождение': 'product_origin',
                'возвраты %': 'return_rate',
                'return_rate': 'return_rate',
                'дрр %': 'drr',
                'drr': 'drr',
                'средняя цена': 'avg_price',
                'avg_price': 'avg_price',
                'средняя маржа %': 'avg_margin',
                'avg_margin': 'avg_margin',
            }
            
            df = df.rename(columns=column_mapping)
            
            # 🆕 v101.0: Маппинг сезонных колонок
            month_names = {
                'янв': 0, 'фев': 1, 'мар': 2, 'апр': 3, 'май': 4, 'июн': 5,
                'июл': 6, 'авг': 7, 'сен': 8, 'окт': 9, 'ноя': 10, 'дек': 11,
                'jan': 0, 'feb': 1, 'mar': 2, 'apr': 3, 'may': 4, 'jun': 5,
                'jul': 6, 'aug': 7, 'sep': 8, 'oct': 9, 'nov': 10, 'dec': 11,
            }
            
            seasonality_columns = {}
            for col in df.columns:
                for month_key, month_idx in month_names.items():
                    if month_key in col:
                        seasonality_columns[col] = month_idx
                        break
            
            # Проверка обязательных колонок
            required_cols = ['category', 'length', 'width', 'height', 'weight']
            missing_cols = [col for col in required_cols if col not in df.columns]
            if missing_cols:
                result["errors"].append(f"Отсутствуют колонки: {', '.join(missing_cols)}")
                return result
            
            # Импорт данных
            imported_count = 0
            origin_counts = {}
            
            for idx, row in df.iterrows():
                try:
                    category_name = str(row.get('category', '')).strip()
                    if not category_name:
                        result["warnings"].append(f"Строка {idx + 1}: пустое название")
                        continue
                    
                    length = safe_float(row.get('length', 0))
                    width = safe_float(row.get('width', 0))
                    height = safe_float(row.get('height', 0))
                    weight = safe_float(row.get('weight', 0))
                    
                    if length <= 0 or width <= 0 or height <= 0 or weight <= 0:
                        result["warnings"].append(
                            f"Строка {idx + 1}: некорректные размеры для '{category_name}'"
                        )
                        continue
                    
                    # 🆕 v101.0: Тип товара
                    product_origin = str(row.get('product_origin', 'analog_standard')).strip()
                    if product_origin not in [
                        'original', 'analog_premium', 'analog_standard',
                        'analog_budget', 'china', 'remanufactured', 'used'
                    ]:
                        product_origin = 'analog_standard'
                    
                    # 🆕 v101.0: Базовые параметры
                    return_rate = safe_float(row.get('return_rate', 5)) / 100.0
                    drr = safe_float(row.get('drr', 15)) / 100.0
                    avg_price = safe_float(row.get('avg_price', 0))
                    avg_margin = safe_float(row.get('avg_margin', 0))
                    
                    # 🆕 v101.0: Сезонные коэффициенты
                    seasonality = [1.0] * 12
                    for col, month_idx in seasonality_columns.items():
                        value = safe_float(row.get(col, 1.0))
                        if 0.1 <= value <= 5.0:
                            seasonality[month_idx] = value
                    
                    # Единицы измерения
                    length_unit = str(row.get('length_unit', 'см')).strip()
                    weight_unit = str(row.get('weight_unit', 'кг')).strip()
                    
                    record = CategoryRecord(
                        name=category_name,
                        length_cm=length,
                        width_cm=width,
                        height_cm=height,
                        weight_kg=weight,
                        unit=length_unit,
                        weight_unit=weight_unit,
                        product_origin_default=product_origin,
                        seasonality_demand=seasonality,
                        return_rate_base=return_rate,
                        drr_base=drr,
                        avg_price=avg_price,
                        avg_margin=avg_margin,
                        source="excel",
                    )
                    
                    if self.add_category(record):
                        imported_count += 1
                        origin_counts[product_origin] = origin_counts.get(product_origin, 0) + 1
                    else:
                        result["errors"].append(f"Строка {idx + 1}: не удалось добавить '{category_name}'")
                
                except Exception as e:
                    result["errors"].append(f"Строка {idx + 1}: {str(e)}")
            
            result["success"] = imported_count > 0
            result["imported"] = imported_count
            result["by_origin"] = origin_counts
            self.metrics["imported_from_excel"] += imported_count
            
            if imported_count == 0:
                result["errors"].append("Не удалось импортировать ни одну категорию")
        
        except Exception as e:
            result["errors"].append(f"Ошибка чтения файла: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ИМПОРТ ИЗ GOOGLE SHEETS
    # ========================================================================
    def import_from_google_sheets(
        self,
        credentials_path: str,
        spreadsheet_id: str,
        sheet_name: str = "Категории"
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Импорт категорий из Google Sheets
        
        Args:
            credentials_path: Путь к JSON credentials
            spreadsheet_id: ID таблицы
            sheet_name: Название листа
        """
        result = {
            "success": False,
            "imported": 0,
            "errors": [],
            "warnings": [],
        }
        
        if not GSPREAD_AVAILABLE:
            result["errors"].append("gspread не установлен")
            return result
        
        try:
            # Аутентификация
            scopes = [
                "https://www.googleapis.com/auth/spreadsheets",
                "https://www.googleapis.com/auth/drive.readonly",
            ]
            creds = Credentials.from_service_account_file(
                credentials_path, scopes=scopes
            )
            gc = gspread.authorize(creds)
            
            # Открываем таблицу
            spreadsheet = gc.open_by_key(spreadsheet_id)
            worksheet = spreadsheet.worksheet(sheet_name)
            
            # Получаем данные
            data = worksheet.get_all_records()
            
            if not data:
                result["errors"].append("Лист пустой")
                return result
            
            # Конвертируем в DataFrame
            df = pd.DataFrame(data)
            
            # Нормализация названий колонок
            df.columns = [col.strip().lower() for col in df.columns]
            
            # Маппинг колонок (как в import_from_excel)
            column_mapping = {
                'категория': 'category', 'category': 'category',
                'длина': 'length', 'length': 'length',
                'ширина': 'width', 'width': 'width',
                'высота': 'height', 'height': 'height',
                'вес': 'weight', 'weight': 'weight',
                'тип товара': 'product_origin',
                'product_origin': 'product_origin',
            }
            df = df.rename(columns=column_mapping)
            
            # Проверка обязательных колонок
            required_cols = ['category', 'length', 'width', 'height', 'weight']
            missing_cols = [col for col in required_cols if col not in df.columns]
            if missing_cols:
                result["errors"].append(f"Отсутствуют колонки: {', '.join(missing_cols)}")
                return result
            
            # Импорт данных
            imported_count = 0
            for idx, row in df.iterrows():
                try:
                    category_name = str(row.get('category', '')).strip()
                    if not category_name:
                        continue
                    
                    length = safe_float(row.get('length', 0))
                    width = safe_float(row.get('width', 0))
                    height = safe_float(row.get('height', 0))
                    weight = safe_float(row.get('weight', 0))
                    
                    if length <= 0 or width <= 0 or height <= 0 or weight <= 0:
                        continue
                    
                    product_origin = str(row.get('product_origin', 'analog_standard')).strip()
                    
                    record = CategoryRecord(
                        name=category_name,
                        length_cm=length,
                        width_cm=width,
                        height_cm=height,
                        weight_kg=weight,
                        product_origin_default=product_origin,
                        source="google_sheets",
                    )
                    
                    if self.add_category(record):
                        imported_count += 1
                
                except Exception as e:
                    result["warnings"].append(f"Строка {idx + 1}: {str(e)}")
            
            result["success"] = imported_count > 0
            result["imported"] = imported_count
            self.metrics["imported_from_sheets"] += imported_count
            
            if imported_count == 0:
                result["errors"].append("Не удалось импортировать ни одну категорию")
        
        except Exception as e:
            result["errors"].append(f"Ошибка Google Sheets: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЭКСПОРТ В GOOGLE SHEETS
    # ========================================================================
    def export_to_google_sheets(
        self,
        credentials_path: str,
        spreadsheet_title: Optional[str] = None,
        share_email: Optional[str] = None
    ) -> Dict[str, Any]:
        """🆕 v101.0: Экспорт категорий в Google Sheets"""
        result = {
            "success": False,
            "spreadsheet_url": None,
            "rows_written": 0,
            "errors": [],
        }
        
        if not GSPREAD_AVAILABLE:
            result["errors"].append("gspread не установлен")
            return result
        
        if not self.categories:
            result["errors"].append("Нет категорий для экспорта")
            return result
        
        try:
            # Формируем DataFrame
            data = []
            for key, cat in self.categories.items():
                row = {
                    'Категория': cat.name,
                    'Длина (см)': cat.length_cm,
                    'Ширина (см)': cat.width_cm,
                    'Высота (см)': cat.height_cm,
                    'Вес (кг)': cat.weight_kg,
                    'Тип товара': cat.product_origin_default,
                    'Возвраты %': cat.return_rate_base * 100,
                    'ДРР %': cat.drr_base * 100,
                    'Средняя цена': cat.avg_price,
                    'Средняя маржа %': cat.avg_margin,
                    'ABC класс': cat.abc_class or '',
                    'Пик спроса (месяц)': cat.get_peak_month(),
                    'Мин. спрос (месяц)': cat.get_low_month(),
                }
                data.append(row)
            
            df = pd.DataFrame(data)
            
            # Аутентификация
            scopes = [
                "https://www.googleapis.com/auth/spreadsheets",
                "https://www.googleapis.com/auth/drive",
            ]
            creds = Credentials.from_service_account_file(
                credentials_path, scopes=scopes
            )
            gc = gspread.authorize(creds)
            
            # Создаём таблицу
            title = spreadsheet_title or (
                f"Категории {datetime.now().strftime('%Y%m%d_%H%M%S')}"
            )
            spreadsheet = gc.create(title)
            
            # Записываем данные
            worksheet = spreadsheet.sheet1
            worksheet.update_title("Категории")
            
            values = [df.columns.tolist()] + df.values.tolist()
            worksheet.update("A1", values)
            
            # Форматирование
            worksheet.freeze_rows(1)
            
            # Шаринг
            if share_email:
                spreadsheet.share(share_email, perm_type="user", role="writer")
            
            result["success"] = True
            result["spreadsheet_url"] = spreadsheet.url
            result["rows_written"] = len(df)
            
            self.logger.info(f"✅ Экспорт в Google Sheets завершён: {spreadsheet.url}")
        
        except Exception as e:
            result["errors"].append(f"Ошибка экспорта: {str(e)}")
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: ЭКСПОРТ В EXCEL
    # ========================================================================
    def export_to_excel(self, file_path: str) -> bool:
        """Экспорт категорий в Excel"""
        try:
            data = []
            for key, cat in self.categories.items():
                row = {
                    'Категория': cat.name,
                    'Длина (см)': cat.length_cm,
                    'Ширина (см)': cat.width_cm,
                    'Высота (см)': cat.height_cm,
                    'Вес (кг)': cat.weight_kg,
                    'Единица длины': cat.unit,
                    'Единица веса': cat.weight_unit,
                    'Тип товара': cat.product_origin_default,
                    'Возвраты %': cat.return_rate_base * 100,
                    'ДРР %': cat.drr_base * 100,
                    'Средняя цена': cat.avg_price,
                    'Средняя маржа %': cat.avg_margin,
                    'ABC класс': cat.abc_class or '',
                }
                data.append(row)
            
            df = pd.DataFrame(data)
            df.to_excel(file_path, index=False, engine='openpyxl')
            return True
        except Exception as e:
            self.logger.error(f"Ошибка экспорта: {e}")
            return False
    
    # ========================================================================
    # 🆕 v101.0: ВАЛИДАЦИЯ С ИСПОЛЬЗОВАНИЕМ БЛОКА 12
    # ========================================================================
    def validate_dimensions(
        self,
        length: float,
        width: float,
        height: float,
        weight: float,
        category: str,
        tolerance_percent: float = 20.0
    ) -> Dict[str, Any]:
        """
        🆕 v101.0: Валидация весогабаритов с использованием базы категорий
        
        Интеграция с AdvancedDimensionsValidator (Блок 12)
        """
        result = {
            "valid": True,
            "category": category,
            "deviations": [],
            "warnings": [],
            "recommendations": [],
        }
        
        category_record = self.get_category(category)
        
        if not category_record:
            result["warnings"].append(f"⚠️ Категория '{category}' не найдена в базе")
            
            # 🆕 v101.0: Используем эвристику из Блока 12
            try:
                inferred = AdvancedDimensionsValidator.infer_missing_dimensions(
                    category, weight
                )
                result["recommendations"].append(
                    f"💡 Рекомендуемые габариты: "
                    f"{inferred['length_cm']:.1f}x{inferred['width_cm']:.1f}x{inferred['height_cm']:.1f} см"
                )
            except Exception:
                pass
            
            return result
        
        # Проверяем отклонения
        checks = [
            ("Длина", length, category_record.length_cm),
            ("Ширина", width, category_record.width_cm),
            ("Высота", height, category_record.height_cm),
            ("Вес", weight, category_record.weight_kg),
        ]
        
        for param_name, actual, expected in checks:
            if expected > 0:
                deviation = abs(actual - expected) / expected * 100
                if deviation > tolerance_percent:
                    result["deviations"].append({
                        "parameter": param_name,
                        "actual": actual,
                        "expected": expected,
                        "deviation_percent": deviation,
                    })
                    result["valid"] = False
        
        if result["valid"]:
            result["warnings"].append("✅ Все параметры в пределах нормы")
        else:
            result["recommendations"].append(
                f"💡 Рекомендуемые габариты: "
                f"{category_record.length_cm:.1f}x{category_record.width_cm:.1f}x"
                f"{category_record.height_cm:.1f} см, {category_record.weight_kg:.2f} кг"
            )
        
        self.metrics["validated_count"] += 1
        
        return result
    
    # ========================================================================
    # 🆕 v101.0: МАССОВАЯ ВАЛИДАЦИЯ КАТАЛОГА
    # ========================================================================
    def validate_catalog_batch(
        self,
        df: pd.DataFrame,
        length_col: str = "Длина",
        width_col: str = "Ширина",
        height_col: str = "Высота",
        weight_col: str = "Вес",
        category_col: str = "Категория",
        tolerance_percent: float = 20.0
    ) -> pd.DataFrame:
        """
        🆕 v101.0: Массовая валидация каталога
        
        Returns:
            DataFrame с результатами валидации
        """
        results = []
        
        for idx, row in df.iterrows():
            try:
                length = safe_float(row.get(length_col, 0))
                width = safe_float(row.get(width_col, 0))
                height = safe_float(row.get(height_col, 0))
                weight = safe_float(row.get(weight_col, 0))
                category = str(row.get(category_col, ""))
                
                validation = self.validate_dimensions(
                    length=length,
                    width=width,
                    height=height,
                    weight=weight,
                    category=category,
                    tolerance_percent=tolerance_percent,
                )
                
                result_dict = {
                    "index": idx,
                    "Артикул": row.get("Артикул", ""),
                    "Категория": category,
                    "Валидно": validation["valid"],
                    "Отклонений": len(validation["deviations"]),
                    "Предупреждений": len(validation["warnings"]),
                }
                
                # Добавляем детали отклонений
                if validation["deviations"]:
                    for i, dev in enumerate(validation["deviations"][:3]):
                        result_dict[f"Отклонение_{i+1}"] = (
                            f"{dev['parameter']}: {dev['actual']:.2f} vs {dev['expected']:.2f} "
                            f"({dev['deviation_percent']:.1f}%)"
                        )
                
                results.append(result_dict)
            
            except Exception as e:
                results.append({
                    "index": idx,
                    "Валидно": False,
                    "Ошибка": str(e),
                })
        
        return pd.DataFrame(results)
    
    # ========================================================================
    # 🆕 v101.0: ABC-АНАЛИЗ КАТЕГОРИЙ
    # ========================================================================
    def analyze_abc_by_profit(self, profit_by_category: Dict[str, float]) -> Dict[str, Any]:
        """
        🆕 v101.0: ABC-анализ категорий по прибыли
        
        Args:
            profit_by_category: Dict {категория: прибыль}
        
        Returns:
            Dict с результатами ABC-анализа
        """
        if not profit_by_category:
            return {"success": False, "error": "Нет данных о прибыли"}
        
        # Сортируем по прибыли (убывание)
        sorted_cats = sorted(
            profit_by_category.items(),
            key=lambda x: x[1],
            reverse=True
        )
        
        total_profit = sum(profit_by_category.values())
        
        if total_profit <= 0:
            return {"success": False, "error": "Общая прибыль <= 0"}
        
        # Назначаем ABC-классы
        cumulative = 0
        for cat_name, profit in sorted_cats:
            cumulative += profit
            share = cumulative / total_profit
            
            if share <= CATEGORY_DB_CONFIG["abc_a_threshold"]:
                abc_class = "A"
            elif share <= CATEGORY_DB_CONFIG["abc_b_threshold"]:
                abc_class = "B"
            else:
                abc_class = "C"
            
            # Обновляем запись категории
            if cat_name.lower().strip() in self.categories:
                self.categories[cat_name.lower().strip()].abc_class = abc_class
                self.categories[cat_name.lower().strip()].profit_share = profit / total_profit
        
        self.save_to_file()
        
        # Статистика
        class_counts = {"A": 0, "B": 0, "C": 0}
        class_profits = {"A": 0.0, "B": 0.0, "C": 0.0}
        
        for cat_name, profit in sorted_cats:
            key = cat_name.lower().strip()
            if key in self.categories and self.categories[key].abc_class:
                abc = self.categories[key].abc_class
                class_counts[abc] += 1
                class_profits[abc] += profit
        
        return {
            "success": True,
            "total_categories": len(sorted_cats),
            "total_profit": total_profit,
            "class_counts": class_counts,
            "class_profits": class_profits,
            "class_shares": {
                "A": class_profits["A"] / total_profit if total_profit > 0 else 0,
                "B": class_profits["B"] / total_profit if total_profit > 0 else 0,
                "C": class_profits["C"] / total_profit if total_profit > 0 else 0,
            },
        }
    
    # ========================================================================
    # 🆕 v101.0: КОНФЛИКТ-ДЕТЕКТОР
    # ========================================================================
    def detect_conflicts(self) -> List[Dict[str, Any]]:
        """
        🆕 v101.0: Выявление конфликтов в данных категорий
        
        Проверяет:
        - Противоречия в типах товаров
        - Аномальные габариты
        - Отсутствующие сезонные коэффициенты
        """
        conflicts = []
        
        for key, cat in self.categories.items():
            # Проверка 1: Аномальные габариты
            volume = cat.get_volume_liters()
            if volume > 1000:  # Более 1 кубометра
                conflicts.append({
                    "category": cat.name,
                    "type": "аномальный_объём",
                    "severity": "warning",
                    "message": f"Объём {volume:.1f} л — проверьте габариты",
                })
            
            # Проверка 2: Вес > 100 кг
            if cat.weight_kg > 100:
                conflicts.append({
                    "category": cat.name,
                    "type": "аномальный_вес",
                    "severity": "warning",
                    "message": f"Вес {cat.weight_kg:.1f} кг — проверьте",
                })
            
            # Проверка 3: Отсутствующие сезонные коэффициенты
            if all(c == 1.0 for c in cat.seasonality_demand):
                conflicts.append({
                    "category": cat.name,
                    "type": "нет_сезонности",
                    "severity": "info",
                    "message": "Все коэффициенты = 1.0 — сезонность не задана",
                })
            
            # Проверка 4: Возвраты > 30%
            if cat.return_rate_base > 0.30:
                conflicts.append({
                    "category": cat.name,
                    "type": "высокие_возвраты",
                    "severity": "warning",
                    "message": f"Возвраты {cat.return_rate_base*100:.1f}% — проверьте",
                })
            
            # Проверка 5: ДРР > 40%
            if cat.drr_base > 0.40:
                conflicts.append({
                    "category": cat.name,
                    "type": "высокий_дрр",
                    "severity": "warning",
                    "message": f"ДРР {cat.drr_base*100:.1f}% — проверьте",
                })
        
        self.metrics["conflicts_detected"] = len(conflicts)
        
        return conflicts
    
    # ========================================================================
    # 🆕 v101.0: СТАТИСТИКА (РАСШИРЕННАЯ)
    # ========================================================================
    def get_statistics(self) -> Dict[str, Any]:
        """🆕 v101.0: Расширенная статистика"""
        if not self.categories:
            return {"total": 0}
        
        lengths = [cat.length_cm for cat in self.categories.values()]
        widths = [cat.width_cm for cat in self.categories.values()]
        heights = [cat.height_cm for cat in self.categories.values()]
        weights = [cat.weight_kg for cat in self.categories.values()]
        
        # 🆕 v101.0: Статистика по типам товаров
        origin_counts = {}
        for cat in self.categories.values():
            origin = cat.product_origin_default
            origin_counts[origin] = origin_counts.get(origin, 0) + 1
        
        # 🆕 v101.0: Статистика по ABC-классам
        abc_counts = {"A": 0, "B": 0, "C": 0, "None": 0}
        for cat in self.categories.values():
            abc = cat.abc_class or "None"
            abc_counts[abc] = abc_counts.get(abc, 0) + 1
        
        # 🆕 v101.0: Статистика по сезонам
        peak_months = {}
        for cat in self.categories.values():
            peak = cat.get_peak_month()
            peak_months[peak] = peak_months.get(peak, 0) + 1
        
        return {
            "total": len(self.categories),
            "avg_length": sum(lengths) / len(lengths),
            "avg_width": sum(widths) / len(widths),
            "avg_height": sum(heights) / len(heights),
            "avg_weight": sum(weights) / len(weights),
            "min_weight": min(weights),
            "max_weight": max(weights),
            "by_origin": origin_counts,
            "by_abc": abc_counts,
            "peak_months": peak_months,
            "metrics": self.metrics,
        }
    
    # ========================================================================
    # 🆕 v101.0: ПОЛУЧЕНИЕ КОЭФФИЦИЕНТА СПРОСА
    # ========================================================================
    def get_demand_coefficient(self, category: str, month: int) -> float:
        """🆕 v101.0: Получить коэффициент спроса для категории и месяца"""
        cat = self.get_category(category)
        if cat:
            return cat.get_demand_coefficient(month)
        return 1.0
    
    # ========================================================================
    # 🆕 v101.0: ПОИСК ПО ТИПУ ТОВАРА
    # ========================================================================
    def get_categories_by_origin(self, origin: str) -> List[CategoryRecord]:
        """🆕 v101.0: Получить категории по типу товара"""
        return [
            cat for cat in self.categories.values()
            if cat.product_origin_default == origin
        ]
    
    # ========================================================================
    # 🆕 v101.0: ПОИСК ПО ABC-КЛАССУ
    # ========================================================================
    def get_categories_by_abc(self, abc_class: str) -> List[CategoryRecord]:
        """🆕 v101.0: Получить категории по ABC-классу"""
        return [
            cat for cat in self.categories.values()
            if cat.abc_class == abc_class
        ]


