# 🆕 v101.0: ИМПОРТ ИЗ GOOGLE SHEETS
# ============================================================================
def show_category_import_from_sheets(db):
    """📑 Импорт категорий из Google Sheets (🆕 v101.0)"""
    st.subheader("📑 Импорт категорий из Google Sheets")
    st.info("""
📋 **ИНСТРУКЦИЯ:**
1. Подготовьте Google таблицу с категориями
2. Убедитесь, что есть колонки: Категория, Длина, Ширина, Высота, Вес
3. Укажите путь к JSON credentials Service Account
4. Введите ID таблицы (из URL)
5. Нажмите "Импортировать"

💡 **Формат ID таблицы:**
Из URL `https://docs.google.com/spreadsheets/d/1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgVE2upms/edit`
ID = `1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgVE2upms`
""")
    
    if not GSPREAD_AVAILABLE:
        st.warning("⚠️ gspread не установлен. Установите: `pip install gspread google-auth`")
        return
    
    col1, col2 = st.columns(2)
    
    with col1:
        credentials_path = st.text_input(
            "🔑 Путь к JSON credentials",
            placeholder="/path/to/credentials.json",
            key="cat_gs_credentials",
            help="Путь к JSON файлу Service Account из Google Cloud Console"
        )
    
    with col2:
        spreadsheet_id = st.text_input(
            "📊 ID таблицы",
            placeholder="1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgVE2upms",
            key="cat_gs_spreadsheet_id"
        )
    
    sheet_name = st.text_input(
        "📝 Название листа",
        value="Категории",
        key="cat_gs_sheet_name"
    )
    
    if st.button("🚀 Импортировать из Google Sheets", type="primary", key="cat_gs_import"):
        if not credentials_path:
            st.error("❌ Укажите путь к credentials")
        elif not os.path.exists(credentials_path):
            st.error(f"❌ Файл не найден: {credentials_path}")
        elif not spreadsheet_id:
            st.error("❌ Укажите ID таблицы")
        else:
            with st.spinner("Импорт из Google Sheets..."):
                try:
                    result = db.import_from_google_sheets(
                        credentials_path=credentials_path,
                        spreadsheet_id=spreadsheet_id,
                        sheet_name=sheet_name
                    )
                    
                    if result.get("success"):
                        st.success(f"✅ Импортировано {result.get('imported', 0)} категорий")
                        
                        if result.get("warnings"):
                            st.warning(f"⚠️ Предупреждений: {len(result['warnings'])}")
                            with st.expander("📋 Показать предупреждения"):
                                for warning in result["warnings"][:10]:
                                    st.warning(warning)
                        
                        st.rerun()
                    else:
                        st.error(f"❌ Ошибка импорта: {result.get('errors', ['Неизвестная ошибка'])[0]}")
                
                except Exception as e:
                    st.error(f"❌ Ошибка: {e}")
                    logger.error(traceback.format_exc())


