def show_category_upload(db):
    """📥 Загрузка категорий из Excel (🆕 v101.0 — расширенная)"""
    st.subheader("📥 Загрузка категорий из Excel")
    st.info("""
📋 **ТРЕБОВАНИЯ К ФАЙЛУ:**

**Обязательные колонки:**
- Категория (название категории)
- Длина (числовое значение)
- Ширина (числовое значение)
- Высота (числовое значение)
- Вес (числовое значение)

**🆕 v101.0: Опциональные колонки:**
- Тип товара (original/analog_premium/analog_standard/analog_budget/china/remanufactured/used)
- Возвраты % (процент возвратов)
- ДРР % (доля рекламных расходов)
- Средняя цена
- Средняя маржа %
- Сезон Янв...Сен (коэффициенты спроса по месяцам)

**Пример файла:**
| Категория | Длина | Ширина | Высота | Вес | Тип товара | Возвраты % |
|-----------|-------|--------|--------|-----|------------|------------|
| Фильтры   | 15    | 15     | 15     | 0.5 | analog_premium | 5    |
| Колодки   | 15    | 10     | 5      | 2.0 | analog_premium | 8    |
""")
    
    uploaded_file = st.file_uploader(
        "📤 Загрузите Excel файл с категориями",
        type=['xlsx', 'xls'],
        key="category_upload_file"
    )
    
    if uploaded_file is not None:
        # Сохраняем временный файл
        temp_path = TEMP_DIR / f"categories_{int(time.time())}.xlsx"
        TEMP_DIR.mkdir(exist_ok=True)
        with open(temp_path, "wb") as f:
            f.write(uploaded_file.getbuffer())
        
        st.info(f"📄 Файл загружен: {uploaded_file.name}")
        
        # 🆕 v101.0: Предпросмотр данных
        try:
            preview_df = pd.read_excel(temp_path, engine='openpyxl')
            st.write("**Предпросмотр данных:**")
            st.dataframe(preview_df.head(10), use_container_width=True)
            st.info(f"📊 Строк в файле: {len(preview_df)}")
        except Exception as e:
            st.warning(f"⚠️ Не удалось показать предпросмотр: {e}")
        
        if st.button("🚀 Импортировать категории", type="primary", key="import_categories"):
            with st.spinner("Импорт категорий..."):
                result = db.import_from_excel(str(temp_path))
                
                if result.get("success"):
                    st.success(f"✅ Импортировано {result['imported']} категорий")
                    
                    if result.get("warnings"):
                        st.warning(f"⚠️ Предупреждений: {len(result['warnings'])}")
                        with st.expander("📋 Показать предупреждения"):
                            for warning in result["warnings"][:10]:
                                st.warning(warning)
                    
                    # 🆕 v101.0: Показываем статистику по типам товаров
                    if result.get("by_origin"):
                        st.subheader("📊 Распределение по типам товаров")
                        origin_df = pd.DataFrame([
                            {"Тип товара": k, "Количество": v}
                            for k, v in result["by_origin"].items()
                        ])
                        st.dataframe(origin_df, use_container_width=True)
                    
                    st.rerun()
                else:
                    st.error("❌ Ошибка импорта")
                    with st.expander("📋 Показать ошибки"):
                        for error in result["errors"]:
                            st.error(error)
        
        # Удалить временный файл
        if temp_path.exists():
            temp_path.unlink()
    
    # Кнопка скачать шаблон
    if st.button("📥 Скачать шаблон Excel", key="download_category_template"):
        template_data = {
            'Категория': ['Фильтры', 'Колодки', 'Масла', 'Шины', 'Аккумуляторы'],
            'Длина': [15, 15, 10, 60, 35],
            'Ширина': [15, 10, 10, 60, 20],
            'Высота': [15, 5, 25, 25, 22],
            'Вес': [0.5, 2.0, 1.0, 10.0, 18.0],
            'Единица длины': ['см', 'см', 'см', 'см', 'см'],
            'Единица веса': ['кг', 'кг', 'кг', 'кг', 'кг'],
            'Тип товара': ['analog_premium', 'analog_premium', 'analog_premium', 
                          'analog_premium', 'analog_premium'],
            'Возвраты %': [5, 8, 3, 7, 12],
            'ДРР %': [15, 18, 20, 18, 20],
        }
        template_df = pd.DataFrame(template_data)
        output = io.BytesIO()
        with pd.ExcelWriter(output, engine='openpyxl') as writer:
            template_df.to_excel(writer, index=False, sheet_name='Категории')
        output.seek(0)
        st.download_button(
            label="⬇️ Скачать шаблон",
            data=output,
            file_name="шаблон_категорий_v101.xlsx",
            mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            key="download_category_template_btn"
        )


