def show_category_add_manual(db):
    """➕ Добавление категории вручную (🆕 v101.0 — расширенное)"""
    st.subheader("➕ Добавить категорию вручную")
    
    col1, col2 = st.columns(2)
    
    with col1:
        category_name = st.text_input(
            "📝 Название категории",
            placeholder="например: Фильтры масляные",
            key="category_name"
        )
        
        length = st.number_input(
            "📏 Длина",
            min_value=0.0,
            value=0.0,
            step=0.1,
            key="category_length"
        )
        
        width = st.number_input(
            "📐 Ширина",
            min_value=0.0,
            value=0.0,
            step=0.1,
            key="category_width"
        )
    
    with col2:
        height = st.number_input(
            "📐 Высота",
            min_value=0.0,
            value=0.0,
            step=0.1,
            key="category_height"
        )
        
        weight = st.number_input(
            "⚖️ Вес",
            min_value=0.0,
            value=0.0,
            step=0.1,
            key="category_weight"
        )
        
        unit = st.selectbox(
            "📏 Единица длины",
            ["см", "мм", "м"],
            key="category_unit"
        )
        
        weight_unit = st.selectbox(
            "⚖️ Единица веса",
            ["кг", "г", "т"],
            key="category_weight_unit"
        )
    
    # 🆕 v101.0: Тип товара
    st.subheader("🏷️ Тип товара")
    
    product_origin = st.selectbox(
        "Тип товара по умолчанию",
        list(CATEGORY_UI_CONSTANTS["PRODUCT_ORIGINS"].keys()),
        format_func=lambda x: CATEGORY_UI_CONSTANTS["PRODUCT_ORIGINS"][x],
        index=3,  # analog_standard
        key="category_origin"
    )
    
    # 🆕 v101.0: Базовые параметры
    st.subheader("📊 Базовые параметры")
    
    col1, col2, col3 = st.columns(3)
    
    with col1:
        return_rate = st.number_input(
            "Возвраты %",
            min_value=0.0,
            max_value=100.0,
            value=5.0,
            step=0.5,
            key="category_return_rate"
        )
    
    with col2:
        drr = st.number_input(
            "ДРР %",
            min_value=0.0,
            max_value=100.0,
            value=15.0,
            step=0.5,
            key="category_drr"
        )
    
    with col3:
        avg_price = st.number_input(
            "Средняя цена",
            min_value=0.0,
            value=0.0,
            step=100.0,
            key="category_avg_price"
        )
    
    # 🆕 v101.0: Сезонные коэффициенты
    st.subheader("🌤️ Сезонные коэффициенты спроса")
    st.info("Коэффициент 1.0 = средний спрос. > 1.0 — выше среднего, < 1.0 — ниже.")
    
    seasonality = []
    cols = st.columns(6)
    for i in range(12):
        with cols[i % 6]:
            coeff = st.number_input(
                CATEGORY_UI_CONSTANTS["MONTHS"][i + 1],
                min_value=0.0,
                max_value=5.0,
                value=1.0,
                step=0.1,
                key=f"season_{i}"
            )
            seasonality.append(coeff)
    
    if st.button("➕ Добавить категорию", type="primary", key="add_category"):
        if not category_name:
            st.error("❌ Введите название категории")
        elif length <= 0 or width <= 0 or height <= 0 or weight <= 0:
            st.error("❌ Все размеры должны быть больше 0")
        else:
            # 🆕 v101.0: Создаём расширенную запись
            try:
                from streamlit_app import CategoryRecord
                
                record = CategoryRecord(
                    name=category_name,
                    length_cm=length,
                    width_cm=width,
                    height_cm=height,
                    weight_kg=weight,
                    unit=unit,
                    weight_unit=weight_unit,
                    product_origin_default=product_origin if product_origin != "all" else "analog_standard",
                    seasonality_demand=seasonality,
                    return_rate_base=return_rate / 100.0,
                    drr_base=drr / 100.0,
                    avg_price=avg_price,
                    source="manual"
                )
                
                if db.add_category(record):
                    st.success(f"✅ Категория '{category_name}' добавлена")
                    st.rerun()
                else:
                    st.error("❌ Ошибка добавления категории")
            
            except ImportError:
                # Fallback на старый формат
                db.add_category(
                    name=category_name,
                    length=length,
                    width=width,
                    height=height,
                    weight=weight,
                    unit=unit,
                    weight_unit=weight_unit
                )
                st.success(f"✅ Категория '{category_name}' добавлена")
                st.rerun()


