# 🆕 v101.0: СПИСОК КАТЕГОРИЙ (РАСШИРЕННЫЙ)
# ============================================================================
def show_category_list(db):
    """📋 Список категорий (🆕 v101.0 — расширенный)"""
    st.subheader("📋 Список категорий")
    
    categories = db.get_all_categories()
    
    if not categories:
        st.info("ℹ️ Категории не добавлены")
        return
    
    st.info(f"📊 Всего категорий: {len(categories)}")
    
    # 🆕 v101.0: Фильтры
    col1, col2 = st.columns(2)
    
    with col1:
        origin_filter = st.selectbox(
            "🏷️ Фильтр по типу товара",
            list(CATEGORY_UI_CONSTANTS["PRODUCT_ORIGINS"].keys()),
            format_func=lambda x: CATEGORY_UI_CONSTANTS["PRODUCT_ORIGINS"][x],
            key="cat_list_origin_filter"
        )
    
    with col2:
        abc_filter = st.selectbox(
            "🏆 Фильтр по ABC-классу",
            ["Все", "A", "B", "C"],
            key="cat_list_abc_filter"
        )
    
    # Фильтрация
    filtered_categories = categories
    if origin_filter != "all":
        filtered_categories = {
            k: v for k, v in categories.items()
            if hasattr(v, 'product_origin_default') and v.product_origin_default == origin_filter
        }
    
    if abc_filter != "Все":
        filtered_categories = {
            k: v for k, v in filtered_categories.items()
            if hasattr(v, 'abc_class') and v.abc_class == abc_filter
        }
    
    st.info(f"📊 Показано категорий: {len(filtered_categories)}")
    
    # Таблица категорий
    data = []
    for key, cat in filtered_categories.items():
        # Поддержка старого и нового формата
        if hasattr(cat, 'to_dict'):
            cat_dict = cat.to_dict()
        else:
            cat_dict = cat
        
        row = {
            'Категория': cat_dict.get('name', key),
            'Длина (см)': cat_dict.get('length_cm', 0),
            'Ширина (см)': cat_dict.get('width_cm', 0),
            'Высота (см)': cat_dict.get('height_cm', 0),
            'Вес (кг)': cat_dict.get('weight_kg', 0),
            'Единица': cat_dict.get('unit', 'см'),
            'Ед. веса': cat_dict.get('weight_unit', 'кг'),
            'Тип товара': cat_dict.get('product_origin_default', 'analog_standard'),
            'ABC класс': cat_dict.get('abc_class', ''),
            'Пик спроса': f"{cat.get_peak_month() if hasattr(cat, 'get_peak_month') else 1}",
        }
        data.append(row)
    
    df = pd.DataFrame(data)
    st.dataframe(df, use_container_width=True, height=400)
    
    # Удаление категории
    st.divider()
    st.subheader("🗑️ Удалить категорию")
    
    category_to_delete = st.selectbox(
        "Выберите категорию для удаления",
        options=list(categories.keys()),
        format_func=lambda x: categories[x].name if hasattr(categories[x], 'name') else categories[x].get('name', x),
        key="delete_category_select"
    )
    
    if st.button("🗑️ Удалить", key="delete_category_btn"):
        db.delete_category(category_to_delete)
        st.success("✅ Категория удалена")
        st.rerun()
    
    # Очистка всех
    st.divider()
    if st.button("⚠️ Очистить все категории", key="clear_all_categories"):
        if st.checkbox("Подтверждаю удаление всех категорий", key="confirm_clear"):
            db.clear_all()
            st.success("✅ Все категории удалены")
            st.rerun()


