def show_category_export(db):
    """📤 Экспорт категорий (🆕 v101.0 — расширенный)"""
    st.subheader("📤 Экспорт категорий")
    
    categories = db.get_all_categories()
    
    if not categories:
        st.info("ℹ️ Нет категорий для экспорта")
        return
    
    st.info(f"📊 Всего категорий: {len(categories)}")
    
    col1, col2 = st.columns(2)
    
    with col1:
        st.markdown("#### 🟢 Экспорт в Excel")
        if st.button("📥 Экспортировать в Excel", key="export_categories_excel"):
            output_path = TEMP_DIR / f"categories_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
            TEMP_DIR.mkdir(exist_ok=True)
            
            if db.export_to_excel(str(output_path)):
                with open(output_path, "rb") as f:
                    file_data = f.read()
                st.download_button(
                    label="⬇️ Скачать Excel файл",
                    data=file_data,
                    file_name=output_path.name,
                    mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                    key="download_categories_excel"
                )
                st.success("✅ Файл готов к скачиванию")
            else:
                st.error("❌ Ошибка экспорта")
    
    with col2:
        st.markdown("#### 🟡 Экспорт в Google Sheets")
        
        if not GSPREAD_AVAILABLE:
            st.warning("⚠️ gspread не установлен")
        else:
            credentials_path = st.text_input(
                "🔑 Путь к credentials",
                placeholder="/path/to/credentials.json",
                key="cat_export_gs_credentials"
            )
            
            share_email = st.text_input(
                "📧 Email для шаринга (опционально)",
                placeholder="user@example.com",
                key="cat_export_gs_share"
            )
            
            if st.button("📑 Экспортировать в Google Sheets", key="export_categories_sheets"):
                if not credentials_path:
                    st.error("❌ Укажите путь к credentials")
                elif not os.path.exists(credentials_path):
                    st.error(f"❌ Файл не найден: {credentials_path}")
                else:
                    with st.spinner("Экспорт в Google Sheets..."):
                        result = db.export_to_google_sheets(
                            credentials_path=credentials_path,
                            share_email=share_email if share_email else None
                        )
                        
                        if result.get("success"):
                            st.success("✅ Экспорт завершён!")
                            st.info(f"📊 Таблица: [{result.get('spreadsheet_url')}]({result.get('spreadsheet_url')})")
                            st.info(f"📝 Записано строк: {result.get('rows_written', 0)}")
                        else:
                            st.error(f"❌ Ошибка: {result.get('errors', ['Неизвестная ошибка'])[0]}")


