def show_category_abc_analysis(db):
    """🏆 ABC-анализ категорий (🆕 v101.0)"""
    st.subheader("🏆 ABC-анализ категорий")
    st.info("""
📋 **О АНАЛИЗЕ:**
ABC-анализ классифицирует категории по прибыльности:
- **Класс A** — 80% прибыли (стратегические категории)
- **Класс B** — 15% прибыли (важные категории)
- **Класс C** — 5% прибыли (прочие категории)

💡 **Для запуска анализа** нужно указать прибыль по каждой категории.
""")
    
    categories = db.get_all_categories()
    
    if not categories:
        st.info("ℹ️ Нет категорий для анализа")
        return
    
    # Ввод прибыли по категориям
    st.subheader("💰 Введите прибыль по категориям")
    
    profit_data = {}
    for key, cat in list(categories.items())[:50]:  # Ограничиваем 50 категориями
        cat_name = cat.name if hasattr(cat, 'name') else cat.get('name', key)
        profit = st.number_input(
            f"{cat_name}",
            min_value=0.0,
            value=0.0,
            step=1000.0,
            key=f"profit_{key}"
        )
        profit_data[cat_name] = profit
    
    if st.button("🏆 Запустить ABC-анализ", type="primary", key="cat_abc_analyze"):
        # Фильтруем категории с прибылью > 0
        profit_filtered = {k: v for k, v in profit_data.items() if v > 0}
        
        if not profit_filtered:
            st.warning("⚠️ Укажите прибыль хотя бы для одной категории")
            return
        
        with st.spinner("Запуск ABC-анализа..."):
            result = db.analyze_abc_by_profit(profit_filtered)
            
            if result.get("success"):
                st.success("✅ ABC-анализ завершён!")
                
                # KPI-метрики
                col1, col2, col3, col4 = st.columns(4)
                
                with col1:
                    st.metric("📦 Всего категорий", result["total_categories"])
                
                with col2:
                    st.metric("💰 Общая прибыль", f"{result['total_profit']:,.0f} ₽")
                
                with col3:
                    st.metric("🏆 Класс A", f"{result['class_counts']['A']} кат.")
                
                with col4:
                    st.metric("📈 Доля A", f"{result['class_shares']['A']*100:.1f}%")
                
                # Таблица по классам
                st.subheader("📊 Распределение по классам")
                
                class_data = []
                for abc in ["A", "B", "C"]:
                    class_data.append({
                        "Класс": CATEGORY_UI_CONSTANTS["ABC_CLASSES"][abc]["label"],
                        "Количество": result["class_counts"][abc],
                        "Прибыль": f"{result['class_profits'][abc]:,.0f} ₽",
                        "Доля": f"{result['class_shares'][abc]*100:.1f}%",
                    })
                
                class_df = pd.DataFrame(class_data)
                st.dataframe(class_df, use_container_width=True)
                
                # Визуализация
                if PLOTLY_AVAILABLE:
                    fig = px.pie(
                        values=[result["class_profits"]["A"], 
                               result["class_profits"]["B"],
                               result["class_profits"]["C"]],
                        names=["Класс A", "Класс B", "Класс C"],
                        title="Распределение прибыли по ABC-классам",
                        color_discrete_map={
                            "Класс A": "#00cc96",
                            "Класс B": "#ffa600",
                            "Класс C": "#ef553b"
                        }
                    )
                    st.plotly_chart(fig, use_container_width=True)
                
                st.rerun()
            else:
                st.error(f"❌ Ошибка: {result.get('error', 'Неизвестная ошибка')}")


