# 🆕 v101.0: КОНФЛИКТ-ДЕТЕКТОР
# ============================================================================
def show_category_conflicts(db):
    """⚠️ Конфликт-детектор (🆕 v101.0)"""
    st.subheader("⚠️ Конфликт-детектор")
    st.info("""
📋 **О ДЕТЕКТОРЕ:**
Автоматически выявляет аномалии в данных категорий:
- Аномальные габариты (объём > 1000 л, вес > 100 кг)
- Отсутствие сезонных коэффициентов
- Высокие возвраты (> 30%)
- Высокий ДРР (> 40%)
""")
    
    if st.button("🔍 Запустить проверку", type="primary", key="cat_conflict_check"):
        with st.spinner("Проверка данных..."):
            conflicts = db.detect_conflicts()
            
            if not conflicts:
                st.success("✅ Конфликтов не обнаружено!")
                return
            
            st.warning(f"⚠️ Обнаружено конфликтов: {len(conflicts)}")
            
            # Группировка по типу
            conflicts_by_type = {}
            for conflict in conflicts:
                conflict_type = conflict["type"]
                if conflict_type not in conflicts_by_type:
                    conflicts_by_type[conflict_type] = []
                conflicts_by_type[conflict_type].append(conflict)
            
            # Отображение по типам
            for conflict_type, conflicts_list in conflicts_by_type.items():
                with st.expander(f"⚠️ {conflict_type} ({len(conflicts_list)})", expanded=True):
                    for conflict in conflicts_list:
                        severity = conflict["severity"]
                        if severity == "warning":
                            st.warning(f"**{conflict['category']}**: {conflict['message']}")
                        elif severity == "error":
                            st.error(f"**{conflict['category']}**: {conflict['message']}")
                        else:
                            st.info(f"**{conflict['category']}**: {conflict['message']}")


