# 🆕 v101.0: ДАТАКЛАСС ДЛЯ РЕЗУЛЬТАТА ВАЛИДАЦИИ
# ============================================================================
@dataclass
class ValidationResult:
    """🆕 v101.0: Расширенный результат валидации"""
    valid: bool = True
    category: str = ""
    product_origin: str = "analog_standard"
    abc_class: Optional[str] = None
    marketplace: str = "Яндекс Маркет"
    deviations: List[Dict[str, Any]] = field(default_factory=list)
    warnings: List[str] = field(default_factory=list)
    recommendations: List[str] = field(default_factory=list)
    corrected_dimensions: Optional[Dict[str, float]] = None
    validation_score: float = 1.0  # 0-1, где 1 = идеальная валидация
    season: Optional[str] = None
    conflicts: List[Dict[str, Any]] = field(default_factory=list)
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            "valid": self.valid,
            "category": self.category,
            "product_origin": self.product_origin,
            "abc_class": self.abc_class,
            "marketplace": self.marketplace,
            "deviations": self.deviations,
            "warnings": self.warnings,
            "recommendations": self.recommendations,
            "corrected_dimensions": self.corrected_dimensions,
            "validation_score": self.validation_score,
            "season": self.season,
            "conflicts": self.conflicts,
        }


# ============================================================================
# 🆕 v101.0: ГЛАВНАЯ ФУНКЦИЯ ВАЛИДАЦИИ (РАСШИРЕННАЯ)
# ============================================================================
def validate_dimensions_with_category(
    length: float,
    width: float,
    height: float,
    weight: float,
    category: str,
    tolerance_percent: float = 20.0,
    product_origin: str = "analog_standard",
    abc_class: Optional[str] = None,
    marketplace: str = "Яндекс Маркет",
    month: Optional[int] = None,
    use_validator: bool = True,
) -> ValidationResult:
    """
    🆕 v101.0: Расширенная валидация весогабаритов с учётом:
    - Типа товара (оригинал/аналог/Китай)
    - ABC-класса (A/B/C)
    - Маркетплейса (Яндекс Маркет — строже)
    - Сезона (зимние шины зимой больше)
    
    Args:
        length, width, height: Фактические размеры (см)
        weight: Фактический вес (кг)
        category: Название категории
        tolerance_percent: Базовый допуск в % (по умолчанию 20%)
        product_origin: Тип товара (original/analog_premium/analog_standard/
                       analog_budget/china/remanufactured/used)
        abc_class: ABC-класс (A/B/C или None)
        marketplace: Маркетплейс (Яндекс Маркет/Ozon/Wildberries/...)
        month: Месяц для сезонной корректировки (1-12 или None)
        use_validator: Использовать AdvancedDimensionsValidator из Блока 12
    
    Returns:
        ValidationResult с полной информацией
    """
    result = ValidationResult(
        category=category,
        product_origin=product_origin,
        abc_class=abc_class,
        marketplace=marketplace,
    )
    
    try:
        # 🆕 v101.0: Определяем сезон
        if month is None:
            month = datetime.now().month
        
        if month in [12, 1, 2]:
            season = "winter"
        elif month in [3, 4, 5]:
            season = "spring"
        elif month in [6, 7, 8]:
            season = "summer"
        else:
            season = "autumn"
        
        result.season = season
        
        # 🆕 v101.0: Рассчитываем итоговый допуск
        # База × Тип товара × ABC-класс × Маркетплейс
        base_tolerance = tolerance_percent / 100.0
        
        origin_mult = VALIDATION_CONFIG["tolerance_by_origin"].get(
            product_origin, 0.20
        )
        
        abc_mult = VALIDATION_CONFIG["tolerance_by_abc"].get(
            abc_class, 1.0
        ) if abc_class else 1.0
        
        mp_mult = VALIDATION_CONFIG["tolerance_by_marketplace"].get(
            marketplace, 1.0
        )
        
        final_tolerance = base_tolerance * origin_mult * abc_mult * mp_mult
        
        # 🆕 v101.0: Получаем стандартные размеры категории
        category_data = None
        if 'category_dimensions_db' in st.session_state:
            db = st.session_state.category_dimensions_db
            category_data = db.get_category(category)
        
        # 🆕 v101.0: Если категории нет в БД — используем эвристику
        if not category_data and use_validator and VALIDATOR_AVAILABLE:
            try:
                inferred = AdvancedDimensionsValidator.infer_missing_dimensions(
                    category, weight
                )
                category_data = {
                    "length_cm": inferred["length_cm"],
                    "width_cm": inferred["width_cm"],
                    "height_cm": inferred["height_cm"],
                    "weight_kg": weight,  # Вес берём из ввода
                }
            except Exception as e:
                logger.warning(f"Ошибка эвристики: {e}")
        
        if not category_data:
            result.warnings.append(f"⚠️ Категория '{category}' не найдена в базе")
            return result
        
        # 🆕 v101.0: Сезонная корректировка стандартных размеров
        std_length = category_data.get("length_cm", 0)
        std_width = category_data.get("width_cm", 0)
        std_height = category_data.get("height_cm", 0)
        std_weight = category_data.get("weight_kg", 0)
        
        cat_key = category.lower().strip()
        if cat_key in VALIDATION_CONFIG["seasonal_dimension_multipliers"]:
            multipliers = VALIDATION_CONFIG["seasonal_dimension_multipliers"][cat_key]
            height_mult = multipliers.get(season, 1.0)
            std_height *= height_mult
        
        # 🆕 v101.0: Проверка отклонений
        checks = [
            ("Длина", length, std_length),
            ("Ширина", width, std_width),
            ("Высота", height, std_height),
            ("Вес", weight, std_weight),
        ]
        
        for param_name, actual, expected in checks:
            if expected > 0:
                deviation = abs(actual - expected) / expected
                if deviation > final_tolerance:
                    result.deviations.append({
                        "parameter": param_name,
                        "actual": round(actual, 2),
                        "expected": round(expected, 2),
                        "deviation_percent": round(deviation * 100, 1),
                        "tolerance_percent": round(final_tolerance * 100, 1),
                    })
                    result.valid = False
        
        # 🆕 v101.0: Если есть отклонения — предлагаем исправленные габариты
        if result.deviations:
            result.corrected_dimensions = {
                "length_cm": round(std_length, 2),
                "width_cm": round(std_width, 2),
                "height_cm": round(std_height, 2),
                "weight_kg": round(std_weight, 2),
            }
            
            result.warnings.append(
                f"⚠️ Обнаружены отклонения в {len(result.deviations)} параметрах"
            )
            
            # 🆕 v101.0: Рекомендации
            result.recommendations.append(
                f"💡 Рекомендуемые габариты: "
                f"{std_length:.1f}x{std_width:.1f}x{std_height:.1f} см, "
                f"{std_weight:.2f} кг"
            )
            
            # Специфические рекомендации по типу товара
            if product_origin == "china":
                result.recommendations.append(
                    "🇨🇳 Китайские товары часто имеют большие отклонения. "
                    "Проверьте упаковку."
                )
            elif product_origin == "original":
                result.recommendations.append(
                    "🏆 Оригиналы должны точно соответствовать габаритам. "
                    "Возможна ошибка в данных."
                )
        
        # 🆕 v101.0: Конфликт-детектор (аномалии)
        result.conflicts = _detect_conflicts(
            length, width, height, weight, category
        )
        
        if result.conflicts:
            for conflict in result.conflicts:
                result.warnings.append(conflict["message"])
        
        # 🆕 v101.0: Расчёт validation score
        if result.valid:
            result.validation_score = 1.0
        else:
            max_dev = max(d["deviation_percent"] for d in result.deviations) if result.deviations else 0
            result.validation_score = max(0.0, 1.0 - max_dev / 100)
        
        # 🆕 v101.0: Итоговые рекомендации
        if result.valid and not result.conflicts:
            result.recommendations.append("✅ Все параметры в пределах нормы")
        
        if abc_class == "A":
            result.recommendations.append(
                "🏆 Стратегический товар (класс A). "
                "Рекомендуется повышенная точность данных."
            )
        
    except Exception as e:
        logger.error(f"Ошибка валидации: {e}")
        result.warnings.append(f"❌ Ошибка валидации: {str(e)}")
        result.valid = False
    
    return result


# ============================================================================
# 🆕 v101.0: КОНФЛИКТ-ДЕТЕКТОР
# ============================================================================
def _detect_conflicts(
    length: float,
    width: float,
    height: float,
    weight: float,
    category: str,
) -> List[Dict[str, Any]]:
    """🆕 v101.0: Выявление аномалий в габаритах"""
    conflicts = []
    
    # Проверка 1: Аномально большой объём
    if length > 0 and width > 0 and height > 0:
        volume = (length * width * height) / 1000  # в литрах
        if volume > 1000:  # Более 1 кубометра
            conflicts.append({
                "type": "аномальный_объём",
                "severity": "warning",
                "message": f"⚠️ Объём {volume:.1f} л — проверьте габариты",
            })
    
    # Проверка 2: Аномально большой вес
    if weight > VALIDATION_CONFIG["max_weight_kg"]:
        conflicts.append({
            "type": "аномальный_вес",
            "severity": "warning",
            "message": f"⚠️ Вес {weight:.1f} кг превышает лимит "
                      f"{VALIDATION_CONFIG['max_weight_kg']} кг",
        })
    
    # Проверка 3: Аномально малый вес
    if 0 < weight < VALIDATION_CONFIG["min_weight_kg"]:
        conflicts.append({
            "type": "аномально_малый_вес",
            "severity": "info",
            "message": f"ℹ️ Вес {weight:.3f} кг очень мал — проверьте",
        })
    
    # Проверка 4: Несоответствие веса и объёма
    if length > 0 and width > 0 and height > 0 and weight > 0:
        volume = (length * width * height) / 1000
        density = weight / volume if volume > 0 else 0
        
        # Очень высокая плотность (> 10 кг/л)
        if density > 10:
            conflicts.append({
                "type": "высокая_плотность",
                "severity": "warning",
                "message": f"⚠️ Плотность {density:.1f} кг/л — "
                          f"проверьте вес или габариты",
            })
        
        # Очень низкая плотность (< 0.01 кг/л)
        elif density < 0.01:
            conflicts.append({
                "type": "низкая_плотность",
                "severity": "info",
                "message": f"ℹ️ Плотность {density:.3f} кг/л — "
                          f"товар очень лёгкий для своего объёма",
            })
    
    # Проверка 5: Нестандартные размеры для категории
    cat_key = category.lower().strip()
    category_defaults = {
        "фильтры": {"max_l": 30, "max_w": 30, "max_h": 40},
        "колодки": {"max_l": 25, "max_w": 20, "max_h": 15},
        "масла": {"max_l": 30, "max_w": 30, "max_h": 40},
        "шины": {"max_l": 100, "max_w": 100, "max_h": 50},
        "аккумуляторы": {"max_l": 50, "max_w": 30, "max_h": 30},
    }
    
    if cat_key in category_defaults:
        defaults = category_defaults[cat_key]
        if length > defaults["max_l"] * 2:
            conflicts.append({
                "type": "нестандартная_длина",
                "severity": "warning",
                "message": f"⚠️ Длина {length:.1f} см необычна для категории '{category}'",
            })
    
    return conflicts


# ============================================================================
# 🆕 v101.0: МАССОВАЯ ВАЛИДАЦИЯ КАТАЛОГА
# ============================================================================
def validate_catalog_with_report(
    df: pd.DataFrame,
    length_col: str = "Длина",
    width_col: str = "Ширина",
    height_col: str = "Высота",
    weight_col: str = "Вес",
    category_col: str = "Категория",
    origin_col: Optional[str] = None,
    abc_col: Optional[str] = None,
    marketplace: str = "Яндекс Маркет",
    tolerance_percent: float = 20.0,
    progress_callback: Optional[callable] = None,
) -> pd.DataFrame:
    """
    🆕 v101.0: Массовая валидация каталога с отчётом
    
    Args:
        df: DataFrame с каталогом
        length_col, width_col, height_col, weight_col: Колонки с габаритами
        category_col: Колонка с категорией
        origin_col: Колонка с типом товара (опционально)
        abc_col: Колонка с ABC-классом (опционально)
        marketplace: Маркетплейс для расчёта допусков
        tolerance_percent: Базовый допуск в %
        progress_callback: Функция для отображения прогресса
    
    Returns:
        DataFrame с результатами валидации
    """
    results = []
    total = len(df)
    
    logger.info(f"🔍 Запуск массовой валидации: {total} записей")
    
    for idx, row in df.iterrows():
        try:
            length = safe_float(row.get(length_col, 0))
            width = safe_float(row.get(width_col, 0))
            height = safe_float(row.get(height_col, 0))
            weight = safe_float(row.get(weight_col, 0))
            category = str(row.get(category_col, ""))
            
            product_origin = "analog_standard"
            if origin_col and origin_col in row:
                product_origin = str(row.get(origin_col, "analog_standard"))
            
            abc_class = None
            if abc_col and abc_col in row:
                abc_class = str(row.get(abc_col, None))
            
            validation = validate_dimensions_with_category(
                length=length,
                width=width,
                height=height,
                weight=weight,
                category=category,
                tolerance_percent=tolerance_percent,
                product_origin=product_origin,
                abc_class=abc_class,
                marketplace=marketplace,
            )
            
            result_dict = {
                "index": idx,
                "Артикул": row.get("Артикул", ""),
                "Бренд": row.get("Бренд", ""),
                "Категория": category,
                "Тип товара": product_origin,
                "ABC класс": abc_class or "",
                "Валидно": validation.valid,
                "Validation Score": round(validation.validation_score, 2),
                "Отклонений": len(validation.deviations),
                "Предупреждений": len(validation.warnings),
                "Рекомендаций": len(validation.recommendations),
            }
            
            # Добавляем детали отклонений
            if validation.deviations:
                for i, dev in enumerate(validation.deviations[:3]):
                    result_dict[f"Отклонение_{i+1}"] = (
                        f"{dev['parameter']}: {dev['actual']:.2f} vs "
                        f"{dev['expected']:.2f} ({dev['deviation_percent']:.1f}%)"
                    )
            
            # Добавляем исправленные габариты
            if validation.corrected_dimensions:
                result_dict["Исправленная длина"] = validation.corrected_dimensions["length_cm"]
                result_dict["Исправленная ширина"] = validation.corrected_dimensions["width_cm"]
                result_dict["Исправленная высота"] = validation.corrected_dimensions["height_cm"]
                result_dict["Исправленный вес"] = validation.corrected_dimensions["weight_kg"]
            
            results.append(result_dict)
            
            # Progress callback
            if progress_callback and (idx + 1) % 100 == 0:
                progress_callback((idx + 1) / total)
        
        except Exception as e:
            logger.error(f"Ошибка валидации строки {idx}: {e}")
            results.append({
                "index": idx,
                "Валидно": False,
                "Ошибка": str(e),
            })
    
    if progress_callback:
        progress_callback(1.0)
    
    logger.info(
        f"✅ Массовая валидация завершена: "
        f"{sum(1 for r in results if r.get('Валидно'))}/{total} валидных"
    )
    
    return pd.DataFrame(results)


# ============================================================================
# 🆕 v101.0: ЭКСПОРТ ОТЧЁТА В GOOGLE SHEETS
# ============================================================================
def export_validation_report_to_sheets(
    validation_df: pd.DataFrame,
    credentials_path: str,
    spreadsheet_title: Optional[str] = None,
    share_email: Optional[str] = None,
) -> Dict[str, Any]:
    """
    🆕 v101.0: Экспорт отчёта о валидации в Google Sheets
    
    Создаёт таблицу с тремя листами:
    1. Сводка — KPI по валидации
    2. Проблемные товары — товары с отклонениями
    3. Рекомендации — автоматические советы
    """
    if not GSPREAD_AVAILABLE:
        return {
            "success": False,
            "error": "gspread не установлен",
        }
    
    try:
        # Аутентификация
        scopes = [
            "https://www.googleapis.com/auth/spreadsheets",
            "https://www.googleapis.com/auth/drive",
        ]
        creds = Credentials.from_service_account_file(
            credentials_path, scopes=scopes
        )
        gc = gspread.authorize(creds)
        
        # Создаём таблицу
        title = spreadsheet_title or (
            f"Отчёт валидации габаритов {datetime.now().strftime('%Y%m%d_%H%M%S')}"
        )
        spreadsheet = gc.create(title)
        
        # ====================================================================
        # Лист 1: Сводка
        # ====================================================================
        total = len(validation_df)
        valid_count = validation_df["Валидно"].sum() if "Валидно" in validation_df.columns else 0
        invalid_count = total - valid_count
        
        summary_data = {
            "Показатель": [
                "Всего проверено",
                "Валидных",
                "Невалидных",
                "% валидных",
                "Средний validation score",
            ],
            "Значение": [
                total,
                valid_count,
                invalid_count,
                f"{valid_count/total*100:.1f}%" if total > 0 else "0%",
                f"{validation_df['Validation Score'].mean():.2f}" if "Validation Score" in validation_df.columns else "Н/Д",
            ],
        }
        summary_df = pd.DataFrame(summary_data)
        
        ws_summary = spreadsheet.sheet1
        ws_summary.update_title("Сводка")
        ws_summary.update(
            "A1",
            [summary_df.columns.tolist()] + summary_df.values.tolist()
        )
        
        # ====================================================================
        # Лист 2: Проблемные товары
        # ====================================================================
        if "Валидно" in validation_df.columns:
            invalid_df = validation_df[~validation_df["Валидно"]].copy()
            
            if not invalid_df.empty:
                ws_invalid = spreadsheet.add_worksheet(
                    title="Проблемные товары",
                    rows=len(invalid_df) + 10,
                    cols=len(invalid_df.columns) + 5
                )
                
                # Преобразуем в список списков
                values = [invalid_df.columns.tolist()] + invalid_df.values.tolist()
                
                # Записываем батчами
                batch_size = VALIDATION_CONFIG["google_sheets_batch_size"]
                for i in range(0, len(values), batch_size):
                    batch = values[i:i + batch_size]
                    end_row = i + len(batch)
                    end_col = get_column_letter(len(invalid_df.columns))
                    range_name = f"A{i + 1}:{end_col}{end_row}"
                    ws_invalid.update(range_name, batch)
        
        # ====================================================================
        # Лист 3: Рекомендации
        # ====================================================================
        recommendations = []
        for _, row in validation_df.head(100).iterrows():
            if "Рекомендаций" in row and row["Рекомендаций"] > 0:
                # Извлекаем рекомендации из отчёта (если есть)
                recommendations.append({
                    "Артикул": row.get("Артикул", ""),
                    "Категория": row.get("Категория", ""),
                    "Тип товара": row.get("Тип товара", ""),
                    "Статус": "✅ Валидно" if row.get("Валидно") else "❌ Невалидно",
                    "Validation Score": row.get("Validation Score", 0),
                })
        
        if recommendations:
            rec_df = pd.DataFrame(recommendations)
            ws_rec = spreadsheet.add_worksheet(
                title="Рекомендации",
                rows=len(rec_df) + 10,
                cols=len(rec_df.columns) + 5
            )
            ws_rec.update(
                "A1",
                [rec_df.columns.tolist()] + rec_df.values.tolist()
            )
        
        # Форматирование
        ws_summary.freeze_rows(1)
        
        # Шаринг
        if share_email:
            spreadsheet.share(share_email, perm_type="user", role="writer")
        
        return {
            "success": True,
            "spreadsheet_id": spreadsheet.id,
            "spreadsheet_url": spreadsheet.url,
            "sheets_created": ["Сводка", "Проблемные товары", "Рекомендации"],
            "rows_written": total,
        }
    
    except Exception as e:
        logger.error(f"Ошибка экспорта в Google Sheets: {e}")
        logger.error(traceback.format_exc())
        return {
            "success": False,
            "error": str(e),
        }


