# 🆕 v101.0: ВИЗУАЛИЗАЦИЯ РЕЗУЛЬТАТОВ ВАЛИДАЦИИ
# ============================================================================
def visualize_validation_results(validation_df: pd.DataFrame):
    """🆕 v101.0: Визуализация результатов валидации"""
    if not PLOTLY_AVAILABLE:
        st.warning("⚠️ Plotly не установлен. Визуализация недоступна.")
        return
    
    st.subheader("📊 Визуализация результатов")
    
    # ====================================================================
    # График 1: Распределение validation score
    # ====================================================================
    if "Validation Score" in validation_df.columns:
        fig1 = go.Figure()
        fig1.add_trace(go.Histogram(
            x=validation_df["Validation Score"],
            nbinsx=20,
            name="Validation Score",
            marker_color="#0f3460",
        ))
        fig1.update_layout(
            title="Распределение validation score",
            xaxis_title="Validation Score",
            yaxis_title="Количество товаров",
            height=400,
        )
        st.plotly_chart(fig1, use_container_width=True)
    
    # ====================================================================
    # График 2: Валидные vs невалидные
    # ====================================================================
    if "Валидно" in validation_df.columns:
        valid_count = validation_df["Валидно"].sum()
        invalid_count = len(validation_df) - valid_count
        
        fig2 = go.Figure(data=[go.Pie(
            labels=["Валидные", "Невалидные"],
            values=[valid_count, invalid_count],
            marker=dict(colors=["#00cc96", "#ef553b"]),
        )])
        fig2.update_layout(
            title="Соотношение валидных и невалидных товаров",
            height=400,
        )
        st.plotly_chart(fig2, use_container_width=True)
    
    # ====================================================================
    # График 3: Отклонения по параметрам
    # ====================================================================
    deviation_cols = [col for col in validation_df.columns if col.startswith("Отклонение_")]
    if deviation_cols:
        # Собираем все отклонения
        all_deviations = []
        for col in deviation_cols:
            for val in validation_df[col].dropna():
                if isinstance(val, str) and ":" in val:
                    param = val.split(":")[0].strip()
                    all_deviations.append(param)
        
        if all_deviations:
            from collections import Counter
            deviation_counts = Counter(all_deviations)
            
            fig3 = go.Figure(data=[go.Bar(
                x=list(deviation_counts.keys()),
                y=list(deviation_counts.values()),
                marker_color="#ffa600",
            )])
            fig3.update_layout(
                title="Частота отклонений по параметрам",
                xaxis_title="Параметр",
                yaxis_title="Количество",
                height=400,
            )
            st.plotly_chart(fig3, use_container_width=True)


