def main():
    """Главная функция приложения (🆕 v101.0)"""
    
    st.set_page_config(
        page_title=APP_NAME,
        page_icon="🚗",
        layout="wide",
        initial_sidebar_state="expanded"
    )
    
    st.title(APP_NAME)
    st.caption(f"Версия {APP_VERSION} | {APP_DESCRIPTION}")
    
    # 🆕 v101.0: Приветственное сообщение
    st.info("""
👋 **Добро пожаловать в Ultimate Unit Economics for Auto Parts v101.0!**

🆕 **Новые возможности v101.0:**
- 🏆 ABC/XYZ-анализ каталога
- 🏷️ Типы товаров (оригинал/аналог/Китай)
- 🌤️ Сезонность спроса (12 месяцев)
- 📑 Google Sheets экспорт
- 🤖 DeepSeek AI интеграция
- ⚖️ Безубыточность в штуках
- 🎯 Приоритет Яндекс Маркет

💡 **Начните с раздела "⚙️ Настройки" для конфигурации Google Sheets и DeepSeek API.**
""")
    
    st.sidebar.title("🧭 Навигация")
    
    # 🆕 v101.0: Расширенное меню
    section = st.sidebar.radio(
        "Выберите раздел:",
        [
            "📁 Загрузка данных",
            "📊 Юнит-экономика",
            "🗂️ Каталог для группировки",
            "📏 Категории с весогабаритами",
            "🏆 ABC/XYZ-анализ",              # 🆕 v101.0
            "🤖 AI Тарифы",
            "🌐 API Тарифы маркетплейсов",
            "🧠 Умная загрузка тарифов",
            "📑 Google Sheets экспорт",       # 🆕 v101.0
            "📚 История расчётов",
            "⚙️ Настройки",
        ],
        key="main_navigation",
    )
    
