# 🆕 v101.0: НОВЫЙ РАЗДЕЛ "ABC/XYZ-АНАЛИЗ"
# ============================================================================
def show_catalog_abc_xyz_interface():
    """🏆 ABC/XYZ-анализ каталога (🆕 v101.0)"""
    st.header("🏆 ABC/XYZ-анализ каталога")
    st.info("""
📋 **О АНАЛИЗЕ:**
ABC/XYZ-анализ помогает классифицировать товары по:
- **ABC** — доле прибыли (A=80%, B=15%, C=5%)
- **XYZ** — стабильности спроса (X=стабильный, Y=умеренный, Z=нестабильный)

💡 **Рекомендации:**
- Класс A — стратегические товары, держать запас
- Класс B — важные товары, контролировать маржу
- Класс C — кандидаты на вывод
""")
    
    # Проверка наличия данных
    if 'ue_parallel_results' not in st.session_state:
        st.warning("⚠️ Сначала выполните расчёт в разделе '📊 Юнит-экономика'")
        return
    
    results_df = st.session_state.ue_parallel_results
    
    # Запуск анализа
    if st.button("🏆 Запустить ABC/XYZ-анализ", type="primary"):
        with st.spinner("Анализ каталога..."):
            try:
                unit_economics = get_marketplace_unit_economics()
                abc_result = unit_economics.calculate_abc_xyz_analysis(results_df)
                
                st.session_state.abc_analysis_result = abc_result
                st.success("✅ Анализ завершён!")
                st.rerun()
            
            except Exception as e:
                st.error(f"❌ Ошибка: {e}")
                logger.error(traceback.format_exc())
    
    # Отображение результатов
    if 'abc_analysis_result' in st.session_state:
        abc_result = st.session_state.abc_analysis_result
        
        # KPI
        col1, col2, col3, col4 = st.columns(4)
        
        with col1:
            st.metric("📦 Всего товаров", abc_result.total_items)
        
        with col2:
            st.metric("🏆 Класс A", abc_result.class_a_count)
        
        with col3:
            st.metric("🥈 Класс B", abc_result.class_b_count)
        
        with col4:
            st.metric("🥉 Класс C", abc_result.class_c_count)
        
        # Матрица ABC/XYZ
        st.subheader("📊 Матрица ABC/XYZ")
        
        matrix_data = []
        for abc in ["A", "B", "C"]:
            row_data = {"Класс": abc}
            for xyz in ["X", "Y", "Z"]:
                cell = f"{abc}{xyz}"
                row_data[xyz] = abc_result.matrix.get(cell, 0)
            matrix_data.append(row_data)
        
        matrix_df = pd.DataFrame(matrix_data)
        st.dataframe(matrix_df, use_container_width=True)
        
        # Рекомендации
        st.subheader("💡 Рекомендации")
        
        recommendations = {
            "A": "🏆 Стратегические товары (80% прибыли). Держать запас, не демпинговать.",
            "B": "🥈 Важные товары (15% прибыли). Контролировать маржу, автоматизация.",
            "C": "🥉 Прочие товары (5% прибыли). Кандидаты на вывод или ребрендинг.",
        }
        
        for abc, rec in recommendations.items():
            st.info(rec)


