# 🆕 v101.0: НОВЫЙ РАЗДЕЛ "GOOGLE SHEETS ЭКСПОРТ"
# ============================================================================
def show_google_sheets_export_interface():
    """📑 Google Sheets экспорт (🆕 v101.0)"""
    st.header("📑 Экспорт в Google Sheets")
    st.info("""
📋 **О РАЗДЕЛЕ:**
Прямой экспорт результатов в Google Sheets через API.

**Требования:**
1. Установить: `pip install gspread google-auth`
2. Создать Service Account в Google Cloud Console
3. Скачать JSON credentials
4. Настроить в разделе "⚙️ Настройки"
""")
    
    if not GSPREAD_AVAILABLE:
        st.error("❌ gspread не установлен. Установите: `pip install gspread google-auth`")
        return
    
    # Проверка наличия данных
    if 'ue_parallel_results' not in st.session_state:
        st.warning("⚠️ Сначала выполните расчёт в разделе '📊 Юнит-экономика'")
        return
    
    results_df = st.session_state.ue_parallel_results
    
    # Настройки экспорта
    st.subheader("⚙️ Настройки экспорта")
    
    col1, col2 = st.columns(2)
    
    with col1:
        spreadsheet_title = st.text_input(
            "📝 Название таблицы",
            value=f"Юнит-экономика {datetime.now().strftime('%Y%m%d_%H%M%S')}",
            key="gs_title",
        )
    
    with col2:
        share_email = st.text_input(
            "📧 Email для шаринга (опционально)",
            placeholder="user@example.com",
            key="gs_share",
        )
    
    # Источник credentials
    gs_source = st.radio(
        "Источник credentials",
        ["Из файла", "Из st.secrets (Streamlit Cloud)"],
        key="gs_source",
    )
    
    if gs_source == "Из файла":
        credentials_path = st.text_input(
            "🔑 Путь к JSON credentials",
            placeholder="/path/to/credentials.json",
            key="gs_credentials_path",
        )
    else:
        credentials_path = None
    
    # Экспорт
    if st.button("🚀 Экспортировать в Google Sheets", type="primary"):
        with st.spinner("Экспорт в Google Sheets..."):
            try:
                # Аутентификация
                scopes = [
                    "https://www.googleapis.com/auth/spreadsheets",
                    "https://www.googleapis.com/auth/drive",
                ]
                
                if gs_source == "Из файла":
                    if not credentials_path or not os.path.exists(credentials_path):
                        st.error("❌ Файл не найден")
                        return
                    creds = Credentials.from_service_account_file(
                        credentials_path, scopes=scopes
                    )
                else:
                    if not (hasattr(st, 'secrets') and 'gcp_service_account' in st.secrets):
                        st.error("❌ Credentials не найдены в st.secrets")
                        return
                    creds = Credentials.from_service_account_info(
                        st.secrets['gcp_service_account'], scopes=scopes
                    )
                
                gc = gspread.authorize(creds)
                
                # Создаём таблицу
                spreadsheet = gc.create(spreadsheet_title)
                
                # Записываем данные батчами
                worksheet = spreadsheet.sheet1
                worksheet.update_title("Результаты")
                
                values = [results_df.columns.tolist()] + results_df.values.tolist()
                batch_size = 5000
                
                for i in range(0, len(values), batch_size):
                    batch = values[i:i + batch_size]
                    end_row = i + len(batch)
                    end_col = get_column_letter(len(results_df.columns))
                    range_name = f"A{i + 1}:{end_col}{end_row}"
                    worksheet.update(range_name, batch)
                
                # Форматирование
                worksheet.freeze_rows(1)
                
                # Шаринг
                if share_email:
                    spreadsheet.share(share_email, perm_type="user", role="writer")
                
                st.success("✅ Экспорт в Google Sheets завершён!")
                st.info(f"📊 Таблица: [{spreadsheet.url}]({spreadsheet.url})")
                
                # Сохраняем в session_state
                st.session_state.last_google_sheets_url = spreadsheet.url
            
            except Exception as e:
                st.error(f"❌ Ошибка экспорта: {e}")
                logger.error(traceback.format_exc())
    
    # История экспортов
    if 'last_google_sheets_url' in st.session_state:
        st.divider()
        st.subheader("📜 Последний экспорт")
        st.info(f"📊 [{st.session_state.last_google_sheets_url}]({st.session_state.last_google_sheets_url})")


